  function localLoad() {
    requireLocalDemoStorage();
    const localUser = JSON.parse(localStorage.getItem(storage.user) || "null");
    currentUser = localUser;
    currentView = currentUser?.view || "dashboard";
    bookings = JSON.parse(localStorage.getItem(storage.bookings) || "{}");
    orders = JSON.parse(localStorage.getItem(storage.orders) || "{}");
    customerEdits = JSON.parse(localStorage.getItem(storage.edits) || "{}");
    deletedCustomers = new Set(JSON.parse(localStorage.getItem(storage.deleted) || "[]"));
    doneJobs = new Set(JSON.parse(localStorage.getItem(storage.doneJobs) || "[]"));
    insulationCalcLines = JSON.parse(localStorage.getItem(storage.insulationCalc) || "[]");
    crmSettings = JSON.parse(localStorage.getItem(storage.crmSettings) || "{}");
    syncProductCatalogFromSettings();
    loadWebsiteSubmissionVisibleOverrides();
    profiles = Object.values(users).map((user) => ({
      id: user.key,
      display_name: user.name,
      full_name: user.name,
      role: user.key === "admin" ? "admin" : "technician",
      active: user.active !== false,
    }));
    applyCurrentUserPreferences();
    buildCustomerLocations([]);
    customers = rawData.customers
      .filter((customer) => !deletedCustomers.has(customer.lime_id))
      .filter((customer) => !hiddenDuplicateLimeIds.has(String(customer.lime_id || customer.legacy_lime_id || "")))
      .map((customer) => ({ ...customer, ...(customerEdits[customer.lime_id] || {}) }));
    const customerKeys = new Set(customers.map((customer) => customerKey(customer)).filter(Boolean));
    Object.values(customerEdits)
      .filter((customer) => customer && customerKey(customer) && !customerKeys.has(customerKey(customer)) && !deletedCustomers.has(customerKey(customer)))
      .forEach((customer) => {
        customers.unshift(customer);
        customerKeys.add(customerKey(customer));
      });
    applyLimeEnrichmentToCustomers(customers);
    applyKnownCustomerCorrections(customers);
    buildInvoices(rawData.invoices || []);
    buildServiceEvents(localServiceEvents());
    buildInstallations(localInstallations());
    buildCrmAttachments([]);
    leads = localLeads();
    intakeItems = [];
    assistantActions = [];
    activities = [];
    activityArchiveRows = [];
  }

  function activityIsHiddenFromCrm(activity) {
    const value = activity?.metadata?.hidden_from_crm_history;
    return value === true || String(value || "").toLowerCase() === "true";
  }

  function visibleActivityRows(rows) {
    return (rows || []).filter((activity) => !activityIsHiddenFromCrm(activity));
  }

  function assistantActionSnapshotTimestamp(action = {}) {
    const timestamp = new Date(action.updated_at || action.created_at || 0).getTime();
    return Number.isFinite(timestamp) ? timestamp : 0;
  }

  function deduplicateAssistantActionSnapshot(rows = []) {
    const result = [];
    const indexById = new Map();
    const indexByIdempotencyKey = new Map();
    for (const action of Array.isArray(rows) ? rows : []) {
      if (!action || typeof action !== "object" || Array.isArray(action)) continue;
      const id = String(action.id || "").trim();
      const idempotencyKey = String(action.idempotency_key || "").trim();
      let index = id ? indexById.get(id) : undefined;
      if (index === undefined && idempotencyKey) index = indexByIdempotencyKey.get(idempotencyKey);
      if (index === undefined) {
        index = result.length;
        result.push(action);
      } else if (assistantActionSnapshotTimestamp(action) > assistantActionSnapshotTimestamp(result[index])) {
        result[index] = action;
      }
      const selected = result[index];
      const selectedId = String(selected?.id || "").trim();
      const selectedIdempotencyKey = String(selected?.idempotency_key || "").trim();
      if (id) indexById.set(id, index);
      if (idempotencyKey) indexByIdempotencyKey.set(idempotencyKey, index);
      if (selectedId) indexById.set(selectedId, index);
      if (selectedIdempotencyKey) indexByIdempotencyKey.set(selectedIdempotencyKey, index);
    }
    return result;
  }

  function reconcileAssistantActionSnapshot(serverRows = [], localRows = [], requestStartedAt = 0) {
    const requestedAt = Number(requestStartedAt) || 0;
    const concurrentLocalRows = (Array.isArray(localRows) ? localRows : [])
      .filter((action) => assistantActionSnapshotTimestamp(action) > requestedAt);
    return deduplicateAssistantActionSnapshot([
      ...(Array.isArray(serverRows) ? serverRows : []),
      ...concurrentLocalRows,
    ]);
  }

  function applySupabaseLoadedData(loaded, profile = null) {
    customers = (loaded.customers || [])
      .filter((customer) => !hiddenDuplicateLimeIds.has(String(customer.lime_id || customer.legacy_lime_id || "")));
    applyLimeEnrichmentToCustomers(customers);
    applyKnownCustomerCorrections(customers);
    bookings = loaded.bookings || {};
    orders = loaded.orders || {};
    leads = loaded.leads || [];
    activityArchiveRows = loaded.activities || [];
    activities = visibleActivityRows(activityArchiveRows);
    jobs = loaded.jobs || [];
    appointments = loaded.appointments || [];
    websiteSubmissions = loaded.websiteSubmissions || [];
    loadWebsiteSubmissionVisibleOverrides();
    intakeItems = loaded.intakeItems || [];
    assistantActions = loaded.assistantActions || [];
    crmAttachments = loaded.crmAttachments || [];
    profiles = loaded.profiles || [];
    crmSettings = loaded.crmSettings || {};
    syncProductCatalogFromSettings();
    applyCurrentUserPreferences(profile);
    buildCustomerLocations(loaded.customerLocations || []);
    buildInvoices(loaded.invoices || []);
    buildServiceEvents(loaded.serviceEvents || []);
    buildInstallations(loaded.installations || []);
    buildAccessNotes(loaded.accessNotes || []);
    buildCrmAttachments(crmAttachments);
    leadRenderCache = null;
  }

  async function supabaseLoad() {
    const startupStartedAt = Date.now();
    if (el.syncStatus) {
      delete el.syncStatus.dataset.startupReadyMs;
      delete el.syncStatus.dataset.freshReadyMs;
      delete el.syncStatus.dataset.startupSource;
      delete el.syncStatus.dataset.sessionHint;
      delete el.syncStatus.dataset.cacheReadMs;
      delete el.syncStatus.dataset.cacheApplyMs;
      delete el.syncStatus.dataset.cacheRenderMs;
    }
    customerHistoryGeneration += 1;
    customerHistoryLoadedIds = new Set();
    customerHistoryLoadPromises.clear();
    const firstLoad = !currentUser;
    let cacheUserId = "";
    let showedCachedData = false;
    const showCachedDataFor = async (userId, sessionUser = {}) => {
      if (!firstLoad || !userId || !store.loadCachedData) return false;
      try {
        const cacheReadStartedAt = Date.now();
        const cached = await store.loadCachedData(userId);
        const cacheReadMs = Date.now() - cacheReadStartedAt;
        const cachedProfile = cached?.profile
          || (cached?.data?.profiles || []).find((item) => String(item?.id || "") === String(userId));
        if (!cached?.data || !cachedProfile || cachedProfile.active === false) return false;
        currentUser = {
          id: cachedProfile.id,
          name: cachedProfile.full_name || cachedProfile.display_name || sessionUser.email || "Bruker",
          role: cachedProfile.role === "admin" ? "Admin" : "Tekniker",
          key: cachedProfile.role === "admin" ? "admin" : "tech",
          view: cachedProfile.role === "admin" ? "dashboard" : "technician",
        };
        if (!currentView) currentView = currentUser.view;
        const cacheApplyStartedAt = Date.now();
        applySupabaseLoadedData(cached.data, cachedProfile);
        const cacheApplyMs = Date.now() - cacheApplyStartedAt;
        const cacheRenderStartedAt = Date.now();
        renderApp();
        const cacheRenderMs = Date.now() - cacheRenderStartedAt;
        setSyncStatus("Viser sist lagrede data. Henter siste oppdateringer i bakgrunnen...", "");
        const cacheReadyMs = Date.now() - startupStartedAt;
        if (el.syncStatus) {
          el.syncStatus.dataset.startupReadyMs = String(cacheReadyMs);
          el.syncStatus.dataset.startupSource = "cache";
          el.syncStatus.dataset.cacheReadMs = String(cacheReadMs);
          el.syncStatus.dataset.cacheApplyMs = String(cacheApplyMs);
          el.syncStatus.dataset.cacheRenderMs = String(cacheRenderMs);
        }
        console.info(`[CRM ytelse] Lokal kopi ${cacheReadyMs} ms (les ${cacheReadMs}, behandle ${cacheApplyMs}, vise ${cacheRenderMs})`);
        await new Promise((resolve) => setTimeout(resolve, 0));
        return true;
      } catch (_) {
        // A missing or unavailable browser cache must never block live CRM data.
        return false;
      }
    };
    const sessionHint = firstLoad ? store.sessionHint?.() : null;
    if (el.syncStatus) el.syncStatus.dataset.sessionHint = sessionHint?.user?.id ? "stored" : "none";
    if (sessionHint?.user?.id) {
      cacheUserId = sessionHint.user.id;
      showedCachedData = await showCachedDataFor(cacheUserId, sessionHint.user);
    }
    const session = await store.session();
    if (!session) {
      resetSensitiveWorkflowState();
      currentUser = null;
      customers = [];
      bookings = {};
      orders = {};
      leads = [];
      activities = [];
      activityArchiveRows = [];
      jobs = [];
      appointments = [];
      websiteSubmissions = [];
      intakeItems = [];
      assistantActions = [];
      crmAttachments = [];
      profiles = [];
      crmSettings = {};
      syncProductCatalogFromSettings();
      buildCustomerLocations([]);
      buildInvoices([]);
      buildServiceEvents([]);
      buildInstallations([]);
      buildAccessNotes([]);
      buildCrmAttachments([]);
      return;
    }
    const verifiedUserId = session.user?.id || "";
    if (showedCachedData && cacheUserId !== verifiedUserId) {
      currentUser = null;
      applySupabaseLoadedData({});
      showedCachedData = false;
    }
    cacheUserId = verifiedUserId;
    if (!showedCachedData) showedCachedData = await showCachedDataFor(cacheUserId, session.user);
    const loadStartedAt = Date.now();
    const assistantActionRequestStartedAt = Date.now();
    const freshDataPromise = store.loadAll().then(
      (data) => ({ data, error: null }),
      (error) => ({ data: null, error }),
    );
    const freshAssistantActionPromise = store.loadAssistantActions
      ? store.loadAssistantActions().then(
        (rows) => ({ rows, error: null }),
        (error) => ({ rows: null, error }),
      )
      : Promise.resolve({ rows: null, error: null });
    let profile;
    try {
      profile = await store.profile(cacheUserId);
    } catch (error) {
      const status = Number(error?.status || error?.statusCode || 0);
      const accessRevoked = status === 401
        || status === 403
        || /ikke aktiv CRM-profil|not authenticated|invalid jwt|jwt expired/i.test(String(error?.message || ""));
      if (accessRevoked) {
        await store.clearCachedData?.(cacheUserId).catch(() => {});
        currentUser = null;
        renderApp();
      }
      throw error;
    }
    if (currentUser?.id && profile?.id && String(currentUser.id) !== String(profile.id)) resetSensitiveWorkflowState();
    currentUser = {
      id: profile?.id,
      name: profile?.full_name || profile?.display_name || session.user?.email || "Bruker",
      role: profile?.role === "admin" ? "Admin" : "Tekniker",
      key: profile?.role === "admin" ? "admin" : "tech",
      view: profile?.role === "admin" ? "dashboard" : "technician",
    };
    if (firstLoad || !currentView) currentView = currentUser.view;
    const assistantActionUserId = String(currentUser.id || "");
    const assistantActionStateGeneration = sensitiveWorkflowGeneration;
    const assistantActionRequestGeneration = ++assistantActionRefreshGeneration;
    let freshAssistantActionRows = null;
    const assistantActionRefreshTask = freshAssistantActionPromise.then(async (result) => {
      if (result.error || !Array.isArray(result.rows)) return false;
      if (assistantActionRequestGeneration !== assistantActionRefreshGeneration
        || !sensitiveWorkflowIsCurrent(assistantActionStateGeneration)
        || String(currentUser?.id || "") !== assistantActionUserId) return false;
      freshAssistantActionRows = deduplicateAssistantActionSnapshot(result.rows);
      assistantActions = reconcileAssistantActionSnapshot(
        freshAssistantActionRows,
        assistantActions,
        assistantActionRequestStartedAt,
      );
      renderAssistantActionQueue();
      renderCrmAssistantSuggestions();
      if (currentView === "dashboard") renderDashboard();
      await store.cacheAssistantActions?.(assistantActionUserId, assistantActions).catch(() => false);
      return true;
    }).catch(() => false);
    if (!showedCachedData) {
      renderApp();
      setSyncStatus(
        firstLoad
          ? "Innlogging bekreftet. Laster kundedata, jobber og historikk..."
          : "Oppdaterer kundedata, jobber og historikk...",
        "",
      );
    } else {
      renderApp();
    }
    const freshResult = await freshDataPromise;
    if (freshResult.error) {
      const assistantQueueFresh = await assistantActionRefreshTask;
      if (assistantQueueFresh && typeof freshResult.error !== "object") {
        const wrappedError = new Error(String(freshResult.error || "Klarte ikke laste data."));
        wrappedError.assistantQueueFresh = true;
        throw wrappedError;
      }
      if (assistantQueueFresh) freshResult.error.assistantQueueFresh = true;
      throw freshResult.error;
    }
    const loaded = freshResult.data;
    if (Array.isArray(freshAssistantActionRows)) loaded.assistantActions = freshAssistantActionRows;
    insulationCalcLines = [];
    applySupabaseLoadedData(loaded, profile);
    store.cacheLoadedData?.(cacheUserId, loaded, profile).catch(() => {});
    const freshReadyMs = Date.now() - startupStartedAt;
    if (el.syncStatus) {
      el.syncStatus.dataset.freshReadyMs = String(freshReadyMs);
      if (!showedCachedData) {
        el.syncStatus.dataset.startupReadyMs = String(freshReadyMs);
        el.syncStatus.dataset.startupSource = "fresh";
      }
    }
    console.info(`[CRM ytelse] Ferske data lastet etter ${freshReadyMs} ms`, {
      databaseMilliseconds: Date.now() - loadStartedAt,
      customers: customers.length,
      leads: leads.length,
      bookings: Object.keys(bookings).length,
      installations: loaded.installations?.length || 0,
    });
  }

  function buildInvoices(invoices) {
    invoicesByCustomer = new Map();
    for (const invoice of invoices || []) {
      const keys = [invoice.customer_id, invoice.lime_id, invoice.legacy_lime_id].filter(Boolean);
      for (const key of keys) {
        const list = invoicesByCustomer.get(key) || [];
        list.push(invoice);
        invoicesByCustomer.set(key, list);
      }
    }
    for (const list of invoicesByCustomer.values()) {
      list.sort((a, b) => String(b.date || b.invoice_date || "").localeCompare(String(a.date || a.invoice_date || "")));
    }
  }

  function buildServiceEvents(events) {
    serviceEventsByCustomer = new Map();
    for (const event of events || []) {
      const keys = [event.customer_id, event.lime_id, event.legacy_lime_id].filter(Boolean);
      for (const key of keys) {
        const list = serviceEventsByCustomer.get(key) || [];
        list.push(event);
        serviceEventsByCustomer.set(key, list);
      }
    }
    for (const list of serviceEventsByCustomer.values()) {
      list.sort((a, b) => String(b.event_date || "").localeCompare(String(a.event_date || "")));
    }
  }

  function mergeUniqueHistoryRows(currentRows, incomingRows) {
    const merged = new Map();
    for (const row of [...(currentRows || []), ...(incomingRows || [])]) {
      if (!row) continue;
      const key = row.id
        || row.event_id
        || [row.invoice_number, row.invoice_date, row.customer_id, row.amount].filter((value) => value !== undefined && value !== null).join("|")
        || JSON.stringify(row);
      merged.set(String(key), row);
    }
    return [...merged.values()];
  }

  async function ensureCustomerHistory(customer) {
    const customerId = customer?.id;
    if (!store.loadCustomerHistory || !isUuid(customerId) || customerHistoryLoadedIds.has(customerId)) return;
    if (customerHistoryLoadPromises.has(customerId)) return customerHistoryLoadPromises.get(customerId);
    const generation = customerHistoryGeneration;
    const request = store.loadCustomerHistory(customerId)
      .then((history) => {
        if (generation !== customerHistoryGeneration) return;
        buildInvoices(mergeUniqueHistoryRows(uniqueSnapshotRowsFromMap(invoicesByCustomer), history.invoices));
        buildServiceEvents(mergeUniqueHistoryRows(uniqueSnapshotRowsFromMap(serviceEventsByCustomer), history.serviceEvents));
        activityArchiveRows = mergeUniqueHistoryRows(activityArchiveRows, history.activities)
          .sort((a, b) => String(b.occurred_at || b.created_at || "").localeCompare(String(a.occurred_at || a.created_at || "")));
        activities = visibleActivityRows(activityArchiveRows);
        customerHistoryLoadedIds.add(customerId);
        leadRenderCache = null;
        if (currentView === "customers" && customerKey(customer) === selectedCustomerId) renderCustomerDetail();
        if (currentView === "leads" && leadEntryCustomerKey(selectedLeadEntry()) === customerKey(customer)) renderLeads();
      })
      .catch((error) => {
        if (generation === customerHistoryGeneration && currentView === "customers" && customerKey(customer) === selectedCustomerId) {
          setSyncStatus(error.message || "Klarte ikke laste eldre kundehistorikk.", "error");
        }
      })
      .finally(() => customerHistoryLoadPromises.delete(customerId));
    customerHistoryLoadPromises.set(customerId, request);
    return request;
  }

  function buildInstallations(installations) {
    installationsByCustomer = new Map();
    const seen = new Set();
    for (const installation of installations || []) {
      const keys = [...new Set([installation.customer_id, installation.lime_id, installation.legacy_lime_id].filter(Boolean))];
      const uniqueKey = installation.id
        || installation.legacy_key
        || `${installation.customer_id || installation.lime_id || ""}|${installation.label || ""}|${installation.model || ""}|${installation.installed_at || ""}|${installation.last_service_at || ""}|${installation.notes || ""}`;
      if (seen.has(uniqueKey)) continue;
      seen.add(uniqueKey);
      for (const key of keys) {
        const list = installationsByCustomer.get(key) || [];
        list.push(installation);
        installationsByCustomer.set(key, list);
      }
    }
    for (const list of installationsByCustomer.values()) {
      list.sort((a, b) => {
        const aDate = a.next_service_due || a.last_service_at || a.installed_at || "";
        const bDate = b.next_service_due || b.last_service_at || b.installed_at || "";
        return String(aDate).localeCompare(String(bDate)) || installationLabelRank(a) - installationLabelRank(b) || String(a.label || "").localeCompare(String(b.label || ""));
      });
    }
  }

  function installationLabelRank(installation) {
    const match = String(installation.label || "").match(/\d+/);
    return match ? Number(match[0]) : 999;
  }

  function buildCustomerLocations(locations) {
    customerLocationsByCustomer = new Map();
    customerLocationById = new Map();
    for (const location of locations || []) {
      if (!location?.id) continue;
      customerLocationById.set(String(location.id), location);
      if (!location.customer_id) continue;
      const list = customerLocationsByCustomer.get(location.customer_id) || [];
      list.push(location);
      customerLocationsByCustomer.set(location.customer_id, list);
    }
    for (const list of customerLocationsByCustomer.values()) {
      list.sort((a, b) => {
        if (Boolean(a.is_primary) !== Boolean(b.is_primary)) return a.is_primary ? -1 : 1;
        return String(a.location_name || "").localeCompare(String(b.location_name || ""), "nb");
      });
    }
  }

  function mergeUniqueHistoryRows(currentRows, incomingRows) {
    const merged = new Map();
    for (const row of [...(currentRows || []), ...(incomingRows || [])]) {
      if (!row) continue;
      const key = row.id
        || row.event_id
        || [row.invoice_number, row.invoice_date, row.customer_id, row.amount].filter((value) => value !== undefined && value !== null).join("|")
        || JSON.stringify(row);
      merged.set(String(key), row);
    }
    return [...merged.values()];
  }

  async function ensureCustomerHistory(customer) {
    const customerId = customer?.id;
    if (!store.loadCustomerHistory || !isUuid(customerId) || customerHistoryLoadedIds.has(customerId)) return;
    if (customerHistoryLoadPromises.has(customerId)) return customerHistoryLoadPromises.get(customerId);
    const generation = customerHistoryGeneration;
    const request = store.loadCustomerHistory(customerId)
      .then((history) => {
        if (generation !== customerHistoryGeneration) return;
        buildInvoices(mergeUniqueHistoryRows(uniqueSnapshotRowsFromMap(invoicesByCustomer), history.invoices));
        buildServiceEvents(mergeUniqueHistoryRows(uniqueSnapshotRowsFromMap(serviceEventsByCustomer), history.serviceEvents));
        activityArchiveRows = mergeUniqueHistoryRows(activityArchiveRows, history.activities)
          .sort((a, b) => String(b.occurred_at || b.created_at || "").localeCompare(String(a.occurred_at || a.created_at || "")));
        activities = visibleActivityRows(activityArchiveRows);
        customerHistoryLoadedIds.add(customerId);
        leadRenderCache = null;
        if (currentView === "customers" && customerKey(customer) === selectedCustomerId) renderCustomerDetail();
        if (currentView === "leads" && leadEntryCustomerKey(selectedLeadEntry()) === customerKey(customer)) renderLeads();
      })
      .catch((error) => {
        if (generation === customerHistoryGeneration && currentView === "customers" && customerKey(customer) === selectedCustomerId) {
          setSyncStatus(error.message || "Klarte ikke laste eldre kundehistorikk.", "error");
        }
      })
      .finally(() => customerHistoryLoadPromises.delete(customerId));
    customerHistoryLoadPromises.set(customerId, request);
    return request;
  }

  function buildAccessNotes(notes) {
    accessNotesByCustomer = new Map();
    for (const note of notes || []) {
      if (!note.customer_id || note.active === false) continue;
      const list = accessNotesByCustomer.get(note.customer_id) || [];
      list.push(note);
      accessNotesByCustomer.set(note.customer_id, list);
    }
    for (const list of accessNotesByCustomer.values()) {
      list.sort((a, b) => String(b.updated_at || b.created_at || "").localeCompare(String(a.updated_at || a.created_at || "")));
    }
  }

  function buildCrmAttachments(rows) {
    crmAttachments = (rows || []).filter((item) => item && !item.deleted_at);
    crmAttachmentsByCustomer = new Map();
    crmAttachmentsByLead = new Map();
    crmAttachmentsByInstallation = new Map();
    crmAttachmentsByJob = new Map();
    crmAttachmentsByIntake = new Map();
    crmAttachmentsByWebsiteSubmission = new Map();
    const add = (map, key, attachment) => {
      if (!key) return;
      const list = map.get(String(key)) || [];
      list.push(attachment);
      map.set(String(key), list);
    };
    for (const attachment of crmAttachments) {
      add(crmAttachmentsByCustomer, attachment.customer_id, attachment);
      add(crmAttachmentsByLead, attachment.lead_id, attachment);
      add(crmAttachmentsByInstallation, attachment.installation_id, attachment);
      add(crmAttachmentsByJob, attachment.job_id, attachment);
      add(crmAttachmentsByIntake, attachment.intake_id, attachment);
      add(crmAttachmentsByWebsiteSubmission, attachment.website_submission_id, attachment);
    }
    const sort = (list) => list.sort((a, b) => String(b.created_at || "").localeCompare(String(a.created_at || "")) || String(a.title || "").localeCompare(String(b.title || ""), "nb"));
    for (const map of [crmAttachmentsByCustomer, crmAttachmentsByLead, crmAttachmentsByInstallation, crmAttachmentsByJob, crmAttachmentsByIntake, crmAttachmentsByWebsiteSubmission]) {
      for (const list of map.values()) sort(list);
    }
  }

  function replaceCrmAttachments(updatedRows) {
    const updated = Array.isArray(updatedRows) ? updatedRows : [updatedRows].filter(Boolean);
    if (!updated.length) return;
    const byId = new Map(crmAttachments.map((item) => [item.id, item]));
    for (const row of updated) {
      if (row?.id) byId.set(row.id, row);
    }
    buildCrmAttachments([...byId.values()]);
  }

  function upsertAccessNoteInMemory(customer, note) {
    const key = customerKey(customer);
    if (!key) return;
    const cleanNote = String(note || "").trim();
    if (!cleanNote) {
      accessNotesByCustomer.set(key, []);
      return;
    }
    const list = accessNotesByCustomer.get(key) || [];
    const existingIndex = list.findIndex((item) => item.note_type === "adkomst");
    const existing = existingIndex >= 0 ? list[existingIndex] : {};
    const row = {
      ...existing,
      id: existing.id || `access-${Date.now()}`,
      customer_id: key,
      note_type: "adkomst",
      note: cleanNote,
      active: true,
      updated_at: new Date().toISOString(),
    };
    accessNotesByCustomer.set(key, [row, ...list.filter((_, index) => index !== existingIndex)]);
  }

  function localServiceEvents() {
    const events = [];
    const enrichment = window.CRM_LIME_ENRICHMENT || { records: [] };
    for (const record of enrichment.records || []) {
      const customer = (record.limeId && customers.find((item) => item.lime_id === record.limeId || item.legacy_lime_id === record.limeId))
        || customers.find((item) => normalizeMatch(item.name) === normalizeMatch(record.matchName));
      if (!customer) continue;
      for (const entry of record.history || []) {
        events.push({
          customer_id: customerKey(customer),
          event_date: entry.event_date,
          event_type: entry.event_type || "Lime Go",
          note: `${entry.title || "Lime Go oppgave"}\n${entry.description || ""}`.trim(),
        });
      }
    }
    return events;
  }

  function localInstallations() {
    const rows = [];
    for (const record of limeInstallations.records || []) {
      const customer = (record.limeId && customers.find((item) => item.lime_id === record.limeId || item.legacy_lime_id === record.limeId))
        || customers.find((item) => normalizeMatch(item.name) === normalizeMatch(record.matchName));
      if (!customer) continue;
      for (const installation of record.installations || []) {
        rows.push({
          ...installation,
          customer_id: customerKey(customer),
          lime_id: customer.lime_id,
        });
      }
    }
    try {
      rows.push(...JSON.parse(localStorage.getItem(storage.installations) || "[]"));
    } catch {
      // Ignore broken local demo data and keep imported rows.
    }
    return rows;
  }

  async function refreshData(message) {
    if (refreshDataPromise) {
      const loaded = await refreshDataPromise;
      if (loaded && message) setSyncStatus(message, "ok");
      return loaded;
    }
    refreshDataPromise = refreshDataNow(message).finally(() => {
      refreshDataPromise = null;
    });
    return refreshDataPromise;
  }

  async function refreshDataNow(message) {
    try {
      invalidateVerifiedRoute();
      if (store.isConfigured) {
        if (currentUser) setSyncStatus("Laster kundedata, jobber og historikk. På tregt nett kan dette ta litt tid.", "");
        else if (rememberLoginPreference() && el.loginMessage) el.loginMessage.textContent = "Sjekker lagret innlogging på denne enheten...";
        await supabaseLoad();
      }
      else if (canUseLocalDemo()) localLoad();
      else throw new Error(databaseUnavailableMessage);
      const repairedOrders = store.isConfigured ? 0 : await ensureOrdersForLoadedBookings();
      updateResourceSelects();
      renderApp();
      if (message) setSyncStatus(message, "ok");
      else if (repairedOrders) setSyncStatus(`Fant ${repairedOrders} avtale${repairedOrders === 1 ? "" : "r"} uten jobb og opprettet jobb automatisk.`, "ok");
      else if (syncStatusLooksLikeLoading()) setSyncStatus("Kundedata er oppdatert.", "ok");
      return true;
    } catch (error) {
      const messageText = `${error.message || "Klarte ikke laste data."}${error.assistantQueueFresh ? " Kontrollkøen er likevel oppdatert." : ""}`;
      setSyncStatus(messageText, "error");
      if (!el.loginView.classList.contains("hidden")) {
        el.loginMessage.textContent = messageText;
      }
      if (!currentUser || !el.loginView.classList.contains("hidden")) {
        resetSensitiveWorkflowState();
        currentUser = null;
        renderApp();
      }
      return false;
    }
  }

  function saveLocalBookings() {
    requireLocalDemoStorage();
    localStorage.setItem(storage.bookings, JSON.stringify(bookings));
  }

  function saveLocalOrders() {
    requireLocalDemoStorage();
    localStorage.setItem(storage.orders, JSON.stringify(orders));
  }

  function saveLocalEdits() {
    requireLocalDemoStorage();
    localStorage.setItem(storage.edits, JSON.stringify(customerEdits));
  }

  function localLeads() {
    try {
      return JSON.parse(localStorage.getItem(storage.leads) || "[]");
    } catch {
      return [];
    }
  }

  function saveLocalLeads() {
    requireLocalDemoStorage();
    localStorage.setItem(storage.leads, JSON.stringify(leads));
  }

  function saveLocalInstallations() {
    requireLocalDemoStorage();
    const rows = [];
    const seen = new Set();
    for (const list of installationsByCustomer.values()) {
      for (const installation of list || []) {
        const id = String(installation?.id || "");
        const isLocal = installation?.source === "local" || id.startsWith("installation-");
        if (!isLocal || seen.has(id)) continue;
        seen.add(id);
        rows.push(installation);
      }
    }
    localStorage.setItem(storage.installations, JSON.stringify(rows));
  }

  function loadWebsiteSubmissionVisibleOverrides() {
    try {
      websiteSubmissionVisibleOverrides = new Set(JSON.parse(localStorage.getItem(storage.websiteSubmissionVisibleOverrides) || "[]"));
    } catch {
      websiteSubmissionVisibleOverrides = new Set();
    }
  }

  function saveWebsiteSubmissionVisibleOverrides() {
    try {
      localStorage.setItem(storage.websiteSubmissionVisibleOverrides, JSON.stringify([...websiteSubmissionVisibleOverrides]));
    } catch {
      // Local override is only a convenience; ignore browsers that block storage.
    }
  }

  function setWebsiteSubmissionVisibleOverride(id, shouldShow) {
    if (!id) return;
    const key = String(id);
    if (shouldShow) websiteSubmissionVisibleOverrides.add(key);
    else websiteSubmissionVisibleOverrides.delete(key);
    saveWebsiteSubmissionVisibleOverrides();
  }

  function saveLocalLeadPatch(id, patch = {}) {
    requireLocalDemoStorage();
    const index = leads.findIndex((lead) => lead.id === id);
    if (index < 0) throw new Error("Fant ikke saken.");
    const updated = { ...leads[index], ...patch, updated_at: new Date().toISOString() };
    leads[index] = updated;
    invalidateLeadCustomerLookupIndex();
    saveLocalLeads();
    return updated;
  }

  function deleteLocalLead(id) {
    requireLocalDemoStorage();
    leads = leads.filter((lead) => lead.id !== id);
    saveLocalLeads();
  }

  function bookingRows() {
    return Object.entries(bookings)
      .map(([id, booking]) => ({
        id,
        booking,
        customer: findCustomer(booking.customerId),
      }))
      .filter((row) => row.customer && row.booking.date && row.booking.status !== "cancelled")
      .sort((a, b) => `${a.booking.date} ${a.booking.time || ""}`.localeCompare(`${b.booking.date} ${b.booking.time || ""}`));
  }

  function normalizeOrderId(id) {
    return String(id || "").trim();
  }

  function bookingIdsForOrder(order) {
    if (Array.isArray(order?.bookingIds)) return order.bookingIds.map(String).filter(Boolean);
    if (Array.isArray(order?.booking_ids)) return order.booking_ids.map(String).filter(Boolean);
    return [];
  }

  function setBookingIdsForOrder(order, ids) {
    const unique = [...new Set((ids || []).map(String).filter(Boolean))];
    order.bookingIds = unique;
    order.booking_ids = unique;
    return order;
  }

  function orderCustomerId(order) {
    return order?.customerId || order?.customer_id || "";
  }

  function findOrder(orderId) {
    const id = normalizeOrderId(orderId);
    return id ? orders[id] || null : null;
  }

  function openOrderById(orderId, options = {}) {
    const id = normalizeOrderId(orderId);
    if (!id || !findOrder(id)) return false;
    selectedOrderId = id;
    currentOrderFilter = options.filter || "all";
    currentOrderSearch = "";
    if (el.orderStatusFilter) el.orderStatusFilter.value = currentOrderFilter;
    if (el.orderSearch) el.orderSearch.value = "";
    setView("orders");
    return true;
  }

  function findJob(jobId) {
    const id = String(jobId || "").trim();
    return id ? (jobs || []).find((job) => String(job.id || "") === id) || null : null;
  }

  function jobForOrder(orderOrId) {
    const order = typeof orderOrId === "object" ? orderOrId : findOrder(orderOrId);
    const orderId = normalizeOrderId(typeof orderOrId === "object" ? order?.id : orderOrId);
    const directJob = findJob(order?.jobId || order?.job_id);
    if (directJob) return directJob;
    if (!orderId) return null;
    return (jobs || []).find((job) => (
      job?.source_table === "orders"
      && normalizeOrderId(job.source_id) === orderId
    )) || null;
  }

  function orderForLeadId(leadId) {
    const id = String(leadId || "").trim();
    if (!id) return null;
    for (const [orderId, order] of Object.entries(orders || {})) {
      const normalized = { ...order, id: order.id || orderId };
      if (
        String(normalized.lead_id || normalized.leadId || "") === id
        && orderEffectiveStatus(normalized, jobForOrder(normalized)) !== "cancelled"
      ) {
        return normalized;
      }
    }
    const job = (jobs || []).find((row) => (
      String(row.lead_id || "") === id
      && String(row.work_status || "") !== "cancelled"
      && row.source_table === "orders"
      && findOrder(row.source_id)
    ));
    return job ? findOrder(job.source_id) : null;
  }

  function cleanLeadOrderMatchTerm(value) {
    const term = String(value || "")
      .replace(/^\s*[-*]\s*/, "")
      .replace(/\s+\d[\d\s.,]*\s*(kr|,-)?\s*$/i, "")
      .replace(/\b(sum tilbudslinjer|sum prisgrunnlag|tilbudslinjer|prisgrunnlag|lead|phone|new installation)\b/gi, " ")
      .replace(/\s+/g, " ")
      .trim();
    const normalized = normalizeMatch(term);
    if (!normalized || normalized.length < 5) return "";
    if (/^(standard montering|timepris arbeid|montering|arbeid)$/.test(normalized)) return "";
    return term;
  }

  function leadOrderMatchTermsForEntry(entry) {
    const note = leadNoteForEntry(entry);
    const offerLines = offerLinesFromText(note)
      .split(/\n+/)
      .map(cleanLeadOrderMatchTerm)
      .filter(Boolean);
    const rawTerms = [
      entry?.lead?.product_interest,
      entry?.lead?.source_detail,
      ...offerLines,
    ];
    const seen = new Set();
    return rawTerms
      .map(cleanLeadOrderMatchTerm)
      .filter((term) => {
        const key = normalizeMatch(term);
        if (!key || seen.has(key)) return false;
        seen.add(key);
        return true;
      });
  }

  function leadOrderMatchesEntry(order, entry) {
    const terms = leadOrderMatchTermsForEntry(entry);
    if (!terms.length) return false;
    const text = normalizeMatch([
      order?.title,
      order?.note,
      extractJobPriceBasis(order?.note || ""),
    ].filter(Boolean).join(" "));
    return terms.some((term) => {
      const normalized = normalizeMatch(term);
      if (!normalized) return false;
      if (text.includes(normalized)) return true;
      const words = normalized.split(/\s+/).filter((word) => word.length >= 4);
      if (words.length < 2) return false;
      const hits = words.filter((word) => text.includes(word)).length;
      return hits >= Math.min(2, words.length);
    });
  }

  function leadResolutionContext() {
    const rows = orderRows();
    const orderByLeadId = new Map();
    const orderRowsByCustomer = new Map();
    const orderRowById = new Map();
    for (const row of rows) {
      const id = normalizeOrderId(row.id || row.order?.id);
      if (id) orderRowById.set(id, row);
      if (orderEffectiveStatus(row.order, row.job, row.linkedBookings) === "cancelled") continue;
      const customerIds = [
        orderCustomerId(row.order),
        customerKey(row.customer),
        row.customer?.lime_id,
        row.customer?.legacy_lime_id,
      ].filter(Boolean).map(String);
      for (const customerId of new Set(customerIds)) {
        if (!orderRowsByCustomer.has(customerId)) orderRowsByCustomer.set(customerId, []);
        orderRowsByCustomer.get(customerId).push(row);
      }
      const leadId = String(row.order?.lead_id || row.order?.leadId || "");
      if (leadId && !orderByLeadId.has(leadId)) orderByLeadId.set(leadId, row.order);
    }
    for (const job of jobs || []) {
      const leadId = String(job?.lead_id || "");
      if (!leadId || orderByLeadId.has(leadId) || String(job?.work_status || "") === "cancelled") continue;
      const row = orderRowById.get(normalizeOrderId(job?.source_id));
      if (row?.order) orderByLeadId.set(leadId, row.order);
    }
    return { orderByLeadId, orderRowsByCustomer };
  }

  function orderForLeadEntry(entry, resolutionContext = null) {
    const leadId = String(entry?.lead?.id || "");
    const direct = resolutionContext
      ? resolutionContext.orderByLeadId.get(leadId) || null
      : orderForLeadId(leadId);
    if (direct) return direct;
    const customer = entry?.customer ? (findCustomer(leadEntryCustomerKey(entry)) || entry.customer) : null;
    if (!customer) return null;
    const customerKeyValue = String(customerKey(customer) || "");
    const customerCandidates = resolutionContext
      ? (resolutionContext.orderRowsByCustomer.get(customerKeyValue) || []).map((row) => row.order)
      : customerOrders(customer).filter((order) => (
        orderEffectiveStatus(order, jobForOrder(order), bookingRowsForOrder(order)) !== "cancelled"
      ));
    const leadDay = leadCreatedDay(entry);
    const candidates = leadDay
      ? customerCandidates.filter((order) => {
        const orderDay = isoDayText(
          order?.created_at
          || order?.createdAt
          || order?.scheduledDate
          || order?.scheduled_date
          || order?.completedAt
          || order?.completed_at,
        );
        return orderDay ? orderDay >= leadDay : String(order?.source || "") === "lead";
      })
      : customerCandidates;
    if (!candidates.length) return null;
    const leadSourced = candidates.filter((order) => String(order?.source || "") === "lead");
    const directLeadMatches = leadSourced.filter((order) => leadOrderMatchesEntry(order, entry));
    if (directLeadMatches.length) return directLeadMatches[0];
    const matching = candidates.filter((order) => leadOrderMatchesEntry(order, entry));
    if (matching.length) return matching[0];
    if (leadSourced.length === 1) return leadSourced[0];
    return candidates.length === 1 ? candidates[0] : null;
  }

  function isoDayText(value) {
    const text = String(value || "").slice(0, 10);
    return /^\d{4}-\d{2}-\d{2}$/.test(text) ? text : "";
  }

  function leadCreatedDay(entry) {
    const lead = entry?.lead || {};
    return isoDayText(lead.created_at || lead.received_at || lead.updated_at || lead.createdAt || lead.date);
  }

  function installationMatchesLeadEntry(installation, entry) {
    const terms = leadOrderMatchTermsForEntry(entry);
    if (!terms.length) return false;
    const text = normalizeMatch([
      installation?.label,
      installation?.brand,
      installation?.model,
      installation?.notes,
    ].filter(Boolean).join(" "));
    if (!text) return false;
    return terms.some((term) => {
      const normalized = normalizeMatch(term);
      if (!normalized) return false;
      if (text.includes(normalized)) return true;
      const words = normalized.split(/\s+/).filter((word) => word.length >= 4);
      if (words.length < 2) return false;
      const hits = words.filter((word) => text.includes(word)).length;
      return hits >= Math.min(2, words.length);
    });
  }

  function completedInstallationForLeadEntry(entry) {
    const customer = entry?.customer ? (findCustomer(leadEntryCustomerKey(entry)) || entry.customer) : null;
    if (!customer) return null;
    const leadDay = leadCreatedDay(entry);
    const rows = installationsForCustomer(customer)
      .filter((installation) => installation.active !== false)
      .filter((installation) => !installationLooksLikeLeadMetadata(installation))
      .filter((installation) => isoDayText(installation.installed_at));
    if (!rows.length) return null;
    const datedRows = leadDay
      ? rows.filter((installation) => isoDayText(installation.installed_at) >= leadDay)
      : [];
    const candidates = datedRows.length ? datedRows : rows;
    const matching = candidates.filter((installation) => installationMatchesLeadEntry(installation, entry));
    if (matching.length) return matching[0];
    return leadDay && datedRows.length === 1 ? datedRows[0] : null;
  }

  function leadEntryHasResolvedOutcome(entry, resolutionContext = null) {
    return Boolean(orderForLeadEntry(entry, resolutionContext) || completedInstallationForLeadEntry(entry));
  }

  function orderIdForActivity(activity) {
    const metadataOrderId = activity?.metadata?.order_id || "";
    if (metadataOrderId && findOrder(metadataOrderId)) return metadataOrderId;
    const job = findJob(activity?.job_id || activity?.jobId);
    if (job?.source_table === "orders" && job.source_id && findOrder(job.source_id)) return job.source_id;
    return "";
  }

  function linkedOrderForBooking(bookingId) {
    const id = normalizeOrderId(bookingId);
    if (!id) return null;
    return Object.values(orders).find((order) => bookingIdsForOrder(order).includes(id)) || null;
  }

  function bookingRowsForOrder(order, bookingRowById = null) {
    const rowsById = bookingRowById || new Map(bookingRows().map((row) => [String(row.id), row]));
    return bookingIdsForOrder(order)
      .map((id) => rowsById.get(String(id)))
      .filter(Boolean);
  }

  function customerOrders(customer, preparedOrderRows = null) {
    const key = customerKey(customer);
    return (preparedOrderRows || orderRows())
      .filter((row) => row.customer && customerKey(row.customer) === key)
      .map((row) => row.order);
  }

  function orderRows() {
    const allBookingRows = bookingRows();
    const bookingRowById = new Map(allBookingRows.map((row) => [String(row.id), row]));
    return Object.entries(orders || {})
      .map(([id, order]) => {
        const normalized = { ...order, id: order.id || id, customerId: orderCustomerId(order) };
        const linkedBookings = bookingRowsForOrder(normalized, bookingRowById);
        return {
          id: normalized.id,
          order: normalized,
          customer: findCustomer(normalized.customerId),
          job: jobForOrder(normalized),
          linkedBookings,
        };
      })
      .filter((row) => row.order && row.customer)
      .sort((a, b) => {
        const rank = { unscheduled: 0, scheduled: 1, completed: 2, cancelled: 9 };
        const aStatus = orderEffectiveStatus(a.order, a.job, a.linkedBookings);
        const bStatus = orderEffectiveStatus(b.order, b.job, b.linkedBookings);
        const aBilling = orderEffectiveBillingStatus(a.order, a.job, a.linkedBookings);
        const bBilling = orderEffectiveBillingStatus(b.order, b.job, b.linkedBookings);
        const billingRank = (status) => status === "ready" ? -1 : status === "draft" ? -0.5 : status === "sent" ? 4 : 0;
        return billingRank(aBilling) - billingRank(bBilling)
          || (rank[aStatus] ?? 5) - (rank[bStatus] ?? 5)
          || String(a.order.scheduledDate || a.order.scheduled_date || a.order.completedAt || a.order.completed_at || a.order.created_at || "").localeCompare(String(b.order.scheduledDate || b.order.scheduled_date || b.order.completedAt || b.order.completed_at || b.order.created_at || ""))
          || cleanDisplayName(a.customer).localeCompare(cleanDisplayName(b.customer), "nb");
      });
  }

  function orderStatusLabel(status) {
    return orderStatuses[status]?.label || "Jobb";
  }

  function orderStatusHelp(status) {
    return orderStatuses[status]?.help || "Jobb knyttet til kundekortet.";
  }

  function billingStatusLabel(status) {
    return billingStatuses[status || "not_ready"] || "Ikke klar";
  }

  function jobWorkStatusLabel(status) {
    return jobWorkStatuses[status || "draft"]?.label || "Jobb";
  }

  function jobWorkStatusHelp(status) {
    return jobWorkStatuses[status || "draft"]?.help || "Status for jobben.";
  }

  function jobBillingStatusLabel(status) {
    return jobBillingStatuses[status || "not_ready"] || "Ikke klar";
  }

  function jobStatusClass(status) {
    return String(status || "draft").replace(/[^a-z0-9_-]/gi, "-");
  }

  function orderJobBadge(order, job = jobForOrder(order)) {
    if (job) {
      const status = job.work_status || "draft";
      return `<span class="order-badge job ${escapeHtml(jobStatusClass(status))}" title="${escapeHtml(jobWorkStatusHelp(status))}">${escapeHtml(jobWorkStatusLabel(status))}</span>`;
    }
    if ((order?.status || "") === "cancelled") {
      return `<span class="order-badge job cancelled" title="Avsluttede jobber skjules fra aktiv jobbliste.">Jobb avsluttet</span>`;
    }
    if (!store.isConfigured) return "";
    return `<span class="order-badge job missing" title="Dette er en eldre jobb som må klargjøres før videre behandling.">Må oppdateres</span>`;
  }

  function orderBadgesHtml(order, job = jobForOrder(order), linkedRows = null) {
    return `${orderStatusBadge(order, orderEffectiveStatus(order, job, linkedRows))}${orderBillingBadge(order, orderEffectiveBillingStatus(order, job, linkedRows))}${orderJobBadge(order, job)}`;
  }

  function orderStatusFromJob(job) {
    if (!job) return "";
    if (job.work_status === "draft") return "unscheduled";
    if (job.work_status === "planned" || job.work_status === "in_progress") return "scheduled";
    if (job.work_status === "completed") return "completed";
    if (job.work_status === "cancelled") return "cancelled";
    return "";
  }

  function orderEffectiveStatus(order, job = jobForOrder(order), linkedRows = null) {
    const rows = Array.isArray(linkedRows) ? linkedRows : bookingRowsForOrder(order);
    const explicit = orderStatusFromJob(job) || order?.status || "";
    if (explicit === "cancelled") return "cancelled";
    if (rows.some((row) => row.booking.status === "done" || doneJobs.has(row.id))) return "completed";
    if (rows.length && explicit !== "completed") return "scheduled";
    return explicit || "unscheduled";
  }

  function orderBillingStatusFromJob(job) {
    if (!job) return "";
    if (job.payment_status === "paid" || job.payment_status === "paid_on_site") return "paid";
    if (job.billing_status === "ready_for_invoice" || job.billing_status === "credit_needed") return "ready";
    if (job.billing_status === "exported") return "draft";
    if (job.billing_status === "invoiced") return "sent";
    return "";
  }

  function orderEffectiveBillingStatus(order, job = jobForOrder(order), linkedRows = null) {
    const explicit = orderBillingStatusFromJob(job) || order?.billingStatus || order?.billing_status || "not_ready";
    const type = order?.type || job?.job_type || job?.type || "";
    if (!billableJobType(type) && !["sent", "paid"].includes(explicit)) return "not_ready";
    if (explicit && explicit !== "not_ready") return explicit;
    const rows = Array.isArray(linkedRows) ? linkedRows : bookingRowsForOrder(order);
    if (rows.some((row) => bookingNeedsPaymentAction(row))) return "ready";
    return explicit || "not_ready";
  }

  function jobWorkStatusFromOrder(order) {
    if ((order?.status || "") === "completed") return "completed";
    if ((order?.status || "") === "cancelled") return "cancelled";
    if ((order?.status || "") === "scheduled") return "planned";
    return "draft";
  }

  function jobBillingStatusFromOrder(order) {
    const billing = order?.billingStatus || order?.billing_status || "not_ready";
    if (billing === "ready") return "ready_for_invoice";
    if (billing === "draft") return "exported";
    if (billing === "sent") return "invoiced";
    return "not_ready";
  }

  function jobPaymentStatusFromOrder(order) {
    const billing = order?.billingStatus || order?.billing_status || "not_ready";
    if (billing === "paid") return "paid_on_site";
    if (billing === "draft") return "unpaid";
    if (billing === "sent") return "unpaid";
    return "unknown";
  }

  function upsertLocalJobMirrorForOrder(order) {
    if (!store.isConfigured || !order?.id) return;
    const existingIndex = (jobs || []).findIndex((job) => (
      String(job.id || "") === String(order.jobId || order.job_id || "")
      || (job?.source_table === "orders" && normalizeOrderId(job.source_id) === normalizeOrderId(order.id))
    ));
    if (existingIndex < 0 && !(order.jobId || order.job_id)) return;
    const existing = existingIndex >= 0 ? jobs[existingIndex] : {};
    const hasInstallationId = Object.prototype.hasOwnProperty.call(order, "installationId")
      || Object.prototype.hasOwnProperty.call(order, "installation_id");
    const hasLocationId = Object.prototype.hasOwnProperty.call(order, "locationId")
      || Object.prototype.hasOwnProperty.call(order, "location_id");
    const next = {
      ...existing,
      id: existing.id || order.jobId || order.job_id,
      customer_id: order.customerId || order.customer_id || existing.customer_id || null,
      lead_id: order.leadId || order.lead_id || existing.lead_id || null,
      title: order.title || existing.title || "Jobb",
      job_type: order.type || existing.job_type || "service",
      installation_id: hasInstallationId ? (order.installationId ?? order.installation_id ?? null) : (existing.installation_id || null),
      location_id: hasLocationId ? (order.locationId ?? order.location_id ?? null) : (existing.location_id || null),
      work_status: jobWorkStatusFromOrder(order),
      billing_status: jobBillingStatusFromOrder(order),
      payment_status: jobPaymentStatusFromOrder(order),
      description: order.note || existing.description || null,
      source_table: "orders",
      source_id: order.id,
      completed_at: order.completedAt || order.completed_at || existing.completed_at || null,
      updated_at: order.updated_at || new Date().toISOString(),
    };
    if (existingIndex >= 0) jobs[existingIndex] = next;
    else jobs.unshift(next);
  }

  function orderMissingJobMirror(row) {
    const order = row?.order || row || {};
    return store.isConfigured && (order.status || "") !== "cancelled" && !row?.job && !jobForOrder(order);
  }

  function upsertJobMirror(job) {
    if (!job?.id) return;
    const index = (jobs || []).findIndex((item) => String(item.id || "") === String(job.id));
    if (index >= 0) jobs[index] = job;
    else jobs.unshift(job);
  }

  async function repairOrderJobMirror(orderId) {
    const order = findOrder(orderId);
    if (!order) throw new Error("Fant ikke jobben som skulle oppdateres.");
    if (!store.repairOrderJobMirror) throw new Error("Denne jobben kan ikke oppdateres i nåværende appversjon.");
    const job = await store.repairOrderJobMirror(order.id, order);
    if (!job?.id) throw new Error("Klarte ikke klargjøre jobben.");
    upsertJobMirror(job);
    orders[order.id] = { ...order, jobId: job.id, job_id: job.id };
    setSyncStatus("Jobben er klargjort.", "ok");
    renderAll();
  }

  function serviceWorkType(type) {
    return ["reparasjon", "servicearbeid", "reklamasjon"].includes(String(type || "").toLowerCase());
  }

  function serviceWorkNoteRegex() {
    return /\b(dryppanne|veggstativ|fjær|fjærer|gummidemper|gummidempere|dempere?|støy|flytte|flytting|demonter|monter|reparasjon|feil|fiks|fix|timejobb|timer|stativ|lekkasje|is|vann)\b/i;
  }

  function bookingDisplayType(rowOrBooking) {
    const booking = rowOrBooking?.booking || rowOrBooking || {};
    const type = booking.type || "service";
    if (serviceWorkType(type)) return "reparasjon";
    if (type === "service" && serviceWorkNoteRegex().test(booking.note || "")) return "reparasjon";
    return type;
  }

  function bookingJobLabel(rowOrBooking) {
    const displayType = bookingDisplayType(rowOrBooking);
    if (displayType === "reparasjon") return "Servicearbeid / timejobb";
    return bookingTypeLabel(displayType || "service");
  }

  function bookingWorkKind(rowOrBooking) {
    const displayType = bookingDisplayType(rowOrBooking);
    if (displayType === "reparasjon") {
      return {
        type: "reparasjon",
        label: "Servicearbeid / timejobb",
        help: "Ikke standardservice 2490,-. Dette faktureres etter timer, materiell eller avtalt pris.",
        billing: "Fakturer etter timer/avtale",
      };
    }
    if (displayType === "service") {
      return {
        type: "service",
        label: "Standard service",
        help: "Vanlig servicejobb. Normalt 2490,- og ny servicefrist etter utført service.",
        billing: "Standard service 2490,-",
      };
    }
    return {
      type: displayType,
      label: bookingTypeLabel(displayType),
      help: "Jobbtype valgt i booking.",
      billing: billableJobType(displayType) ? "Fakturerbar jobb" : "Oppfølging",
    };
  }

  function orderTypeLabel(type) {
    if (type === "blaseisolering") return "Blåseisolering";
    if (type === "annet") return "Annet arbeid";
    return bookingTypeLabel(type || "service");
  }

  function defaultOrderTitle(customer, type = "service") {
    return `${orderTypeLabel(type)} - ${cleanDisplayName(customer)}`;
  }

  function orderDateText(order) {
    const scheduled = order.scheduledDate || order.scheduled_date;
    const completed = order.completedAt || order.completed_at;
    if (scheduled) return `Planlagt ${formatDate(scheduled)}${order.scheduledTime || order.scheduled_time ? ` kl. ${escapeHtml(normalizeBookingTime(order.scheduledTime || order.scheduled_time))}` : ""}`;
    if (completed) return `Utført ${formatDate(completed)}`;
    return "Ikke planlagt";
  }

  function orderSearchText(row) {
    const order = row.order;
    const customer = row.customer;
    const job = row.job || jobForOrder(order);
    const status = orderEffectiveStatus(order, job, row.linkedBookings);
    const billing = orderEffectiveBillingStatus(order, job, row.linkedBookings);
    return normalizeMatch([
      order.title,
      order.note,
      order.type,
      order.status,
      order.billingStatus || order.billing_status,
      orderStatusLabel(status),
      billingStatusLabel(billing),
      job?.title,
      job?.work_status,
      job?.billing_status,
      orderInstallationText(order, customer, job),
      cleanDisplayName(customer),
      customer.phone,
      customer.email,
      customer.visit_street,
      customer.visit_city,
      customer.location_tag,
    ].filter(Boolean).join(" "));
  }

  function orderStatusBadge(order, effectiveStatus = "") {
    const rawStatus = order?.status || "unscheduled";
    const status = effectiveStatus || rawStatus;
    const adjusted = status !== rawStatus;
    const help = adjusted
      ? orderStatusHelp(status)
      : orderStatusHelp(status);
    return `<span class="order-badge ${escapeHtml(status)}" title="${escapeHtml(help)}">${escapeHtml(orderStatusLabel(status))}</span>`;
  }

  function orderBillingBadge(order, effectiveStatus = "") {
    const status = effectiveStatus || order.billingStatus || order.billing_status || "not_ready";
    if (status === "not_ready") return "";
    return `<span class="order-badge billing ${escapeHtml(status)}" title="Fakturastatus for jobben.">${escapeHtml(billingStatusLabel(status))}</span>`;
  }

  function workflowStep(label, state, help = "") {
    return { label, state, help };
  }

  function workflowHtml(flow, options = {}) {
    if (!flow) return "";
    const compact = options.compact ? " compact" : "";
    const summaryOnly = options.summaryOnly ? " summary-only" : "";
    const title = options.title || "Jobbflyt";
    return `
      <section class="job-flow ${escapeHtml(flow.kind || "info")}${compact}${summaryOnly}" title="${escapeHtml(flow.help || "Viser hva som er gjort og hva som er neste steg.")}">
        <div class="job-flow-head">
          <span>${escapeHtml(title)}</span>
          <strong>${escapeHtml(flow.heading)}</strong>
          <em>${escapeHtml(flow.next)}</em>
        </div>
        ${options.summaryOnly ? "" : `<ol class="job-flow-steps">
          ${flow.steps.map((step) => `
            <li class="${escapeHtml(step.state)}" title="${escapeHtml(step.help || step.label)}">
              <span></span>
              <strong>${escapeHtml(step.label)}</strong>
            </li>
          `).join("")}
        </ol>`}
      </section>
    `;
  }

  function billableJobType(type) {
    return ["service", "installasjon", "blaseisolering", "reparasjon", "servicearbeid", "reklamasjon", "utleie"].includes(type || "service");
  }

  function bookingCanHavePriceBasis(row) {
    return billableJobType(bookingDisplayType(row));
  }

  function bookingWorkflowState(row, order = null) {
    if (!row) return null;
    const type = bookingDisplayType(row);
    const workKind = bookingWorkKind(row);
    const done = row.booking.status === "done" || doneJobs.has(row.id);
    const needsMove = bookingNeedsMove(row);
    const paymentMode = bookingPaymentMode(row);
    const billingStatus = order?.billingStatus || order?.billing_status || "not_ready";
    const isCash = Boolean(row.customer?.pays_cash);
    const isBillable = billableJobType(type);
    const steps = [
      workflowStep("Jobb", "done", "Jobben finnes i systemet."),
      workflowStep("Planlagt", "done", "Jobben ligger i planen."),
      workflowStep("Utført", done ? "done" : needsMove || bookingNeedsCompletion(row) ? "warn" : "current", done ? "Jobben er markert utført." : "Trykk Fullfør når jobben er gjort."),
      workflowStep(isCash ? "Betaling" : "Faktura", "pending", isCash ? "Betaling på stedet må registreres mottatt." : "Faktura må sendes manuelt og markeres her."),
      workflowStep("Ferdig", "pending", "Ingen videre handling når betaling/fakturering er avklart."),
    ];

    if (needsMove) {
      steps[2] = workflowStep("Må flyttes", "warn", "Jobben ble ikke gjennomført og må avtales på nytt.");
      return {
        kind: "move",
        heading: "Må flyttes",
        next: "Avtal ny tid med kunde og flytt/book jobben på nytt.",
        help: "Jobben er ikke ferdig. Den må flyttes før den kan fullføres.",
        steps,
      };
    }

    if (!done) {
      const overdue = bookingNeedsCompletion(row);
      return {
        kind: overdue ? "overdue" : "scheduled",
        heading: overdue ? `${workKind.label}: dato passert` : `${workKind.label}: planlagt`,
        next: overdue ? "Trykk Fullfør hvis jobben er gjort, ellers Må flyttes." : "Neste steg er å utføre jobben og trykke Fullfør.",
        help: `${workKind.help} Jobben er ikke markert utført ennå.`,
        steps,
      };
    }

    steps[2] = workflowStep("Utført", "done", "Jobben er markert utført.");

    if (!isBillable) {
      if (type === "befaring") {
        steps[3] = workflowStep("Tilbud/salg", "current", "Befaring faktureres normalt ikke. Avklar tilbud, muntlig salg eller videre oppfølging.");
        steps[4] = workflowStep("Ferdig", "pending", "Ferdig når tilbud/salg/oppfølging er avklart.");
        return {
          kind: "followup",
          heading: "Befaring utført",
          next: "Send tilbud, marker muntlig tilbud/salg eller book installasjon.",
          help: "Befaring er et salgssteg og skal normalt ikke faktureres.",
          steps,
        };
      }
      steps[3] = workflowStep("Oppfølging", "current", "Befaring/annet arbeid kan trenge tilbud eller ny jobb.");
      steps[4] = workflowStep("Ferdig", "pending", "Lukkes når videre oppfølging er avklart.");
      return {
        kind: "done",
        heading: "Utført",
        next: "Sjekk om kunden skal ha tilbud, installasjon eller annen oppfølging.",
        help: "Jobben er utført, men denne typen jobb trenger ikke nødvendigvis faktura.",
        steps,
      };
    }

    if (billingStatus === "draft" || bookingNeedsInvoiceFinalAction(row)) {
      steps[3] = workflowStep("Utkast", "current", "Fakturautkast er laget/eksportert, men faktura er ikke markert sendt.");
      return {
        kind: "billing",
        heading: "Utkast i eAccounting",
        next: "Kontroller og send faktura i eAccounting. Marker Fakturert i CRM når faktura er sendt.",
        help: "Dette er et mellomsteg mellom Må faktureres og Fakturert.",
        steps,
      };
    }

    if (bookingNeedsPaymentAction(row) || billingStatus === "ready") {
      steps[3] = workflowStep(isCash ? "Betaling mangler" : "Må faktureres", "warn", isCash ? "Betaling på stedet er ikke markert mottatt." : "Faktura er ikke markert sendt.");
      return {
        kind: "billing",
        heading: isCash ? "Utført - betaling ikke registrert" : "Utført - må faktureres",
        next: isCash ? "Marker betalt når betalingen er mottatt." : "Send faktura i eAccounting og marker Fakturert her.",
        help: "Jobben er utført, men betaling/faktura mangler.",
        steps,
      };
    }

    if (paymentMode === "cash" || billingStatus === "paid") {
      steps[3] = workflowStep("Betalt", "done", "Betaling på stedet er registrert mottatt.");
      steps[4] = workflowStep("Ferdig", "done", "Jobben er ferdig behandlet.");
      return {
        kind: "complete",
        heading: "Ferdig - betalt",
        next: "Ingen handling nødvendig.",
        help: "Jobben er utført og betaling er registrert.",
        steps,
      };
    }

    if (paymentMode === "invoice" || billingStatus === "sent") {
      steps[3] = workflowStep("Fakturert", "done", "Faktura er markert sendt.");
      steps[4] = workflowStep("Ferdig", "done", "Jobben er ferdig behandlet.");
      return {
        kind: "complete",
        heading: "Ferdig - fakturert",
        next: "Ingen handling nødvendig.",
        help: "Jobben er utført og faktura er markert sendt.",
        steps,
      };
    }

    steps[3] = workflowStep(isCash ? "Betaling" : "Faktura", "current", "Avklar betaling/faktura.");
    return {
      kind: "billing",
      heading: "Utført - avklar betaling",
      next: isCash ? "Marker betalt hvis kunden har betalt på stedet." : "Marker Fakturert når faktura er sendt.",
      help: "Jobben er utført, men betalingsstatus er uklar.",
      steps,
    };
  }

  function orderWorkflowState(order, linkedRows = []) {
    if (!order) return null;
    const rows = linkedRows.length ? linkedRows : bookingIdsForOrder(order)
      .map((id) => bookingRows().find((row) => row.id === id))
      .filter(Boolean);
    const priorityRow = rows.find((row) => bookingNeedsPaymentAction(row))
      || rows.find((row) => bookingNeedsCompletion(row))
      || rows.find((row) => row.booking.status !== "done")
      || rows[0];
    if (priorityRow) return bookingWorkflowState(priorityRow, order);

    const linkedJob = jobForOrder(order);
    const status = orderEffectiveStatus(order, linkedJob, linkedRows);
    const billing = orderEffectiveBillingStatus(order, linkedJob, linkedRows);
    const billable = billableJobType(order.type || "service");
    const steps = [
      workflowStep("Jobb", "done", "Jobben finnes på kundekortet."),
      workflowStep("Planlagt", status === "unscheduled" ? "current" : "done", "Jobben må legges i planen."),
      workflowStep("Utført", status === "completed" ? "done" : "pending", "Jobben markeres utført etter arbeid."),
      workflowStep("Faktura", billing === "ready" ? "warn" : billing === "draft" ? "current" : billing === "sent" || billing === "paid" ? "done" : "pending", "Faktura/betaling avklares etter utført jobb."),
      workflowStep("Ferdig", billing === "sent" || billing === "paid" || (status === "completed" && !billable) ? "done" : "pending", "Ferdig når arbeid og betaling er avklart."),
    ];

    if (status === "cancelled") {
      return {
        kind: "move",
        heading: "Avsluttet",
        next: "Ingen aktiv jobb. Lag ny jobb hvis kunden skal følges opp igjen.",
        help: "Jobben er avsluttet.",
        steps: [workflowStep("Avsluttet", "warn", "Jobben er lukket uten videre arbeid.")],
      };
    }
    if (billing === "ready") {
      return {
        kind: "billing",
        heading: "Utført - må faktureres",
        next: "Send faktura i eAccounting og marker Fakturert.",
        help: "Jobben er utført, men faktura mangler.",
        steps,
      };
    }
    if (billing === "draft") {
      steps[3] = workflowStep("Utkast", "current", "Fakturautkast er laget/eksportert, men faktura er ikke markert sendt.");
      return {
        kind: "billing",
        heading: "Utkast i eAccounting",
        next: "Kontroller og send faktura i eAccounting. Marker Fakturert i CRM når faktura er sendt.",
        help: "Dette er et mellomsteg mellom Må faktureres og Fakturert.",
        steps,
      };
    }
    if (billing === "sent" || billing === "paid") {
      return {
        kind: "complete",
        heading: billing === "paid" ? "Ferdig - betalt" : "Ferdig - fakturert",
        next: "Ingen handling nødvendig.",
        help: "Jobben er ferdig behandlet.",
        steps,
      };
    }
    if (status === "completed") {
      if (!billable && (order.type || "") === "befaring") {
        steps[3] = workflowStep("Tilbud/salg", "current", "Befaring faktureres normalt ikke. Avklar tilbud, salg eller videre oppfølging.");
        return {
          kind: "followup",
          heading: "Befaring utført",
          next: "Send tilbud, marker muntlig tilbud/salg eller book installasjon.",
          help: "Befaring er et salgssteg og skal normalt ikke faktureres.",
          steps,
        };
      }
      return {
        kind: billable ? "billing" : "done",
        heading: billable ? "Utført - avklar faktura" : "Utført",
        next: billable ? "Marker fakturert når faktura er sendt." : "Sjekk om det trengs videre oppfølging.",
        help: "Jobben er utført.",
        steps,
      };
    }
    if (status === "scheduled") {
      return {
        kind: "scheduled",
        heading: "Planlagt - ikke utført",
        next: "Utfør jobben og trykk Fullfør i planen.",
        help: "Jobben ligger i kalenderen.",
        steps,
      };
    }
    return {
      kind: "unscheduled",
      heading: "Jobb - ikke planlagt",
      next: "Trykk Book tid og legg jobben i kalenderen.",
      help: "Jobben finnes, men den ligger ikke i kalenderen ennå.",
      steps,
    };
  }

  function workflowInlineHtml(flow) {
    if (!flow) return "";
    return `<div class="job-next-action ${escapeHtml(flow.kind || "info")}" title="${escapeHtml(flow.help || "")}"><strong>${escapeHtml(flow.heading)}</strong><span>Neste: ${escapeHtml(flow.next)}</span></div>`;
  }

  function bookingWorkflowButtons(row, options = {}) {
    if (!row || !isAdmin()) return "";
    const done = row.booking.status === "done" || doneJobs.has(row.id);
    const needsMove = bookingNeedsMove(row);
    const canHavePriceBasis = bookingCanHavePriceBasis(row);
    const paymentActionLabel = row.customer?.pays_cash ? "Betalt" : "Fakturert";
    return [
      !done ? `<button data-complete-booking="${escapeHtml(row.id)}" type="button">Fullfør jobb</button>` : "",
      done && bookingNeedsPaymentAction(row) ? `<button data-billing-booking="${escapeHtml(row.id)}" type="button">${escapeHtml(paymentActionLabel)}</button>` : "",
      done && canHavePriceBasis ? `<button class="secondary" data-price-basis-booking="${escapeHtml(row.id)}" type="button">Fakturagrunnlag</button>` : "",
      !done && !needsMove ? `<button class="secondary" data-move-booking="${escapeHtml(row.id)}" type="button">Må flyttes</button>` : "",
      options.includeEdit ? `<button class="secondary" data-edit-booking="${escapeHtml(row.id)}" type="button">Endre tid</button>` : "",
    ].filter(Boolean).join("");
  }

  function bookingQuickFocusHtml(row, linkedOrder = null) {
    if (!row) return "";
    const workKind = bookingWorkKind(row);
    const flow = bookingWorkflowState(row, linkedOrder);
    const linkedJob = linkedOrder ? jobForOrder(linkedOrder) : null;
    const workLocation = workLocationForCustomer(row.customer, { booking: row.booking, order: linkedOrder, job: linkedJob });
    const fieldActions = [
      mapActionLink(row.customer, workLocation),
      row.customer?.phone ? `<a href="tel:${escapeHtml(phoneForLink(row.customer.phone))}" title="Ring kunden på registrert telefonnummer.">Ring kunde</a>` : "",
    ].filter(Boolean).join("");
    const done = row.booking.status === "done" || doneJobs.has(row.id);
    const needsMove = bookingNeedsMove(row);
    const statusLine = bookingNeedsPaymentAction(row)
      ? (row.customer?.pays_cash ? "Utført, men betaling er ikke registrert." : "Utført, men faktura er ikke markert sendt.")
      : needsMove
        ? "Jobben må avtales på nytt eller flyttes."
        : bookingNeedsCompletion(row)
          ? "Datoen er passert. Fullfør jobben hvis den er gjort, ellers flytt den."
          : done
            ? "Jobben er markert utført."
            : "Jobben er planlagt, men ikke markert utført.";
    return `
      <section class="quick-job-focus ${escapeHtml(workKind.type)}">
        <div class="quick-job-head">
          <span class="job-type-pill ${escapeHtml(workKind.type)}">${escapeHtml(workKind.label)}</span>
          <strong>${escapeHtml(statusLine)}</strong>
          <em>${escapeHtml(formatDate(row.booking.date))} kl. ${escapeHtml(bookingTimeText(row.booking))} · ${escapeHtml(row.booking.resource || "Ikke satt")}</em>
        </div>
        ${fieldActions ? `<div class="quick-field-actions">${fieldActions}</div>` : ""}
        <p class="job-billing-hint">${escapeHtml(workKind.billing)}. ${escapeHtml(workKind.help)}</p>
        ${row.booking.note ? `<p class="quick-job-note">${escapeHtml(cleanBookingNote(row.booking.note)).replaceAll("\n", "<br>")}</p>` : ""}
        ${flow ? workflowHtml(flow, { title: "Hva skjer med jobben?", compact: true }) : ""}
        ${isAdmin() ? `<div class="quick-work-actions">${bookingWorkflowButtons(row, { includeEdit: true })}</div>` : ""}
      </section>
    `;
  }

  function orderTitleFromBooking(customer, booking) {
    return `${bookingJobLabel(booking || { type: "service" })} - ${cleanDisplayName(customer)}`;
  }

  function orderDraftForBooking(bookingId, booking, overrides = {}) {
    const customer = findCustomer(booking.customerId);
    const type = bookingDisplayType(booking);
    const installationId = overrides.installationId ?? overrides.installation_id ?? booking.installationId ?? booking.installation_id ?? "";
    const locationId = overrides.locationId ?? overrides.location_id ?? booking.locationId ?? booking.location_id ?? "";
    const isDone = overrides.status === "completed" || booking.status === "done" || doneJobs.has(bookingId);
    const paymentMode = customer ? bookingPaymentMode({ id: bookingId, booking, customer }) : "";
    const billingStatus = overrides.billingStatus
      || (paymentMode === "cash" ? "paid" : "")
      || (paymentMode === "invoice" ? "sent" : "")
      || (isDone && billableJobType(type) && !customer?.pays_cash ? "ready" : "not_ready");
    return setBookingIdsForOrder({
      id: overrides.id,
      customerId: booking.customerId,
      title: overrides.title || orderTitleFromBooking(customer || {}, booking),
      type,
      status: overrides.status || (isDone ? "completed" : "scheduled"),
      billingStatus,
      source: overrides.source || "booking",
      scheduledDate: booking.date || "",
      scheduledTime: normalizeBookingTime(booking.time),
      resource: booking.resource || "",
      installationId,
      installation_id: installationId,
      locationId,
      location_id: locationId,
      completedAt: overrides.completedAt || (isDone ? booking.done_at || booking.date || "" : ""),
      note: overrides.note ?? noteWithJobPriceBasis(cleanBookingNote(booking.note || ""), extractJobPriceBasis(booking.note || "")),
      created_at: overrides.created_at || new Date().toISOString(),
      updated_at: new Date().toISOString(),
    }, [bookingId]);
  }

  async function saveOrderRecord(id, order, options = {}) {
    const nextId = normalizeOrderId(id || order.id) || `order-${Date.now()}-${Math.random().toString(16).slice(2)}`;
    const mirrorJob = jobForOrder(order.id || id || nextId);
    const hasInstallationId = Object.prototype.hasOwnProperty.call(order, "installationId")
      || Object.prototype.hasOwnProperty.call(order, "installation_id");
    const hasLocationId = Object.prototype.hasOwnProperty.call(order, "locationId")
      || Object.prototype.hasOwnProperty.call(order, "location_id");
    const hasLeadId = Object.prototype.hasOwnProperty.call(order, "leadId")
      || Object.prototype.hasOwnProperty.call(order, "lead_id");
    const leadId = hasLeadId ? (order.leadId ?? order.lead_id ?? "") : (mirrorJob?.lead_id || "");
    const installationId = hasInstallationId ? (order.installationId ?? order.installation_id ?? "") : (mirrorJob?.installation_id || "");
    const locationId = hasLocationId ? (order.locationId ?? order.location_id ?? "") : (mirrorJob?.location_id || "");
    const record = {
      ...order,
      id: nextId,
      customerId: order.customerId || order.customer_id || "",
      type: order.type || "service",
      status: order.status || "unscheduled",
      billingStatus: order.billingStatus || order.billing_status || "not_ready",
      leadId,
      lead_id: leadId,
      installationId,
      installation_id: installationId,
      locationId,
      location_id: locationId,
      updated_at: new Date().toISOString(),
    };
    setBookingIdsForOrder(record, bookingIdsForOrder(record));
    if (store.isConfigured && store.saveOrder && !options.localOnly) {
      const saved = await store.saveOrder(nextId, record);
      const savedWithLinks = {
        ...saved,
        leadId: saved.leadId || saved.lead_id || record.leadId || record.lead_id || "",
        lead_id: saved.lead_id || saved.leadId || record.lead_id || record.leadId || "",
      };
      orders[savedWithLinks.id] = savedWithLinks;
      upsertLocalJobMirrorForOrder(savedWithLinks);
      if (nextId !== savedWithLinks.id) delete orders[nextId];
      return savedWithLinks;
    }
    if (store.isConfigured && options.localOnly) {
      orders[nextId] = record;
      upsertLocalJobMirrorForOrder(record);
      return record;
    }
    requireLocalDemoStorage();
    orders[nextId] = record;
    saveLocalOrders();
    return record;
  }

  function unlinkOrderFromLocalBookings(orderId) {
    let changed = false;
    for (const booking of Object.values(bookings || {})) {
      if (booking?.orderId === orderId) {
        booking.orderId = "";
        changed = true;
      }
    }
    if (changed && !store.isConfigured) saveLocalBookings();
  }

  async function deleteOrderRecord(orderId, options = {}) {
    const id = normalizeOrderId(orderId);
    if (!id || !orders[id]) return;
    const order = orders[id];
    const bookingIds = bookingIdsForOrder(order);
    if (store.isConfigured && store.deleteOrder && !String(id).startsWith("order-")) {
      await store.deleteOrder(id);
    }
    delete orders[id];
    selectedOrderIds.delete(id);
    if (selectedOrderId === id) selectedOrderId = "";
    unlinkOrderFromLocalBookings(id);
    if (options.cancelLinkedBookings) {
      for (const bookingId of bookingIds) {
        if (bookings[bookingId]) {
          if (store.isConfigured) await store.cancelBooking(bookingId);
          delete bookings[bookingId];
        }
      }
      if (!store.isConfigured) saveLocalBookings();
    }
    if (!store.isConfigured) saveLocalOrders();
  }

  function showDeleteOrdersMessage(message, type = "error") {
    if (!el.deleteOrdersDialogMessage) return;
    el.deleteOrdersDialogMessage.textContent = message || "";
    el.deleteOrdersDialogMessage.className = `dialog-message ${type}`;
    el.deleteOrdersDialogMessage.classList.toggle("hidden", !message);
  }

  function clearDeleteOrdersMessage() {
    showDeleteOrdersMessage("", "error");
  }

  function orderDeleteSummary(ids) {
    const linkedBookingCount = ids.reduce((sum, id) => sum + bookingIdsForOrder(orders[id]).filter((bookingId) => bookings[bookingId]).length, 0);
    const examples = ids
      .slice(0, 4)
      .map((id) => {
        const order = orders[id];
        const customer = order ? findCustomer(orderCustomerId(order)) : null;
        return `<li>${escapeHtml(order?.title || "Jobb")} · ${escapeHtml(customer ? cleanDisplayName(customer) : "Ukjent kunde")}</li>`;
      })
      .join("");
    return { linkedBookingCount, examples };
  }

  function openDeleteOrdersDialog(ids = [...selectedOrderIds]) {
    const realIds = ids.map(normalizeOrderId).filter((id) => orders[id]);
    if (!realIds.length || !el.deleteOrdersDialog) return;
    deleteOrdersDialogIds = realIds;
    const { linkedBookingCount, examples } = orderDeleteSummary(realIds);
    el.deleteOrdersSummary.innerHTML = `
      <strong>${realIds.length} jobber valgt</strong>
      <span>${linkedBookingCount ? `${linkedBookingCount} avtale${linkedBookingCount === 1 ? "" : "r"} er koblet til valgte jobber.` : "Ingen aktive avtaler er koblet til valgte jobber."}</span>
      ${examples ? `<ul>${examples}${realIds.length > 4 ? `<li>+ ${realIds.length - 4} flere</li>` : ""}</ul>` : ""}
    `;
    if (el.deleteOrdersBookingOptions) el.deleteOrdersBookingOptions.classList.toggle("hidden", linkedBookingCount === 0);
    if (el.deleteOrdersKeepBookings) el.deleteOrdersKeepBookings.checked = true;
    clearDeleteOrdersMessage();
    el.deleteOrdersDialog.showModal();
  }

  async function deleteSelectedOrders(options = {}) {
    const ids = (deleteOrdersDialogIds.length ? deleteOrdersDialogIds : [...selectedOrderIds]).filter((id) => orders[id]);
    if (!ids.length) return;
    for (const id of ids) await deleteOrderRecord(id, { cancelLinkedBookings: Boolean(options.cancelLinkedBookings) });
    selectedOrderIds = new Set();
    deleteOrdersDialogIds = [];
    renderAll();
    setSyncStatus(`${ids.length} jobber slettet.`, "ok");
  }

  async function ensureOrderForBooking(bookingId, booking, overrides = {}, options = {}) {
    if (!bookingId || !booking?.customerId) return null;
    const existing = findOrder(booking.orderId) || linkedOrderForBooking(bookingId);
    const draft = orderDraftForBooking(bookingId, booking, { ...overrides, id: existing?.id || overrides.id });
    const merged = existing ? {
      ...existing,
      ...draft,
      created_at: existing.created_at || draft.created_at,
      title: existing.title || draft.title,
      note: overrides.note ?? existing.note ?? draft.note,
    } : draft;
    if ("invoicedAt" in overrides || "invoiced_at" in overrides) {
      merged.invoicedAt = overrides.invoicedAt || overrides.invoiced_at || "";
    }
    setBookingIdsForOrder(merged, [...bookingIdsForOrder(existing), bookingId]);
    const saved = await saveOrderRecord(merged.id, merged, { quiet: true, localOnly: options.localOnly });
    if (bookings[bookingId]) {
      bookings[bookingId].orderId = saved.id;
      if (!store.isConfigured) saveLocalBookings();
    }
    return saved;
  }

  async function ensureOrdersForLoadedBookings() {
    if (!isAdmin()) return 0;
    if (store.isConfigured && !store.saveOrder) return 0;
    let created = 0;
    for (const row of bookingRows()) {
      const existing = findOrder(row.booking.orderId) || linkedOrderForBooking(row.id);
      if (existing) {
        if (bookings[row.id] && bookings[row.id].orderId !== existing.id) bookings[row.id].orderId = existing.id;
        continue;
      }
      await ensureOrderForBooking(row.id, row.booking);
      created += 1;
    }
    if (created && !store.isConfigured) saveLocalBookings();
    return created;
  }

  async function markOrderUnscheduledForBooking(bookingId) {
    const order = linkedOrderForBooking(bookingId);
    if (!order) return;
    const ids = bookingIdsForOrder(order).filter((id) => id !== bookingId);
    const next = {
      ...order,
      status: ids.length ? order.status : "unscheduled",
      scheduledDate: ids.length ? order.scheduledDate : "",
      scheduledTime: ids.length ? order.scheduledTime : "",
    };
    setBookingIdsForOrder(next, ids);
    await saveOrderRecord(order.id, next, { quiet: true });
  }

  async function markOrderInvoicedForBooking(bookingId, invoiceDate) {
    return markOrderBillingForBooking(bookingId, "sent", invoiceDate);
  }

  async function markOrderBillingForBooking(bookingId, billingStatus, billingDate) {
    const order = linkedOrderForBooking(bookingId);
    if (!order) return;
    await saveOrderRecord(order.id, {
      ...order,
      billingStatus,
      invoicedAt: billingDate,
      status: order.status === "unscheduled" ? "completed" : order.status,
    }, { quiet: true });
  }

  async function markOrderInvoicedFromDetail(orderId) {
    const order = findOrder(orderId);
    if (!order) throw new Error("Fant ikke jobben.");
    const customer = findCustomer(orderCustomerId(order));
    if (!customer) throw new Error("Fant ikke kundekortet til jobben.");
    const invoiceDate = isoDate(new Date());
    const saved = await saveOrderRecord(order.id, {
      ...order,
      status: order.status === "cancelled" ? "cancelled" : "completed",
      billingStatus: "sent",
      completedAt: order.completedAt || order.completed_at || invoiceDate,
      invoicedAt: invoiceDate,
    }, { quiet: true });
    const linkedJob = jobForOrder(saved);
    const priceBasis = extractJobPriceBasis(saved.note || order.note);
    const installationText = orderInstallationText(saved, customer, linkedJob);
    const body = [
      `${orderTypeLabel(saved.type)} markert fakturert ${formatDate(invoiceDate)}.`,
      saved.title ? `Jobb: ${saved.title}.` : "",
      installationText ? `Anlegg/adresse: ${installationText}.` : "",
      priceBasis ? `Fakturagrunnlag/tillegg:\n${priceBasis}` : "",
    ].filter(Boolean).join("\n");
    const warnings = [];
    try {
      await saveServiceEvent(customer, {
        event_date: invoiceDate,
        event_type: "Fakturert",
        note: body,
      });
    } catch (error) {
      warnings.push(error.message || "historikk");
    }
    try {
      await saveActivityRecord({
        customer_id: customer.id || customerKey(customer),
        job_id: linkedJob?.id || saved.jobId || saved.job_id || "",
        activity_type: "job_invoiced",
        summary: "Jobb markert fakturert",
        body,
        metadata: {
          order_id: saved.id || order.id,
          billing_status: "sent",
          source: "order_detail",
        },
      });
    } catch (error) {
      warnings.push(error.message || "aktivitet");
    }
    warnings.push(...await completeApprovedInvoiceActionsFor({
      orderId: saved.id || order.id,
      jobId: linkedJob?.id || saved.jobId || saved.job_id || "",
    }));
    renderAll();
    if (warnings.length) {
      setSyncStatus(`Jobb markert fakturert, men etterarbeidet ble ikke fullstendig lagret: ${warnings.join(" / ")}`, "error");
    } else {
      setSyncStatus("Jobb markert fakturert og lagret i kundehistorikk.", "ok");
    }
  }

  function leadOrderContextNote(note) {
    const raw = String(note || "").trim();
    if (!raw) return "";
    if (offerLinesFromText(raw) || /\bCRM-ref:\s*NVS-TILBUD-/i.test(raw) || /Prisliste\s*\/\s*prisgrunnlag/i.test(raw)) return "";
    const referenceSplit = splitEmailReferenceFooter(raw);
    return cleanBookingNote(stripOfferDocumentBlock(stripOfferLinesBlock(stripOfferContextBlock(referenceSplit.body)))).trim();
  }

  function leadOrderLooksLikeInstallationSale(productInterest = "", priceBasis = "", accessories = "") {
    const text = normalizeMatch([productInterest, priceBasis, accessories].filter(Boolean).join(" "));
    return /\b(standard montering|installasjon|panasonic|fujitsu|toshiba|mitsubishi|daikin|norgespumpa|signatur|signature|flagship|etherea|seiya|gulvmodell|hz25|nz25|z25|z35|varmepumpehus|vps90)\b/.test(text);
  }

  async function createOrderFromLead(customerId, options = {}) {
    const entry = leadEntryForTarget(customerId);
    const targetCustomerId = entry ? leadEntryCustomerKey(entry) : customerId;
    const customer = findCustomer(targetCustomerId);
    if (!customer) throw new Error("Fant ikke sak/kunde.");
    const lead = entry?.lead || leadForCustomer(customer);
    const leadId = lead?.id || "";
    const lockKey = `lead-order:${leadId || customerKey(customer)}`;
    if (pendingLeadOrderKeys.has(lockKey)) {
      setSyncStatus("Jobb opprettes allerede. Vent et øyeblikk.", "");
      return;
    }
    pendingLeadOrderKeys.add(lockKey);
    try {
      const note = entry ? leadNoteForEntry(entry) : leadNoteForCustomer(customer);
      const selectedInstallation = options.installationId
        ? installationsForCustomer(customer).find((installation) => String(installation.id || "") === String(options.installationId))
        : null;
      const selectedLocation = selectedInstallation ? locationForInstallation(selectedInstallation, customer) : null;
      const productParts = String(options.productInterest || "").trim()
        ? [options.productInterest]
        : [lead?.product_interest, customer.brand, customer.model_or_note];
      const productInterest = productParts
        .map((item) => String(item || "").trim())
        .filter(Boolean)
        .join(" · ");
      const accessories = String(options.accessories || "").trim();
      const wonNote = String(options.note || "").trim();
      const explicitPriceBasis = String(options.priceBasis || "").trim();
      const sourceDetail = String(lead?.source_detail || customer.latest_deal_name || "").trim();
      const contextNote = leadOrderContextNote(note);
      const leadText = normalizeMatch([note, productInterest, sourceDetail, customer.tags].filter(Boolean).join(" "));
      const type = /\b(blaseisolering|isobygg|isolering|supafil)\b/.test(leadText)
        ? "blaseisolering"
        : leadOrderLooksLikeInstallationSale(productInterest, explicitPriceBasis, accessories)
          ? "installasjon"
          : /\b(service|reparasjon|feil|drypp|stoy|støy)\b/.test(leadText)
          ? "service"
          : "installasjon";
      const priceBasis = explicitPriceBasis || (type === "installasjon"
        ? priceBasisFromSalesDetails(productInterest, accessories)
        : priceBasisFromSalesDetails("", accessories));
      const existingLeadOrder = orderForLeadEntry(entry) || orderForLeadId(leadId);
      const existingOrderId = normalizeOrderId(existingLeadOrder?.id || "");
      if (existingOrderId) {
        openOrderById(existingOrderId);
        setSyncStatus("Denne saken har allerede en jobb. Jeg åpnet eksisterende jobb i stedet.", "ok");
        return;
      }
      const openOrders = customerOrders(customer).filter((order) => !["completed", "cancelled"].includes(orderEffectiveStatus(order, jobForOrder(order), bookingRowsForOrder(order))));
      if (openOrders.length) {
        const ok = await askForConfirmation({
          title: "Kunden har åpen jobb",
          message: `${cleanDisplayName(customer)} har allerede ${openOrders.length} åpen jobb. Opprette en ny jobb likevel?`,
          confirmLabel: "Opprett ny jobb",
        });
        if (!ok) return;
      }
      const orderNote = noteWithJobPriceBasis([
        "Fra vunnet oppfølging:",
        productInterest ? `Produkt/ønske: ${productInterest}` : "",
        accessories ? `Tilbehør/tillegg: ${accessories}` : "",
        selectedInstallation ? `Gjelder anlegg: ${installationDisplayName(selectedInstallation)}` : "",
        selectedLocation ? `Anleggsadresse: ${locationAddressText(selectedLocation)}` : "",
        sourceDetail && sourceDetail !== productInterest ? `Kilde/detalj: ${sourceDetail}` : "",
        wonNote ? `Avtalt/notat: ${wonNote}` : "",
        contextNote || `Kunden har takket ja. Status: ${leadStatusLabel(leadStatusForCustomer(customer))}.`,
        accessInfo(customer) ? `Adkomst: ${accessInfo(customer)}` : "",
      ].filter(Boolean).join("\n"), priceBasis);
      const titleProduct = productInterest || sourceDetail;
      const order = await saveOrderRecord("", {
        customerId: customerKey(customer),
        leadId,
        lead_id: leadId,
        title: `${orderTypeLabel(type)} - ${titleProduct || cleanDisplayName(customer)}`,
        type,
        status: "unscheduled",
        billingStatus: "not_ready",
        installationId: selectedInstallation?.id || "",
        installation_id: selectedInstallation?.id || "",
        locationId: selectedLocation?.id || "",
        location_id: selectedLocation?.id || "",
        source: "lead",
        note: orderNote,
        created_at: new Date().toISOString(),
      });
      await saveServiceEvent(customer, {
        event_date: isoDate(new Date()),
        event_type: "Jobb opprettet",
        note: [
          `${orderTypeLabel(type)} opprettet fra vunnet oppfølging.`,
          productInterest ? `Produkt/ønske: ${productInterest}.` : "",
          accessories ? `Tilbehør/tillegg: ${accessories}.` : "",
          selectedInstallation ? `Anlegg: ${installationDisplayName(selectedInstallation)}.` : "",
          wonNote,
          contextNote,
        ].filter(Boolean).join(" ").trim(),
      });
      if (options.bookAfter) {
        selectedOrderId = order.id;
        renderAll();
        openBookingDialog(customerKey(customer), "", {
          orderId: order.id,
          type: type === "blaseisolering" ? "blaseisolering" : type,
          installationId: selectedInstallation?.id || "",
          note: order.note || orderNote,
        });
        setSyncStatus("Jobb opprettet. Velg dato og tid for avtalen.", "ok");
        return;
      }
      openOrderById(order.id, { filter: "unscheduled" });
      setSyncStatus("Jobb opprettet fra oppfølging.", "ok");
    } finally {
      pendingLeadOrderKeys.delete(lockKey);
    }
  }

  function showOrderDialogMessage(message, tone = "error") {
    if (!el.orderDialogMessage) return;
    el.orderDialogMessage.textContent = message || "";
    el.orderDialogMessage.className = `dialog-message ${tone || ""}`.trim();
  }

  function clearOrderDialogMessage() {
    if (!el.orderDialogMessage) return;
    el.orderDialogMessage.textContent = "";
    el.orderDialogMessage.className = "dialog-message hidden";
  }

  function showCustomerDialogMessage(message, tone = "error") {
    if (!el.customerDialogMessage) return;
    el.customerDialogMessage.textContent = message || "";
    el.customerDialogMessage.className = `dialog-message ${tone || ""}`.trim();
  }

  function clearCustomerDialogMessage() {
    if (!el.customerDialogMessage) return;
    el.customerDialogMessage.textContent = "";
    el.customerDialogMessage.className = "dialog-message hidden";
  }

  function renderOrderInstallationOptions(customer, selectedId = "") {
    if (!el.orderInstallationSelect) return;
    const installations = selectableInstallationsForCustomer(customer, selectedId);
    const autoId = !selectedId && installations.length === 1 ? String(installations[0].id || "") : "";
    const current = selectedId || autoId;
    const rows = [
      `<option value="">Ikke valgt / gjelder hele kunden</option>`,
      ...installations.map((installation) => {
        const location = locationForInstallation(installation, customer);
        const locationText = locationAddressText(location);
        const label = [installationDisplayName(installation), locationText].filter(Boolean).join(" - ");
        return `<option value="${escapeHtml(installation.id || "")}">${escapeHtml(label)}</option>`;
      }),
    ];
    el.orderInstallationSelect.innerHTML = rows.join("");
    el.orderInstallationSelect.value = current;
    el.orderInstallationSelect.disabled = installations.length === 0;
    el.orderInstallationSelect.title = installations.length
      ? "Velg hvilket anlegg jobben gjelder. Dette brukes videre ved fullføring og servicefrist."
      : "Kunden har ingen registrerte varmepumper/anlegg ennå.";
  }

  function renderOrderPriceTotal() {
    if (!el.orderPriceTotal || !el.orderPriceLines) return;
    const total = jobPriceBasisTotal(el.orderPriceLines.value);
    el.orderPriceTotal.textContent = total > 0
      ? `Ca. avtalt grunnlag: ${formatJobPriceAmount(total)} inkl. mva - kan korrigeres ved fullføring.`
      : "Ingen summerbare produkt- eller prislinjer lagt inn.";
  }

  function syncOrderPriceQuantity() {
    if (!el.orderPricePreset || !el.orderPriceQuantity) return;
    const item = offerLinePresets.find((entry) => entry.id === el.orderPricePreset.value);
    if (item) el.orderPriceQuantity.value = String(item.defaultQty || 1);
    const heatPump = offerLineAutoIncludesStandardInstallation(item);
    el.orderStandardInstallationWrap?.classList.toggle("hidden", !heatPump);
    if (el.orderIncludeStandardInstallation) el.orderIncludeStandardInstallation.checked = heatPump;
  }

  function syncOrderPriceSearch() {
    if (!el.orderPricePreset) return;
    const query = el.orderPriceSearch?.value || "";
    const currentValue = el.orderPricePreset.value || "heatpump_custom";
    el.orderPricePreset.innerHTML = offerLinePresetOptions(currentValue, query);
    const available = new Set(Array.from(el.orderPricePreset.options).map((option) => option.value).filter(Boolean));
    const preferredValue = query.trim() && currentValue === "heatpump_custom"
      ? firstOfferLineMatch(query).id
      : currentValue;
    el.orderPricePreset.value = available.has(preferredValue) ? preferredValue : firstOfferLineMatch(query).id;
    syncOrderPriceQuantity();
  }

  function orderPriceLineFromSelection() {
    const selected = offerLinePresets.find((entry) => entry.id === el.orderPricePreset?.value);
    const quantity = Number(String(el.orderPriceQuantity?.value || selected?.defaultQty || 1).replace(",", "."));
    if (!Number.isFinite(quantity) || quantity <= 0) throw new Error("Antall må være større enn 0.");
    if (!selected || selected.id === "heatpump_custom") {
      const label = String(el.orderPriceSearch?.value || "").trim();
      if (!label) throw new Error("Søk eller velg produkt/tillegg før du legger til.");
      return customPriceLineFromText(label, quantity, "stk");
    }
    const line = jobPriceLineForItem(selected, quantity);
    if (offerLineAutoIncludesStandardInstallation(selected) && el.orderIncludeStandardInstallation?.checked) {
      return [line, standardInstallationOfferLine(quantity)].filter(Boolean).join("\n");
    }
    return line;
  }

  function addOrderPriceLine() {
    if (!el.orderPriceLines) return;
    const line = orderPriceLineFromSelection();
    const existing = String(el.orderPriceLines.value || "").trim();
    if (offerLinesAlreadyInclude(existing, line)) {
      showOrderDialogMessage("Linjen ligger allerede i grunnlaget. Endre antall hvis kunden skal ha flere.", "info");
      return;
    }
    el.orderPriceLines.value = [existing, line].filter(Boolean).join("\n");
    renderOrderPriceTotal();
    clearOrderDialogMessage();
  }

  function priceBasisLineForItem(item, quantity = 1) {
    if (!item || item.id === "heatpump_custom") return "";
    return jobPriceLineForItem(item, quantity || item.defaultQty || 1);
  }

  function appendUniquePriceBasisLine(lines, line) {
    const clean = String(line || "").trim();
    if (!clean) return lines;
    const existing = lines.join("\n");
    if (offerLinesAlreadyInclude(existing, clean)) return lines;
    return [...lines, clean];
  }

  function priceBasisLinesFromText(text, options = {}) {
    const terms = String(text || "")
      .split(/\r?\n|,/)
      .map((part) => part.trim())
      .filter(Boolean);
    let lines = [];
    for (const term of terms) {
      const item = firstOfferLineMatch(term);
      if (!item || item.id === "heatpump_custom") {
        lines = appendUniquePriceBasisLine(lines, customPriceLineFromText(term, 1, "stk"));
        continue;
      }
      lines = appendUniquePriceBasisLine(lines, priceBasisLineForItem(item, item.defaultQty || 1));
      if (options.includeStandardInstallation && offerLineAutoIncludesStandardInstallation(item)) {
        lines = appendUniquePriceBasisLine(lines, standardInstallationOfferLine(item.defaultQty || 1));
      }
    }
    return lines;
  }

  function priceBasisFromSalesDetails(productInterest = "", accessories = "") {
    const lines = [
      ...priceBasisLinesFromText(productInterest, { includeStandardInstallation: true }),
      ...priceBasisLinesFromText(accessories),
    ].reduce((result, line) => appendUniquePriceBasisLine(result, line), []);
    return lines.join("\n");
  }

  function setupOrderPriceFields(order, options = {}) {
    if (!el.orderPriceDetails || !el.orderPricePreset || !el.orderPriceLines) return;
    const sourceNote = order?.note || options.note || "";
    const generatedBasis = priceBasisFromSalesDetails(options.productInterest, options.accessories);
    const priceBasis = extractJobPriceBasis(sourceNote) || generatedBasis;
    if (el.orderPriceSearch) el.orderPriceSearch.value = String(options.productInterest || "").trim();
    el.orderPricePreset.innerHTML = offerLinePresetOptions("heatpump_custom", el.orderPriceSearch?.value || "");
    const firstMatch = el.orderPriceSearch?.value ? firstOfferLineMatch(el.orderPriceSearch.value) : null;
    if (firstMatch?.id && Array.from(el.orderPricePreset.options).some((option) => option.value === firstMatch.id)) {
      el.orderPricePreset.value = firstMatch.id;
    }
    if (el.orderPriceQuantity) el.orderPriceQuantity.value = "1";
    el.orderPriceLines.value = priceBasis;
    syncOrderPriceQuantity();
    el.orderPriceDetails.open = Boolean(priceBasis || options.productInterest || options.accessories);
    renderOrderPriceTotal();
  }

  function orderPriceBasisText() {
    return String(el.orderPriceLines?.value || "").trim();
  }

  function installationOrderProductSummary(order) {
    if (!order) return "";
    const priceBasis = extractJobPriceBasis(order.note || "");
    const rows = String(priceBasis || "").split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
    const products = uniqueStrings(rows
      .map((line) => heatPumpDescriptorForOfferLine(line)?.productInterest || "")
      .filter(Boolean));
    const specificProducts = products.filter((product) => {
      const normalized = normalizeMatch(product);
      return !products.some((candidate) => {
        const other = normalizeMatch(candidate);
        return other.length > normalized.length && other.includes(normalized);
      });
    });
    if (specificProducts.length) return specificProducts.join(" + ");
    const titleProduct = String(order.title || "").replace(/^\s*Installasjon\s*-\s*/i, "").trim();
    return cleanLeadStatusProductPrefill(titleProduct);
  }

  function bookingInstallationOrder() {
    return bookingPendingOrderId
      ? findOrder(bookingPendingOrderId)
      : linkedOrderForBooking(editingBookingId);
  }

  function renderBookingInstallationOptions(customer, selectedId = "") {
    if (!el.bookingInstallationSelect) return;
    const allInstallations = customer ? installationsForCustomer(customer) : [];
    const installations = allInstallations.filter((installation) => (
      installation.active !== false || String(installation.id || "") === String(selectedId || "")
    ));
    const activeInstallations = installations.filter((installation) => installation.active !== false);
    const installationJob = el.bookingType?.value === "installasjon";
    const newProduct = installationJob ? installationOrderProductSummary(bookingInstallationOrder()) : "";
    const autoId = !selectedId
      && ["service", "reparasjon"].includes(el.bookingType?.value || "service")
      && activeInstallations.length === 1
      ? String(activeInstallations[0].id || "")
      : "";
    const current = selectedId || autoId;
    const emptyOption = installationJob
      ? (newProduct ? `Nytt anlegg: ${newProduct}` : "Nytt anlegg")
      : "Ikke valgt / gjelder hele kunden";
    const rows = [
      `<option value="">${escapeHtml(emptyOption)}</option>`,
      ...installations.map((installation) => {
        const location = locationForInstallation(installation, customer);
        const label = [installationDisplayName(installation), locationAddressText(location)].filter(Boolean).join(" - ");
        return `<option value="${escapeHtml(installation.id || "")}">${escapeHtml(label)}</option>`;
      }),
    ];
    el.bookingInstallationSelect.innerHTML = rows.join("");
    el.bookingInstallationSelect.value = current;
    el.bookingInstallationSelect.disabled = !customer || (!installationJob && installations.length === 0);
    el.bookingInstallationSelect.title = current
      ? "Avtalen kobles til det eksisterende anlegget du valgte."
      : installationJob
        ? "Nytt anlegg opprettes automatisk når installasjonsjobben fullføres."
        : installations.length
          ? "Velg hvilket eksisterende anlegg avtalen gjelder."
          : "Kunden har ingen registrerte varmepumper/anlegg ennå.";
    if (el.bookingInstallationHint) {
      el.bookingInstallationHint.textContent = current
        ? "Jobben gjelder et eksisterende anlegg."
        : installationJob
          ? "Nytt anlegg opprettes på kundekortet når installasjonen fullføres."
          : installations.length
            ? "Velg anlegg hvis jobben gjelder en bestemt varmepumpe."
            : "Opprett anlegg på kundekortet før service hvis pumpen er kjent.";
    }
  }

  function selectedBookingInstallation(customer = findCustomer(bookingSelectedCustomerId)) {
    const installationId = el.bookingInstallationSelect?.value || "";
    if (!customer || !installationId) return null;
    return installationsForCustomer(customer).find((installation) => String(installation.id || "") === String(installationId)) || null;
  }

  function syncBookingInstallationNoteFromSelect() {
    const customer = findCustomer(bookingSelectedCustomerId);
    const installation = selectedBookingInstallation(customer);
    if (!customer || !installation) return;
    const generated = installationBookingNote(installation, customer);
    if (!generated) return;
    const keepLines = String(el.bookingNote?.value || "")
      .split(/\n+/)
      .map((line) => line.trim())
      .filter((line) => line && !/^(Anlegg|Adresse|Serviceintervall|Kodeboks\/nøkkel\/adkomst|Kodeboks\/nokkel\/adkomst):/i.test(line));
    el.bookingNote.value = [...keepLines, generated].filter(Boolean).join("\n");
  }

  function openOrderDialog(customerId, orderId = "", options = {}) {
    const order = findOrder(orderId);
    const customer = findCustomer(order ? orderCustomerId(order) : customerId);
    if (!customer) {
      setSyncStatus("Velg eller opprett kunde før du lager jobb.", "error");
      return;
    }
    editingOrderId = order?.id || "";
    orderDialogCustomerId = customerKey(customer);
    orderDialogBookingDefaults = options.bookingDefaults && typeof options.bookingDefaults === "object"
      ? { ...options.bookingDefaults }
      : null;
    orderTitleManuallyEdited = Boolean(order?.title || options.title);
    clearOrderDialogMessage();
    el.orderDialogTitle.textContent = order ? "Rediger jobb" : "Ny jobb";
    el.orderCustomerName.value = cleanDisplayName(customer);
    el.orderType.value = serviceWorkType(order?.type || options.type) ? "reparasjon" : (order?.type || options.type || "service");
    renderOrderInstallationOptions(customer, installationIdForOrder(
      order || options.order || { installationId: options.installationId || "" },
      jobForOrder(order || ""),
    ));
    el.orderTitleInput.value = order?.title || options.title || defaultOrderTitle(customer, el.orderType.value);
    el.orderBookNow.checked = Boolean(options.bookNow);
    el.orderNoteInput.value = cleanBookingNote(order?.note || options.note || "");
    setupOrderPriceFields(order, options);
    setSyncStatus("");
    el.orderDialog.showModal();
    setTimeout(() => el.orderNoteInput.focus(), 0);
  }

  function syncOrderTitleFromType() {
    const customer = findCustomer(orderDialogCustomerId);
    if (!customer || orderTitleManuallyEdited) return;
    el.orderTitleInput.value = defaultOrderTitle(customer, el.orderType.value);
  }

  function orderFormValues() {
    const customer = findCustomer(orderDialogCustomerId);
    if (!customer) throw new Error("Fant ikke kunden for jobben.");
    const installationId = el.orderInstallationSelect?.value || "";
    const installation = installationId
      ? installationsForCustomer(customer).find((item) => String(item.id || "") === String(installationId))
      : null;
    const location = installation ? locationForInstallation(installation, customer) : null;
    return {
      customer,
      type: el.orderType.value || "service",
      title: el.orderTitleInput.value.trim() || defaultOrderTitle(customer, el.orderType.value),
      note: noteWithJobPriceBasis(el.orderNoteInput.value.trim(), orderPriceBasisText()),
      cleanNote: el.orderNoteInput.value.trim(),
      priceBasis: orderPriceBasisText(),
      installationId,
      locationId: location?.id || "",
      bookNow: Boolean(el.orderBookNow.checked),
    };
  }

  async function saveOrderFromDialog() {
    const values = orderFormValues();
    const existing = findOrder(editingOrderId);
    const selectedInstallation = values.installationId
      ? installationsForCustomer(values.customer).find((item) => String(item.id || "") === String(values.installationId))
      : null;
    const order = await saveOrderRecord(editingOrderId, {
      ...existing,
      customerId: customerKey(values.customer),
      title: values.title,
      type: values.type,
      status: existing?.status || "unscheduled",
      billingStatus: existing?.billingStatus || existing?.billing_status || "not_ready",
      installationId: values.installationId,
      installation_id: values.installationId,
      locationId: values.locationId,
      location_id: values.locationId,
      source: existing?.source || "manual",
      note: values.note,
      created_at: existing?.created_at || new Date().toISOString(),
    });
    await saveServiceEvent(values.customer, {
      event_date: isoDate(new Date()),
      event_type: existing ? "Jobb endret" : "Jobb opprettet",
      note: [
        `${orderTypeLabel(values.type)}-jobb ${existing ? "endret" : "opprettet"} direkte på kundekort.`,
        selectedInstallation ? `Anlegg: ${installationDisplayName(selectedInstallation)}.` : "",
        values.cleanNote,
        values.priceBasis ? `Prisgrunnlag/tillegg:\n${values.priceBasis}` : "",
      ].filter(Boolean).join("\n"),
    });
    selectedOrderId = order.id;
    const shouldBook = values.bookNow;
    const customerId = customerKey(values.customer);
    const bookingDefaults = orderDialogBookingDefaults;
    orderDialogBookingDefaults = null;
    el.orderDialog.close();
    if (shouldBook) {
      renderAll();
      setSyncStatus(existing ? "Jobb oppdatert." : "Jobb opprettet direkte fra kundekort.", "ok");
      openBookingDialog(customerId, "", {
        orderId: order.id,
        type: values.type === "annet" ? "service" : values.type,
        installationId: values.installationId,
        note: values.note,
        ...(bookingDefaults || {}),
      });
    } else {
      setView("orders");
      setSyncStatus(existing ? "Jobb oppdatert." : "Jobb opprettet direkte fra kundekort.", "ok");
    }
  }

  function knownPlanningResources(rows = bookingRows()) {
    const resources = new Set(activeResourceNames());
    if (jointResourceAvailable()) resources.add("Gunnar og Hubert");
    if (currentUser?.name && !/bruker/i.test(currentUser.name) && !resourceBelongsToInactiveProfile(currentUser.name)) resources.add(currentUser.name);
    for (const row of rows) {
      const resource = String(row.booking.resource || "").trim();
      if (resource && !resourceBelongsToInactiveProfile(resource)) resources.add(resource);
    }
    return sortResourceNames([...resources]);
  }

  function resourceMatchesFilter(row, filter = planningResourceFilter) {
    if (!filter || filter === "all") return true;
    const resource = normalizeMatch(row?.booking?.resource || "");
    const selected = normalizeMatch(filter);
    if (!resource || !selected) return false;
    const jointGunnarHubert = resource.includes("gunnar") && resource.includes("hubert");
    if (selected === "gunnar og hubert") return jointGunnarHubert;
    return resource.includes(selected) || jointGunnarHubert;
  }

  function filteredPlanningRows(rows = bookingRows()) {
    return rows.filter((row) => resourceMatchesFilter(row));
  }

  function renderPlanningResourceOptions(rows = bookingRows()) {
    if (!el.planningResourceFilter) return;
    const current = planningResourceFilter || "all";
    const resources = knownPlanningResources(rows);
    if (current !== "all" && !resources.includes(current)) resources.push(current);
    el.planningResourceFilter.innerHTML = [
      `<option value="all">Alle ansatte</option>`,
      ...resources.map((resource) => `<option value="${escapeHtml(resource)}">${escapeHtml(resource)}</option>`),
    ].join("");
    planningResourceFilter = current === "all" || resources.includes(current) ? current : "all";
    el.planningResourceFilter.value = planningResourceFilter;
  }

  function invoiceMarkerRegex() {
    return /\[Fakturert[^\]]*\]/i;
  }

  function invoiceDraftMarkerRegex() {
    return /\[Fakturautkast[^\]]*\]/i;
  }

  function invoiceDraftMarkersRegex() {
    return /\[Fakturautkast[^\]]*\]/gi;
  }

  function cashPaymentMarkerRegex() {
    return /\[(Betalt cash|Betalt på stedet)[^\]]*\]/i;
  }

  function paymentMarkerRegex() {
    return /\[(Fakturert|Betalt cash|Betalt på stedet)[^\]]*\]/i;
  }

  function paymentMarkersRegex() {
    return /\[(Fakturert|Betalt cash|Betalt på stedet)[^\]]*\]/gi;
  }

  function moveMarkerRegex() {
    return /\[Må flyttes[^\]]*\]/gi;
  }

  function markerText(note, regex) {
    return String(note || "").match(regex)?.[0] || "";
  }

  function jobPriceBlockRegex() {
    return /\n*\[Prisgrunnlag\]\n?([\s\S]*?)\n?\[\/Prisgrunnlag\]\n*/i;
  }

  function extractJobPriceBasis(note) {
    return String(note || "").match(jobPriceBlockRegex())?.[1]?.trim() || "";
  }

  function stripJobPriceBasis(note) {
    return String(note || "")
      .replace(jobPriceBlockRegex(), "\n")
      .replace(/\n{3,}/g, "\n\n")
      .trim();
  }

  function noteWithJobPriceBasis(note, priceBasis) {
    const clean = stripJobPriceBasis(note);
    const priceText = String(priceBasis || "").trim();
    if (!priceText) return clean;
    return [clean, `[Prisgrunnlag]\n${priceText}\n[/Prisgrunnlag]`].filter(Boolean).join("\n");
  }

  function noteWithoutMoveMarker(note) {
    return String(note || "")
      .replace(moveMarkerRegex(), "")
      .replace(/\n{3,}/g, "\n\n")
      .trim();
  }

  function cleanLegacyWorkflowText(value) {
    return repairTextEncoding(String(value || ""))
      .split(/\r?\n/)
      .map((line) => line
        .replace(/\s*\blead\b\s*(?:[\/|·:-]\s*)?(?:ny\s+henvendelse)?\b/gi, " ")
        .replace(/\s*\bnew\s+installation\b\s*(?:[\/|·:-]\s*(?:phone|email))?/gi, " ")
        .replace(/\s*\bny\s+henvendelse\b\s*(?:[\/|·:-]\s*(?:phone|telefon|email|e-?post))?/gi, " ")
        .replace(/^[\s\/|·:-]+|[\s\/|·:-]+$/g, "")
        .replace(/\s{2,}/g, " ")
        .trim())
      .filter(Boolean)
      .join("\n")
      .trim();
  }

  function cleanBookingNote(note) {
    const clean = String(note || "")
      .replace(invoiceDraftMarkersRegex(), "")
      .replace(paymentMarkerRegex(), "")
      .replace(paymentMarkersRegex(), "")
      .replace(moveMarkerRegex(), "")
      .replace(jobPriceBlockRegex(), "")
      .trim();
    return cleanLegacyWorkflowText(clean);
  }

  function bookingNeedsMove(row) {
    return Boolean(row?.booking?.needs_move || moveMarkerRegex().test(row?.booking?.note || ""));
  }

  function bookingMoveReason(row) {
    const marker = markerText(row?.booking?.note, moveMarkerRegex());
    return marker.replace(/^\[Må flyttes\s*/i, "").replace(/\]$/, "").trim();
  }

  function isPastBookingDate(date) {
    return Boolean(date && date < isoDate(new Date()));
  }

  function bookingIsInvoiced(row) {
    return Boolean(row?.booking?.invoiced || invoiceMarkerRegex().test(row?.booking?.note || ""));
  }

  function bookingLinkedBillingStatus(row) {
    const order = row ? linkedOrderForBooking(row.id) || findOrder(row.booking.orderId) : null;
    if (!order) return "";
    return orderBillingStatusFromJob(jobForOrder(order)) || order.billingStatus || order.billing_status || "";
  }

  function bookingHasInvoiceDraft(row) {
    return Boolean(invoiceDraftMarkerRegex().test(row?.booking?.note || "") || bookingLinkedBillingStatus(row) === "draft");
  }

  function bookingIsPaidCash(row) {
    return Boolean(row?.booking?.paid_cash || cashPaymentMarkerRegex().test(row?.booking?.note || ""));
  }

  function bookingPaymentMode(row) {
    if (bookingIsPaidCash(row)) return "cash";
    if (bookingIsInvoiced(row)) return "invoice";
    return "";
  }

  function bookingPaymentDone(row) {
    return Boolean(bookingPaymentMode(row));
  }

  function bookingIsSettledForPlanning(row) {
    const done = row?.booking?.status === "done" || doneJobs.has(row?.id);
    if (!done) return false;
    if (!billableJobType(bookingDisplayType(row))) return bookingDisplayType(row) !== "befaring";
    return bookingPaymentDone(row);
  }

  function bookingNeedsSalesFollowup(row) {
    if (!row) return false;
    const done = row.booking.status === "done" || doneJobs.has(row.id);
    return done && bookingDisplayType(row) === "befaring" && !bookingNeedsMove(row);
  }

  function bookingNeedsInvoice(row) {
    if (!row || bookingPaymentDone(row)) return false;
    if (row.customer?.pays_cash) return false;
    if (!billableJobType(bookingDisplayType(row))) return false;
    if (bookingHasInvoiceDraft(row)) return false;
    return row.booking.status === "done" || doneJobs.has(row.id);
  }

  function bookingNeedsInvoiceFinalAction(row) {
    if (!row || bookingPaymentDone(row)) return false;
    if (row.customer?.pays_cash) return false;
    if (!billableJobType(bookingDisplayType(row))) return false;
    if (!bookingHasInvoiceDraft(row)) return false;
    return row.booking.status === "done" || doneJobs.has(row.id);
  }

  function bookingNeedsCashPayment(row) {
    if (!row || bookingPaymentDone(row)) return false;
    if (!row.customer?.pays_cash) return false;
    if (!billableJobType(bookingDisplayType(row))) return false;
    return row.booking.status === "done" || doneJobs.has(row.id);
  }

  function bookingNeedsPaymentAction(row) {
    return bookingNeedsInvoice(row) || bookingNeedsInvoiceFinalAction(row) || bookingNeedsCashPayment(row);
  }

  function bookingNeedsCompletion(row) {
    if (!row || row.booking.status === "done" || doneJobs.has(row.id)) return false;
    if (bookingNeedsMove(row)) return false;
    if (!["service", "installasjon", "blaseisolering", "reparasjon", "servicearbeid", "reklamasjon"].includes(bookingDisplayType(row))) return false;
    return isPastBookingDate(row.booking.date);
  }

  function billingQueueRows() {
    return bookingRows()
      .filter((row) => bookingNeedsPaymentAction(row) || bookingNeedsCompletion(row))
      .sort((a, b) => {
        const rank = (row) => bookingNeedsPaymentAction(row) ? 0 : 1;
        return rank(a) - rank(b) || String(a.booking.date || "").localeCompare(String(b.booking.date || ""));
      });
  }

  function moveQueueRows() {
    return bookingRows()
      .filter((row) => bookingNeedsMove(row) && row.booking.status !== "done" && !doneJobs.has(row.id))
      .sort((a, b) => `${a.booking.date || ""} ${a.booking.time || ""}`.localeCompare(`${b.booking.date || ""} ${b.booking.time || ""}`));
  }

  function setDemoUser(userKey) {
    if (store.isConfigured || !demoEnabled) {
      el.loginMessage.textContent = store.isConfigured
        ? "Tilkoblingen er klar. Bruk e-post og passord."
        : databaseUnavailableMessage;
      return;
    }
    currentUser = { ...users[userKey] };
    applyCurrentUserPreferences(currentUser);
    localStorage.setItem(storage.user, JSON.stringify(currentUser));
    currentView = currentUser.view;
    renderApp();
  }

  function isTechnicianUser() {
    return currentUser?.role === "Tekniker";
  }

  function viewAllowedForCurrentUser(view) {
    if (!isTechnicianUser()) return true;
    return new Set(["technician", "planning", "customers"]).has(view);
  }

  function defaultViewForCurrentUser() {
    return isTechnicianUser() ? "technician" : "dashboard";
  }

  function isMobileLayout() {
    return Boolean(window.matchMedia?.("(max-width: 760px)")?.matches);
  }

  function scrollPanelIntoMobileView(panel) {
    if (!panel || !isMobileLayout()) return;
    setTimeout(() => {
      panel.scrollIntoView({ behavior: "smooth", block: "start" });
    }, 0);
  }

  function closeFloatingMenus() {
    el.moreMenu?.classList.add("hidden");
    el.moreMenuButton?.setAttribute("aria-expanded", "false");
    el.mobileMoreMenu?.classList.add("hidden");
    el.mobileMoreButton?.setAttribute("aria-expanded", "false");
    el.newActionMenu?.classList.add("hidden");
    el.newActionButton?.setAttribute("aria-expanded", "false");
  }

  function appHistoryUrl() {
    return `${window.location.origin}${window.location.pathname}`;
  }

  function appHistoryState(view = currentView) {
    return { numedalCrm: true, view: view || defaultViewForCurrentUser() };
  }

  function isAppHistoryState(state) {
    return Boolean(state && state.numedalCrm === true);
  }

  function ensureAppHistoryGuard() {
    if (!currentUser || passwordRecoveryActive || !window.history?.replaceState || !window.history?.pushState) return;
    const state = appHistoryState();
    const url = appHistoryUrl();
    if (!isAppHistoryState(window.history.state)) {
      window.history.replaceState(state, "", url);
    }
    if (!appHistoryGuardPushed) {
      window.history.pushState(state, "", url);
      appHistoryGuardPushed = true;
    }
  }

  function updateAppHistory(previousView, options = {}) {
    if (options.fromHistory || !currentUser || passwordRecoveryActive || !window.history?.replaceState) return;
    ensureAppHistoryGuard();
    const state = appHistoryState();
    const url = appHistoryUrl();
    if (previousView && previousView !== currentView && window.history?.pushState) {
      window.history.pushState(state, "", url);
    } else if (isAppHistoryState(window.history.state)) {
      window.history.replaceState(state, "", url);
    }
  }

  function updateNavigationForRole() {
    const technician = isTechnicianUser();
    document.querySelectorAll("[data-admin-nav]").forEach((node) => node.classList.toggle("hidden", technician));
    document.querySelectorAll("[data-tech-nav]").forEach((node) => node.classList.toggle("hidden", !technician));
    document.querySelectorAll("[data-admin-mobile]").forEach((node) => node.classList.toggle("hidden", technician));
    document.querySelectorAll("[data-tech-mobile]").forEach((node) => node.classList.toggle("hidden", !technician));
    document.querySelectorAll('[data-tech-nav][data-view="technician"], [data-tech-mobile][data-view="technician"]').forEach((node) => {
      node.textContent = technicianText("navDay");
    });
    document.querySelectorAll("[data-mobile-more-toggle]").forEach((node) => node.classList.toggle("hidden", false));
    el.mobileMoreMenu?.classList.toggle("hidden", true);
    el.mobileMoreButton?.setAttribute("aria-expanded", "false");
    el.moreMenuButton?.closest(".more-nav-wrap")?.classList.toggle("hidden", technician);
  }

  function setNavigationActive(view) {
    const groupedView = view === "routeplanner" ? "planning" : view;
    document.querySelectorAll("[data-view]").forEach((button) => {
      const target = button.dataset.view;
      const grouped = target === groupedView && !button.closest(".more-menu");
      button.classList.toggle("active", target === view || grouped);
    });
    const moreActive = !isTechnicianUser() && moreNavigationViews.includes(view);
    el.moreMenuButton?.classList.toggle("active", moreActive);
    el.mobileMoreButton?.classList.toggle("active", moreActive);
    document.querySelectorAll("[data-plan-tab-view]").forEach((button) => button.classList.toggle("active", button.dataset.planTabView === view));
  }

  function scheduleNavigationRender(view) {
    if (pendingNavigationRender) window.cancelAnimationFrame(pendingNavigationRender);
    pendingNavigationRender = window.requestAnimationFrame(() => {
      pendingNavigationRender = 0;
      if (currentView === view) renderAll();
    });
  }

  function setView(view, options = {}) {
    const requestedView = view || currentUser?.view || defaultViewForCurrentUser();
    const previousView = currentView;
    currentView = viewAllowedForCurrentUser(requestedView) ? requestedView : defaultViewForCurrentUser();
    closeFloatingMenus();
    setNavigationActive(currentView);
    document.querySelectorAll(".view").forEach((panel) => panel.classList.add("hidden"));
    document.getElementById(`${currentView}View`)?.classList.remove("hidden");
    const titles = {
      dashboard: ["Start", "Hva må følges opp nå."],
      customers: ["Kunder", "Søk, rediger og book kunder."],
      leads: ["Innboks", "Nye meldinger, tilbud og oppfølging."],
      orders: ["Jobber", "Jobber fra oppfølging, kalender og utført arbeid."],
      insulation: ["Blåseisolering", "Kalkyle, dokumenter og kunder for iSOBYGG Buskerud."],
      planning: ["Plan", "Kalender for avtaler og jobber."],
      routeplanner: ["Servicerute", "Lag kjørbar rute av kunder som har svart ja."],
      technician: ["Min dag", "Jobbene dine på mobil."],
      settings: ["Innstillinger", "Produkter, tilbud, brukere og innlogging."],
    };
    if (currentView === "technician" && isTechnicianUser()) {
      el.viewTitle.textContent = technicianText("viewTitle");
      el.viewSubtitle.textContent = technicianText("viewSubtitle");
    } else {
      el.viewTitle.textContent = titles[currentView]?.[0] || "CRM";
      el.viewSubtitle.textContent = titles[currentView]?.[1] || "";
    }
    if (options.deferRender) {
      scheduleNavigationRender(currentView);
    } else {
      if (pendingNavigationRender) window.cancelAnimationFrame(pendingNavigationRender);
      pendingNavigationRender = 0;
      renderAll();
    }
    updateAppHistory(previousView, options);
    if (previousView !== currentView && isMobileLayout()) {
      window.scrollTo({ left: 0, top: 0, behavior: "auto" });
    }
    if (crmAssistantOpen) syncCrmAssistantContextIfOpen();
    else renderCrmAssistantContext();
  }

  const crmAssistantViewLabels = {
    dashboard: "Start",
    customers: "Kunder",
    leads: "Innboks",
    orders: "Jobber",
    insulation: "Blåseisolering",
    planning: "Plan",
    routeplanner: "Servicerute",
    technician: "Min dag",
    settings: "Innstillinger",
  };

  function crmAssistantCustomerPayload(customer) {
    return isUuid(customer?.id) ? customer.id : null;
  }

  function currentCrmAssistantContext() {
    const viewLabel = crmAssistantViewLabels[currentView] || "CRM";
    const payload = {
      view: currentView,
      viewLabel,
      capturedAt: new Date().toISOString(),
    };
    let title = viewLabel;
    let detail = "Bruker bare den aktive CRM-flaten som utgangspunkt.";

    if (currentView === "customers") {
      const customer = findCustomer(selectedCustomerId);
      if (customer) {
        if (crmAssistantCustomerPayload(customer)) payload.customerId = crmAssistantCustomerPayload(customer);
        title = `${viewLabel} · ${cleanDisplayName(customer)}`;
        detail = [addressFor(customer), customer.phone, customer.email].filter(Boolean).join(" · ") || "Kundekort uten kontaktinformasjon";
      }
    } else if (currentView === "leads") {
      const activeIntakeId = isUuid(aiRegistrationDraft?.intakeId)
        && !el.aiRegistrationDraft?.classList.contains("hidden")
        ? String(aiRegistrationDraft.intakeId)
        : "";
      const intake = activeIntakeId ? intakeItems.find((row) => String(row.id) === activeIntakeId) : null;
      if (activeIntakeId) {
        payload.intakeId = activeIntakeId;
        const linkedCustomerId = aiRegistrationDraft?.linkedCustomerId || intake?.linked_customer_id;
        const linkedLeadId = aiRegistrationDraft?.linkedLeadId || intake?.linked_lead_id;
        if (isUuid(linkedCustomerId)) payload.customerId = String(linkedCustomerId);
        if (isUuid(linkedLeadId)) payload.leadId = String(linkedLeadId);
        title = `${viewLabel} · ${aiRegistrationDraft?.name || intakeItemTitle(intake) || "åpen henvendelse"}`;
        detail = [
          intake?.source_channel || aiRegistrationSourceLabel(aiRegistrationDraft),
          intake?.source_subject,
          intake?.source_received_at ? crmAssistantTimeLabel(intake.source_received_at) : "",
        ].filter(Boolean).join(" · ") || "Aktiv henvendelse i Hurtigregistrering";
      } else {
        const entry = selectedLeadEntry();
        if (!entry) return { payload, title, detail };
        const customer = entry.customer || null;
        if (crmAssistantCustomerPayload(customer)) payload.customerId = crmAssistantCustomerPayload(customer);
        if (isUuid(entry.lead?.id)) payload.leadId = entry.lead.id;
        title = `${viewLabel} · ${cleanDisplayName(customer)}`;
        detail = [leadStatusForEntry(entry), entry.lead?.product_interest, customer?.phone].filter(Boolean).join(" · ") || "Aktiv innbokssak";
      }
    } else if (currentView === "orders") {
      const order = findOrder(selectedOrderId);
      const customer = order ? findCustomer(orderCustomerId(order)) : null;
      if (order) {
        if (crmAssistantCustomerPayload(customer)) payload.customerId = crmAssistantCustomerPayload(customer);
        if (isUuid(order.id || selectedOrderId)) payload.orderId = order.id || selectedOrderId;
        title = `${viewLabel} · ${order.title || cleanDisplayName(customer) || "valgt jobb"}`;
        detail = [cleanDisplayName(customer), order.type, order.status].filter(Boolean).join(" · ") || "Aktiv jobb";
      }
    } else if (currentView === "insulation") {
      const customer = findCustomer(currentInsulationCustomerId);
      if (customer) {
        if (crmAssistantCustomerPayload(customer)) payload.customerId = crmAssistantCustomerPayload(customer);
        title = `${viewLabel} · ${cleanDisplayName(customer)}`;
        detail = addressFor(customer) || "Valgt blåseisoleringskunde";
      }
    } else if (currentView === "planning" || currentView === "routeplanner") {
      detail = currentView === "routeplanner" ? "Aktiv servicerute" : `Uke fra ${formatDate(isoDate(weekStart))}`;
    } else if (currentView === "technician") {
      detail = `Dagsplan ${formatDate(el.technicianDate?.value || isoDate(new Date()))}`;
    }

    return { payload, title, detail };
  }

  function renderCrmAssistantContext() {
    if (!el.crmAssistantContext) return;
    const context = currentCrmAssistantContext();
    const focused = Boolean(context.payload.customerId || context.payload.leadId || context.payload.orderId || context.payload.intakeId);
    el.crmAssistantContext.innerHTML = `
      <span>Aktiv kontekst</span>
      <strong>${escapeHtml(context.title)}</strong>
      <small>${escapeHtml(context.detail)}</small>
      <em class="crm-assistant-context-state">${focused ? "Koblet" : "Side"}</em>
    `;
  }

  function crmAssistantThreadId(thread = crmAssistantThread) {
    return String(thread?.id || thread?.thread_id || thread?.threadId || "").trim();
  }

  function crmAssistantContextKey(context = currentCrmAssistantContext().payload) {
    const type = context.orderId ? "order" : context.intakeId ? "intake" : context.leadId ? "lead" : context.customerId ? "customer" : "none";
    const id = context.orderId || context.intakeId || context.leadId || context.customerId || "";
    return `${type}:${String(id)}`;
  }

  function crmAssistantThreadMatchesContext(thread, context = currentCrmAssistantContext().payload) {
    if (!thread) return false;
    const [expectedType, ...expectedIdParts] = crmAssistantContextKey(context).split(":");
    const expectedId = expectedIdParts.join(":") || null;
    const threadType = String(thread.context_type || thread.contextType || "none");
    const threadId = thread.context_id || thread.contextId || null;
    return threadType === expectedType && String(threadId || "") === String(expectedId || "");
  }

  function crmAssistantThreadTitle(thread = {}) {
    return String(thread.title || thread.subject || thread.name || "Ny samtale").trim() || "Ny samtale";
  }

  function crmAssistantMessageId(message = {}, index = 0) {
    return String(message.id || message.message_id || message.messageId || `message-${index}`).trim();
  }

  function crmAssistantMessageRole(message = {}) {
    const role = normalizeMatch(message.role || message.sender || message.author || message.type || "assistant");
    if (["user", "human", "bruker"].includes(role)) return "user";
    if (["assistant", "ai", "model", "assistent"].includes(role)) return "assistant";
    return "system";
  }

  function crmAssistantMessageBody(message = {}) {
    if (typeof message === "string") return message.trim();
    return String(message.content || message.message || message.body || message.text || "").trim();
  }

  function crmAssistantMemorySuggestion(message = {}) {
    const structured = message.structured_json || message.structuredJson || message.metadata || {};
    const value = message.memorySuggestion
      || message.memory_suggestion
      || structured.memorySuggestion
      || structured.memory_suggestion
      || "";
    const text = typeof value === "object"
      ? String(value.rule || value.content || value.text || "")
      : String(value || "");
    return text.trim().slice(0, 500);
  }

  function crmAssistantTimeLabel(value) {
    const date = new Date(value || "");
    if (Number.isNaN(date.getTime())) return "";
    return new Intl.DateTimeFormat("nb-NO", {
      day: "2-digit",
      month: "short",
      hour: "2-digit",
      minute: "2-digit",
    }).format(date);
  }

  function mergeCrmAssistantMessages(...groups) {
    const merged = [];
    const seen = new Set();
    for (const row of groups.flat().filter(Boolean)) {
      const message = typeof row === "string" ? { role: "assistant", content: row } : row;
      const id = String(message.id || message.message_id || "").trim();
      const signature = id || `${crmAssistantMessageRole(message)}:${crmAssistantMessageBody(message)}:${message.created_at || message.createdAt || ""}`;
      if (!crmAssistantMessageBody(message) || seen.has(signature)) continue;
      seen.add(signature);
      merged.push(message);
    }
    return merged.sort((a, b) => String(a.created_at || a.createdAt || "").localeCompare(String(b.created_at || b.createdAt || "")));
  }

  function renderCrmAssistantMemories() {
    if (!el.crmAssistantMemories) return;
    if (crmAssistantThread && !crmAssistantThreadMatchesContext(crmAssistantThread)) {
      el.crmAssistantMemories.classList.add("hidden");
      el.crmAssistantMemories.innerHTML = "";
      return;
    }
    const rows = (crmAssistantMemories || []).map((memory, index) => ({
      id: String(memory?.id || "").trim(),
      content: typeof memory === "string"
        ? memory.trim()
        : String(memory.content || memory.memory || memory.text || memory.title || "").trim(),
      scope: String(memory?.scope_type || memory?.scope || "global") === "context" ? "Denne kunden/saken" : "Global arbeidsregel",
      index,
    })).filter((memory) => memory.content);
    el.crmAssistantMemories.classList.toggle("hidden", !rows.length);
    el.crmAssistantMemories.innerHTML = rows.length ? `
      <details>
        <summary><strong>Godkjente regler og kundeminner (${rows.length.toLocaleString("nb-NO")})</strong></summary>
        <div class="crm-assistant-memory-list">
          ${rows.map((memory) => `
            <div>
              <span><small>${escapeHtml(memory.scope)}</small>${escapeHtml(memory.content)}</span>
              ${memory.id ? `<button class="secondary" data-disable-crm-assistant-memory="${escapeHtml(memory.id)}" type="button">Deaktiver</button>` : ""}
            </div>
          `).join("")}
        </div>
      </details>
    ` : "";
  }

  function renderCrmAssistantThreads() {
    if (!el.crmAssistantThreadList) return;
    const activeId = crmAssistantThreadId();
    const activeContext = currentCrmAssistantContext().payload;
    const rows = (crmAssistantThreads || []).filter((thread) => (
      !thread.archived_at
      && thread.status !== "archived"
      && crmAssistantThreadMatchesContext(thread, activeContext)
    ));
    if (!rows.length) {
      el.crmAssistantThreadList.innerHTML = `<div class="crm-assistant-thread-empty">${crmAssistantLoading ? "Laster samtaler…" : "Ingen tidligere samtaler."}</div>`;
      return;
    }
    el.crmAssistantThreadList.innerHTML = rows.map((thread) => {
      const id = crmAssistantThreadId(thread);
      const updated = crmAssistantTimeLabel(thread.updated_at || thread.updatedAt || thread.created_at || thread.createdAt);
      return `
        <div class="crm-assistant-thread-row">
          <button class="${id === activeId ? "active" : ""}" data-crm-assistant-thread="${escapeHtml(id)}" type="button">
            <strong>${escapeHtml(crmAssistantThreadTitle(thread))}</strong>
            <small>${escapeHtml([thread.preview || thread.last_message || "", updated].filter(Boolean).join(" · ") || "Tom samtale")}</small>
          </button>
          <button class="crm-assistant-archive-thread" data-archive-crm-assistant-thread="${escapeHtml(id)}" type="button" aria-label="Arkiver ${escapeHtml(crmAssistantThreadTitle(thread))}" title="Arkiver samtale">×</button>
        </div>
      `;
    }).join("");
  }

  function crmAssistantEmptyHtml() {
    return `
      <div class="crm-assistant-empty">
        <span class="crm-assistant-empty-icon" aria-hidden="true">✦</span>
        <h3>Hva kan jeg hjelpe med?</h3>
        <p>Spør om kunden eller jobben du står på, finn informasjon eller be om et utkast. Ingenting sendes eller endres uten kontroll.</p>
        <div class="crm-assistant-starters">
          <button data-crm-assistant-starter="Oppsummer det viktigste om det jeg står på nå." type="button">Oppsummer aktiv kunde eller sak</button>
          <button data-crm-assistant-starter="Hva bør være neste steg i denne saken?" type="button">Foreslå neste steg</button>
          <button data-crm-assistant-starter="Lag et e-postutkast basert på konteksten, men ikke send noe." type="button">Lag et e-postutkast</button>
          <button data-crm-assistant-starter="Finn servicekunder på Vegglifjell og lag separate SMS-utkast til kontroll." type="button">Finn servicekunder i et område</button>
          <button data-crm-assistant-starter="Lag et trygt bookingforslag for kunden eller saken jeg står på. Ikke book noe." type="button">Lag bookingforslag</button>
          <button data-crm-assistant-starter="Lag et oppfølgingsutkast for tilbudet på kunden eller saken jeg står på." type="button">Følg opp tilbud</button>
        </div>
      </div>
    `;
  }

  function crmAssistantMessageHtml(message, index) {
    const id = crmAssistantMessageId(message, index);
    const role = crmAssistantMessageRole(message);
    const body = crmAssistantMessageBody(message);
    const time = crmAssistantTimeLabel(message.created_at || message.createdAt);
    const roleLabel = role === "user" ? "Du" : role === "assistant" ? "CRM-assistent" : "System";
    const persistedFeedback = message.feedback === "up" ? "helpful" : message.feedback === "down" ? "not_helpful" : "";
    const feedback = crmAssistantFeedback.get(id) || persistedFeedback;
    const memorySuggestion = crmAssistantMemorySuggestion(message);
    const actions = role === "assistant" && !id.startsWith("pending-") ? `
      <div class="crm-assistant-message-actions">
        <button data-crm-assistant-feedback="helpful" data-crm-assistant-message-id="${escapeHtml(id)}" type="button" aria-label="Marker svaret som nyttig" aria-pressed="${feedback === "helpful"}">Nyttig</button>
        <button data-crm-assistant-feedback="not_helpful" data-crm-assistant-message-id="${escapeHtml(id)}" type="button" aria-label="Marker svaret som ikke nyttig" aria-pressed="${feedback === "not_helpful"}">Ikke nyttig</button>
        ${memorySuggestion ? `<button class="${crmAssistantSavedMemories.has(id) ? "saved" : ""}" data-save-crm-assistant-memory="${escapeHtml(id)}" type="button">${crmAssistantSavedMemories.has(id) ? "Regel lagret" : "Lagre foreslått regel"}</button>` : ""}
      </div>
    ` : "";
    return `
      <article class="crm-assistant-message ${escapeHtml(role)}" data-crm-assistant-message="${escapeHtml(id)}">
        <div class="crm-assistant-message-meta"><span>${escapeHtml(roleLabel)}</span>${time ? `<time>${escapeHtml(time)}</time>` : ""}</div>
        <div class="crm-assistant-message-body">${escapeHtml(body)}</div>
        ${memorySuggestion ? `<div class="crm-assistant-memory-proposal"><strong>Foreslått arbeidsregel</strong><span>${escapeHtml(memorySuggestion)}</span></div>` : ""}
        ${actions}
      </article>
    `;
  }

  function renderCrmAssistantMessages(options = {}) {
    if (!el.crmAssistantMessages) return;
    const contextSafe = !crmAssistantThread || crmAssistantThreadMatchesContext(crmAssistantThread);
    const rows = contextSafe ? [...(crmAssistantMessages || [])] : [];
    if (contextSafe && crmAssistantPendingUserMessage) rows.push(crmAssistantPendingUserMessage);
    let html = rows.length ? rows.map(crmAssistantMessageHtml).join("") : crmAssistantEmptyHtml();
    if (crmAssistantLoading) {
      html += `
        <article class="crm-assistant-message assistant" aria-label="CRM-assistenten arbeider">
          <div class="crm-assistant-message-meta"><span>CRM-assistent</span></div>
          <div class="crm-assistant-message-body"><span class="crm-assistant-loading" aria-hidden="true"><i></i><i></i><i></i></span><span class="sr-only">${escapeHtml(crmAssistantLoadingLabel || "Arbeider")}</span></div>
        </article>
      `;
    }
    el.crmAssistantMessages.innerHTML = html;
    if (options.keepScroll) return;
    window.requestAnimationFrame(() => {
      if (crmAssistantOpen && el.crmAssistantMessages) el.crmAssistantMessages.scrollTop = el.crmAssistantMessages.scrollHeight;
    });
  }

  function crmAssistantSuggestionType(suggestion = {}) {
    const raw = normalizeMatch(suggestion.action_type || suggestion.actionType || suggestion.type || suggestion.kind || "").replaceAll(" ", "_");
    const aliases = {
      email: "email_reply",
      email_draft: "email_reply",
      draft_email: "email_reply",
      send_email: "email_reply",
      sms: "sms_reply",
      sms_draft: "sms_reply",
      draft_sms: "sms_reply",
      offer: "offer_draft",
      quote: "offer_draft",
      quote_draft: "offer_draft",
      booking: "booking_proposal",
      schedule: "booking_proposal",
      reminder: "reminder_proposal",
      reminder_draft: "reminder_proposal",
      invoice: "invoice_draft",
      customer_data: "customer_enrichment",
      customer_create: "customer_create_proposal",
      create_customer: "customer_create_proposal",
    };
    return aliases[raw] || raw;
  }

  function crmAssistantSuggestionLabel(suggestion = {}) {
    return ({
      email_reply: "E-postutkast",
      sms_reply: "SMS-utkast",
      offer_draft: "Tilbudsutkast",
      booking_proposal: "Planforslag",
      reminder_proposal: "Påminnelse",
      invoice_draft: "Fakturagrunnlag",
      customer_enrichment: "Kundedata",
      customer_create_proposal: "Nytt kundekort",
    })[crmAssistantSuggestionType(suggestion)] || "Utkast";
  }

  function crmAssistantSuggestionKey(suggestion = {}) {
    const booking = suggestion.booking || suggestion.payload_json?.booking || suggestion.payload?.booking || {};
    const customer = suggestion.customer || suggestion.payload_json?.customer || suggestion.payload?.customer || {};
    const reminderValue = crmAssistantSuggestionType(suggestion) === "reminder_proposal"
      ? (suggestion.reminder || suggestion.payload_json?.reminder || suggestion.payload?.reminder)
      : booking.reminder;
    const reminder = reminderValue && typeof reminderValue === "object" && !Array.isArray(reminderValue)
      ? reminderValue
      : {};
    const source = [
      crmAssistantSuggestionType(suggestion),
      suggestion.customerId || suggestion.customer_id,
      suggestion.customerName || suggestion.customer_name,
      suggestion.recipient,
      suggestion.title,
      suggestion.subject,
      suggestion.body || suggestion.content || suggestion.summary,
      Array.isArray(suggestion.attachments) ? suggestion.attachments.join(",") : "",
      customer.name,
      customer.phone,
      customer.email,
      customer.address,
      customer.postalCode || customer.postal_code,
      customer.city,
      booking.jobType || booking.job_type,
      booking.title,
      booking.note,
      booking.scheduledDate || booking.scheduled_date,
      booking.scheduledTime || booking.scheduled_time,
      booking.durationMinutes || booking.duration_minutes,
      booking.resource,
      booking.scheduleRequested === true || booking.schedule_requested === true ? "scheduled" : "unscheduled",
      booking.operation,
      booking.orderId || booking.order_id,
      booking.bookingId || booking.booking_id,
      reminder.text || reminder.body,
      reminder.dueDate || reminder.due_date,
      reminder.dueTime || reminder.due_time,
    ].map((value) => String(value || "").trim()).join("|");
    let hash = 2166136261;
    for (let cursor = 0; cursor < source.length; cursor += 1) {
      hash ^= source.charCodeAt(cursor);
      hash = Math.imul(hash, 16777619);
    }
    return `suggestion-${(hash >>> 0).toString(36)}`;
  }

  function crmAssistantWorkflowHtml(workflow = {}) {
    if (!workflow || workflow.type !== "service_outreach") return "";
    if (workflow.needsChannelClarification && !workflow.needsClarification) {
      return `
        <article class="crm-assistant-workflow-card attention">
          <span>Kanal må avklares</span>
          <strong>Velg SMS eller e-post</strong>
          <p>Én kontrollert utsendingsrunde bruker én kanal. Ingen kunder er kontaktet.</p>
          <div class="mini-action-row">
            <button data-crm-assistant-channel-prompt="sms" data-crm-assistant-channel-area="${escapeHtml(workflow.areaLabel || "")}" type="button">Lag SMS-utkast</button>
            <button data-crm-assistant-channel-prompt="email" data-crm-assistant-channel-area="${escapeHtml(workflow.areaLabel || "")}" type="button">Lag e-postutkast</button>
          </div>
        </article>
      `;
    }
    if (workflow.needsClarification) {
      const areaOptions = Array.isArray(workflow.areaOptions || workflow.area_options)
        ? (workflow.areaOptions || workflow.area_options).filter((option) => option?.areaLabel || option?.area_label)
        : [
          { areaKey: "vegglifjell_nord", areaLabel: "Vegglifjell nord" },
          { areaKey: "vegglifjell_sor", areaLabel: "Vegglifjell sør" },
        ];
      const vegglifjellOnly = areaOptions.length === 2
        && areaOptions.every((option) => String(option.areaKey || option.area_key || "").startsWith("vegglifjell_"));
      return `
        <article class="crm-assistant-workflow-card attention">
          <span>Område må avklares</span>
          <strong>${vegglifjellOnly ? "Vegglifjell nord og sør planlegges separat" : "Velg ett serviceområde"}</strong>
          <p>Velg ett område før kundedata hentes. Ingen kunder er søkt opp ennå.</p>
          <div class="mini-action-row">
            ${areaOptions.map((option) => {
              const label = option.areaLabel || option.area_label || "";
              return `<button data-crm-assistant-area-prompt="${escapeHtml(label)}" type="button">Bare ${escapeHtml(label)}</button>`;
            }).join("")}
          </div>
        </article>
      `;
    }
    const matched = Number(workflow.matched || 0);
    const eligible = Number(workflow.eligible || 0);
    const excluded = Number(workflow.excluded || 0);
    const remaining = Number(workflow.remaining || 0);
    const draftMessages = workflow.draftMessages !== false;
    return `
      <article class="crm-assistant-workflow-card">
        <span>Serviceutvalg</span>
        <strong>${escapeHtml(workflow.areaLabel || "Valgt område")}</strong>
        <p>${matched.toLocaleString("nb-NO")} aktuelle · ${eligible.toLocaleString("nb-NO")} kvalifiserte · ${excluded.toLocaleString("nb-NO")} holdt utenfor${remaining ? ` · ${remaining.toLocaleString("nb-NO")} i neste pulje` : ""}.</p>
        <small>${draftMessages ? "Hvert meldingsutkast må godkjennes enkeltvis." : "Ingen meldingsutkast er laget."} ${escapeHtml(workflow.areaLabel || "")} er det eneste området i dette utvalget. Ingenting er sendt eller booket.</small>
        <div class="mini-action-row">
          <button data-open-crm-assistant-service-route="${escapeHtml(workflow.areaLabel || "")}" type="button">Åpne i servicerute</button>
        </div>
      </article>
    `;
  }

  function renderCrmAssistantSuggestions() {
    if (!el.crmAssistantSuggestions) return;
    if (crmAssistantThread && !crmAssistantThreadMatchesContext(crmAssistantThread)) {
      el.crmAssistantSuggestions.classList.add("hidden");
      el.crmAssistantSuggestions.innerHTML = "";
      return;
    }
    const rows = crmAssistantSuggestions || [];
    const workflowHtml = crmAssistantWorkflowHtml(crmAssistantWorkflow || {});
    el.crmAssistantSuggestions.classList.toggle("hidden", !rows.length && !workflowHtml);
    if (!rows.length && !workflowHtml) {
      el.crmAssistantSuggestions.innerHTML = "";
      return;
    }
    const savedCount = rows.filter((row) => {
      if (row._saveState !== "saved") return false;
      const action = row._savedActionId ? assistantActionById(row._savedActionId) : null;
      return Boolean(action && pendingAssistantAction(action));
    }).length;
    const completedResultCount = rows.filter((row) => {
      const action = row._savedActionId ? assistantActionById(row._savedActionId) : null;
      return Boolean(action && assistantCompletedResultControl(action).canOpen);
    }).length;
    el.crmAssistantSuggestions.innerHTML = `
      <header>
        <div><strong>Forslag til kontroll</strong><span>${completedResultCount ? `${completedResultCount.toLocaleString("nb-NO")} gjennomført resultat kan åpnes igjen.` : "Dette er utkast. Ingen handling er utført."}</span></div>
        ${savedCount ? `<button data-open-crm-assistant-queue type="button">Åpne kontrollkø (${savedCount})</button>` : ""}
      </header>
      ${workflowHtml}
      ${rows.map((suggestion) => {
        const savedAction = suggestion._savedActionId ? assistantActionById(suggestion._savedActionId) : null;
        const savedActionId = String(savedAction?.id || "").trim();
        const canOpenSavedAction = suggestion._saveState === "saved"
          && Boolean(savedActionId)
          && pendingAssistantAction(savedAction);
        const completedResultControl = assistantCompletedResultControl(savedAction);
        const savedBookingControl = savedAction?.action_type === "booking_proposal"
          ? assistantBookingControl(savedAction)
          : null;
        const savedReminderControl = savedAction?.action_type === "reminder_proposal"
          ? assistantReminderControl(savedAction)
          : null;
        const savedCustomerControl = savedAction?.action_type === "customer_create_proposal"
          ? assistantCustomerControl(savedAction)
          : null;
        const suggestionBlockers = savedAction
          ? assistantActionDisplayBlockers(savedAction)
          : Array.isArray(suggestion.blockers_json || suggestion.blockers)
            ? (suggestion.blockers_json || suggestion.blockers).filter(Boolean)
            : [];
        const booking = savedAction?.payload_json?.booking || suggestion.booking || suggestion.payload_json?.booking || null;
        const bookingBody = crmAssistantSuggestionType(suggestion) === "booking_proposal" && booking
          ? [
            `Planforslag: ${String(booking.jobType || "jobb")}`,
            booking.scheduledDate ? formatDate(booking.scheduledDate) : "dato må avklares",
            booking.scheduledTime ? `kl. ${booking.scheduledTime}` : "klokkeslett må avklares",
            booking.reminder?.dueDate
              ? `påminnelse ${formatDate(booking.reminder.dueDate)}${booking.reminder.dueTime ? ` kl. ${booking.reminder.dueTime}` : ""}`
              : booking.reminder ? "påminnelsesdato må avklares" : "",
          ].filter(Boolean).join(" · ")
          : "";
        const reminder = savedAction?.payload_json?.reminder || suggestion.reminder || suggestion.payload_json?.reminder || null;
        const reminderBody = crmAssistantSuggestionType(suggestion) === "reminder_proposal" && reminder
          ? [
            reminder.text || "Påminnelsestekst mangler",
            reminder.dueDate ? formatDate(reminder.dueDate) : "dato må avklares",
            reminder.dueTime ? `kl. ${reminder.dueTime}` : "",
          ].filter(Boolean).join(" · ")
          : "";
        const offerAttachmentIds = savedAction
          ? assistantEmailAttachments(savedAction).map((attachment) => attachment.id)
          : crmAssistantSuggestionType(suggestion) === "offer_draft" && Array.isArray(suggestion.attachments)
            ? suggestion.attachments.filter((id) => id === "price_list")
            : [];
        const hasSuggestionBlockers = suggestionBlockers.length > 0;
        const originalBody = savedAction?.body || suggestion.body || suggestion.content || suggestion.summary || suggestion.subject || "";
        const body = String(
          crmAssistantSuggestionType(suggestion) === "booking_proposal" && hasSuggestionBlockers && bookingBody
            ? bookingBody
            : originalBody || bookingBody || reminderBody || "Forslag uten tekst",
        ).trim();
        const state = savedAction?.status === "completed"
          ? crmAssistantSuggestionType(suggestion) === "booking_proposal"
            ? savedAction?.payload_json?.booking?.operation === "reschedule"
              ? "Bookingen er flyttet og resultatet ligger under Nylig gjennomført"
              : savedAction?.payload_json?.booking?.operation === "cancel"
                ? "Bookingen er avbestilt, og jobben er beholdt uten dato"
                : "Jobbresultatet er opprettet og ligger under Nylig gjennomført"
            : crmAssistantSuggestionType(suggestion) === "reminder_proposal"
              ? "Påminnelsen er opprettet og ligger på forsiden"
            : crmAssistantSuggestionType(suggestion) === "customer_create_proposal"
              ? "Kundekortet er opprettet og koblet til kilden"
            : "Registrert sendt manuelt"
          : savedAction?.status === "approved"
            ? "Godkjent · ikke sendt"
            : savedAction?.status === "rejected"
              ? "Tidligere avvist · ingen melding er sendt"
              : savedAction?.status === "failed"
                ? "Kunne ikke behandles · se kontrollkøen"
            : suggestion._saveState === "saved"
              ? savedAction
                ? hasSuggestionBlockers ? "Lagt i kontrollkø · må avklares" : "Lagt i kontrollkø · krever godkjenning"
                : "Forslaget finnes ikke lenger i kontrollkøen"
          : suggestion._saveState === "saving"
            ? "Lagrer i kontrollkø…"
            : suggestion._saveState === "unsupported"
              ? "Vist som utkast · handlingstypen støttes ikke i kontrollkøen"
              : suggestion._saveState === "error"
                ? `Kunne ikke lagres: ${suggestion._saveError || "ukjent feil"}`
                : suggestion._saveState === "historical"
                  ? "Historisk utkast · åpning oppretter ikke en ny kontrolloppføring"
                : "Utkast · krever kontroll";
        return `
          <article class="crm-assistant-suggestion-card ${suggestion._saveState === "error" ? "error" : ""}">
            <span>${escapeHtml(crmAssistantSuggestionLabel(suggestion))}</span>
            <strong>${escapeHtml(suggestion.title || suggestion.subject || crmAssistantSuggestionLabel(suggestion))}</strong>
            <p>${escapeHtml(body.slice(0, 180))}${body.length > 180 ? "…" : ""}</p>
            ${offerAttachmentIds.includes("price_list") ? `<small>Vedlegg: Prisoversikt Numedal Varmepumpeservice (PDF)</small>` : ""}
            ${body.length > 180 ? `<details class="crm-assistant-suggestion-details"><summary>Se hele utkastet</summary><p>${escapeHtml(body)}</p></details>` : ""}
            ${suggestionBlockers.length ? assistantBlockersHtml(suggestionBlockers) : canOpenSavedAction ? assistantBlockersHtml([]) : ""}
            <small>${escapeHtml(state)}</small>
            ${canOpenSavedAction || completedResultControl.canOpen ? `<div class="mini-action-row">
              ${savedCustomerControl?.canExecute ? `<button data-run-crm-assistant-customer="${escapeHtml(savedActionId)}" type="button">Godkjenn og opprett kundekort</button>` : ""}
              ${savedBookingControl?.canExecute ? `<button data-run-crm-assistant-booking="${escapeHtml(savedActionId)}" type="button">${escapeHtml(assistantBookingExecuteLabel(savedBookingControl))}</button>` : ""}
              ${savedReminderControl?.canExecute ? `<button data-run-crm-assistant-reminder="${escapeHtml(savedActionId)}" type="button">Godkjenn og opprett påminnelse</button>` : ""}
              ${completedResultControl.canOpen ? `<button data-open-crm-assistant-completed-result="${escapeHtml(savedActionId)}" type="button">${escapeHtml(completedResultControl.label)}</button>` : ""}
              ${canOpenSavedAction ? `<button class="secondary" data-open-crm-assistant-queue="${escapeHtml(savedActionId)}" type="button">Åpne kontroll</button>` : ""}
            </div>` : ""}
          </article>
        `;
      }).join("")}
    `;
  }

  function setCrmAssistantError(message = "", retry = null) {
    crmAssistantLastRetry = typeof retry === "function" ? retry : null;
    el.crmAssistantError?.classList.toggle("hidden", !message);
    if (el.crmAssistantErrorText) el.crmAssistantErrorText.textContent = message || "";
    el.crmAssistantRetryButton?.classList.toggle("hidden", !crmAssistantLastRetry);
  }

  function setCrmAssistantBusy(busy, label = "") {
    crmAssistantLoading = Boolean(busy);
    crmAssistantLoadingLabel = label || "";
    if (el.crmAssistantInput) el.crmAssistantInput.disabled = crmAssistantLoading;
    if (el.crmAssistantSendButton) el.crmAssistantSendButton.disabled = crmAssistantLoading;
    if (el.crmAssistantNewThreadButton) el.crmAssistantNewThreadButton.disabled = crmAssistantLoading;
    if (el.crmAssistantDrawerNewThreadButton) el.crmAssistantDrawerNewThreadButton.disabled = crmAssistantLoading;
    if (el.crmAssistantStatus) {
      el.crmAssistantStatus.textContent = crmAssistantLoading
        ? (crmAssistantLoadingLabel || "Arbeider…")
        : "Enter sender · Shift+Enter gir ny linje";
    }
    renderCrmAssistantMessages();
    renderCrmAssistantThreads();
  }

  function crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch) {
    return sensitiveWorkflowIsCurrent(stateGeneration)
      && crmAssistantContextEpoch === contextEpoch
      && crmAssistantLoadedContextKey === contextKey
      && crmAssistantContextKey() === contextKey;
  }

  function resetCrmAssistantConversationForContext(contextKey = crmAssistantContextKey()) {
    crmAssistantContextEpoch += 1;
    crmAssistantLoadedContextKey = contextKey;
    crmAssistantInitialized = false;
    crmAssistantThread = null;
    crmAssistantMessages = [];
    crmAssistantSuggestions = [];
    crmAssistantWorkflow = null;
    crmAssistantMemories = [];
    crmAssistantPendingUserMessage = null;
    crmAssistantReplacementAction = null;
    crmAssistantThreadDrawerOpen = false;
    setCrmAssistantError();
    setCrmAssistantBusy(false);
  }

  function ensureCrmAssistantContextState() {
    const contextKey = crmAssistantContextKey();
    const threadMatches = !crmAssistantThread || crmAssistantThreadMatchesContext(crmAssistantThread);
    if (crmAssistantLoadedContextKey === contextKey && threadMatches) return false;
    resetCrmAssistantConversationForContext(contextKey);
    return true;
  }

  function syncCrmAssistantContextIfOpen() {
    if (!crmAssistantOpen) return;
    const changed = ensureCrmAssistantContextState();
    if (!changed) {
      renderCrmAssistantContext();
      return;
    }
    renderCrmAssistantPanel();
    void loadCrmAssistantThreads();
  }

  function scheduleCrmAssistantContextSync() {
    if (!crmAssistantOpen) return;
    setTimeout(() => {
      if (crmAssistantOpen) syncCrmAssistantContextIfOpen();
    }, 0);
  }

  function upsertCrmAssistantThread(thread) {
    const id = crmAssistantThreadId(thread);
    if (!id) return;
    crmAssistantThreads = [thread, ...crmAssistantThreads.filter((row) => crmAssistantThreadId(row) !== id)];
  }

  async function storeCrmAssistantSuggestions(
    suggestions = [],
    response = {},
    stateGeneration = sensitiveWorkflowGeneration,
    replacementAction = null,
    requestContext = {},
    persistence = {},
  ) {
    const context = requestContext.payload || currentCrmAssistantContext().payload;
    const contextKey = requestContext.key || crmAssistantContextKey(context);
    const contextEpoch = requestContext.epoch ?? crmAssistantContextEpoch;
    if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
    const serverActions = Array.isArray(response.assistantActions)
      ? response.assistantActions.filter((action) => action?.id)
      : [];
    if (serverActions.length) {
      assistantActions = [
        ...serverActions,
        ...assistantActions.filter((old) => !serverActions.some((action) => action.id === old.id)),
      ];
    }
    const serverActionsById = new Map(serverActions.map((action) => [String(action.id), action]));
    const persistMissingSuggestions = persistence.persistMissing === true;
    const seenSuggestionKeys = new Set();
    crmAssistantSuggestions = (Array.isArray(suggestions) ? suggestions : []).map((suggestion) => {
      const normalizedSuggestion = suggestion && typeof suggestion === "object"
        ? suggestion
        : { body: String(suggestion || "") };
      return {
        ...normalizedSuggestion,
        _key: crmAssistantSuggestionKey(normalizedSuggestion),
        _saveState: serverActionsById.has(String(normalizedSuggestion.actionId || normalizedSuggestion.action_id || ""))
          ? "saved"
          : persistMissingSuggestions
            ? "saving"
            : "historical",
        _savedActionId: serverActionsById.has(String(normalizedSuggestion.actionId || normalizedSuggestion.action_id || ""))
          ? String(normalizedSuggestion.actionId || normalizedSuggestion.action_id)
          : "",
      };
    }).filter((suggestion) => {
      if (seenSuggestionKeys.has(suggestion._key)) return false;
      seenSuggestionKeys.add(suggestion._key);
      return true;
    });
    renderCrmAssistantSuggestions();
    if (!crmAssistantSuggestions.length || !persistMissingSuggestions) return;
    const allowedTypes = new Set(["email_reply", "sms_reply", "offer_draft", "booking_proposal", "reminder_proposal", "invoice_draft", "customer_enrichment", "customer_create_proposal"]);
    const threadId = crmAssistantThreadId();
    const assistantMessageId = crmAssistantMessageId(response.assistantMessage || response.message || {}, 0);
    const savedRows = [];

    for (const suggestion of crmAssistantSuggestions) {
      if (suggestion._saveState === "saved" && suggestion._savedActionId) {
        const serverAction = serverActionsById.get(String(suggestion._savedActionId));
        if (serverAction) savedRows.push(serverAction);
        continue;
      }
      const actionType = crmAssistantSuggestionType(suggestion);
      if (!allowedTypes.has(actionType) || !store.saveAssistantAction) {
        suggestion._saveState = "unsupported";
        continue;
      }
      try {
        const channel = ["email", "sms", "internal"].includes(suggestion.channel)
          ? suggestion.channel
          : actionType === "email_reply" || actionType === "offer_draft"
            ? "email"
            : actionType === "sms_reply"
              ? "sms"
              : "internal";
        const rawBookingProposal = suggestion.booking || suggestion.payload_json?.booking || suggestion.payload?.booking || null;
        const bookingProposal = actionType === "booking_proposal"
          && rawBookingProposal
          && typeof rawBookingProposal === "object"
          && !Array.isArray(rawBookingProposal)
          && assistantCoordinator.normalizeBookingProposal
          ? assistantCoordinator.normalizeBookingProposal(rawBookingProposal)
          : null;
        const rawReminderProposal = suggestion.reminder || suggestion.payload_json?.reminder || suggestion.payload?.reminder || null;
        const reminderProposal = actionType === "reminder_proposal"
          && rawReminderProposal
          && typeof rawReminderProposal === "object"
          && !Array.isArray(rawReminderProposal)
          && assistantCoordinator.normalizeReminderProposal
          ? assistantCoordinator.normalizeReminderProposal(rawReminderProposal)
          : null;
        const offerAttachmentIds = actionType === "offer_draft" && Array.isArray(suggestion.attachments)
          ? [...new Set(suggestion.attachments.map((item) => String(item || "").trim()).filter((item) => item === "price_list"))].slice(0, 1)
          : [];
        const campaignKey = String(suggestion.campaignKey || suggestion.campaign_key || "").trim();
        const suggestionCustomerId = suggestion.customerId || suggestion.customer_id || null;
        const customerContextMismatch = suggestion.customerContextMismatch === true;
        const inheritActiveContext = !campaignKey && !customerContextMismatch;
        const replacesAssistantActionId = actionType === "booking_proposal"
          && replacementAction?.actionId
          && String(replacementAction.customerId || "") === String(suggestionCustomerId || (inheritActiveContext ? context.customerId : null) || "")
          ? replacementAction.actionId
          : null;
        const idempotencyKey = campaignKey && suggestionCustomerId
          ? `crm-assistant:${campaignKey}:${suggestionCustomerId}`
          : `crm-assistant:${threadId || "new"}:${assistantMessageId || "reply"}:${suggestion._key}`;
        const saved = await store.saveAssistantAction({
          idempotencyKey: idempotencyKey.slice(0, 240),
          actionType,
          status: "needs_review",
          channel,
          title: suggestion.title || suggestion.subject || `${crmAssistantSuggestionLabel(suggestion)} fra CRM-assistent`,
          recipient: suggestion.recipient || "",
          subject: suggestion.subject || "",
          body: suggestion.body || suggestion.content || suggestion.summary || "",
          payload: {
            ...(suggestion.payload_json || suggestion.payload || {}),
            booking: bookingProposal,
            reminder: reminderProposal,
            ...(actionType === "offer_draft" ? {
              attachments: offerAttachmentIds.map((id) => ({ id })),
              includePriceList: offerAttachmentIds.includes("price_list"),
            } : {}),
            customer: actionType === "customer_create_proposal"
              ? (suggestion.customer || suggestion.payload_json?.customer || suggestion.payload?.customer || null)
              : null,
            crmAssistantThreadId: threadId || null,
            crmAssistantSuggestionId: suggestion.id || suggestion._key,
            campaignKey: campaignKey || null,
            areaKey: suggestion.areaKey || suggestion.area_key || null,
            areaLabel: suggestion.areaLabel || suggestion.area_label || null,
            serviceDue: suggestion.serviceDue || suggestion.service_due || null,
            replacesAssistantActionId,
            doNotExecuteAutomatically: true,
          },
          evidence: {
            ...(suggestion.evidence_json || suggestion.evidence || {}),
            source: "crm_assistant",
            threadId: threadId || null,
            messageId: assistantMessageId || null,
          },
          blockers: Array.isArray(suggestion.blockers_json || suggestion.blockers) ? (suggestion.blockers_json || suggestion.blockers) : [],
          confidence: suggestion.confidence,
          sourceKind: campaignKey ? "crm_assistant_service_outreach" : "crm_assistant",
          sourceRef: campaignKey || `crm-assistant:${threadId || "new"}:${assistantMessageId || suggestion._key}`,
          sourceIntakeId: context.intakeId || null,
          customerId: suggestionCustomerId || (inheritActiveContext ? context.customerId : null) || null,
          leadId: suggestion.leadId || (inheritActiveContext ? context.leadId : null) || null,
          jobId: suggestion.jobId || null,
          orderId: suggestion.orderId || (inheritActiveContext ? context.orderId : null) || null,
          approval_required: true,
        });
        if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
        suggestion._saveState = "saved";
        suggestion._savedActionId = saved?.id || "";
        if (saved) savedRows.push(saved);
      } catch (error) {
        if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
        suggestion._saveState = "error";
        suggestion._saveError = error.message || "Ukjent feil";
      }
      renderCrmAssistantSuggestions();
    }

    if (savedRows.length) {
      assistantActions = [
        ...savedRows,
        ...assistantActions.filter((old) => !savedRows.some((row) => row.id && row.id === old.id)),
      ];
      const replacementRow = replacementAction?.actionId
        ? savedRows.find((row) => (
          row.action_type === "booking_proposal"
          && row.payload_json?.booking
          && String(row.linked_customer_id || "") === String(replacementAction.customerId || "")
        ))
        : null;
      const oldAction = replacementRow ? assistantActionById(replacementAction.actionId) : null;
      if (oldAction && ["needs_review", "approved", "failed"].includes(oldAction.status || "needs_review")) {
        const serverSuperseded = String(replacementRow.payload_json?.replacesAssistantActionId || "") === String(oldAction.id || "");
        if (serverSuperseded) {
          assistantActions = assistantActions.map((row) => row.id === oldAction.id
            ? {
              ...row,
              status: "expired",
              error_message: "Erstattet av et nyere strukturert forslag.",
              payload_json: {
                ...(row.payload_json || {}),
                replacedByAssistantActionId: replacementRow.id,
              },
            }
            : row);
        } else {
          try {
            await patchAssistantAction(oldAction, {
              status: "expired",
              expectedStatus: oldAction.status || "needs_review",
              error_message: "Erstattet av et nyere strukturert forslag.",
            });
            if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
          } catch (error) {
            if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
            setCrmAssistantError(`Det nye forslaget er lagret, men det gamle kunne ikke ryddes automatisk: ${error.message || "ukjent feil"}`);
          }
        }
      }
      renderAssistantActionQueue();
      if (currentView === "dashboard") renderDashboard();
    }
    renderCrmAssistantSuggestions();
  }

  async function applyCrmAssistantResponse(response = {}, options = {}) {
    const stateGeneration = options.stateGeneration ?? sensitiveWorkflowGeneration;
    const contextPayload = options.contextPayload || currentCrmAssistantContext().payload;
    const contextKey = options.contextKey || crmAssistantContextKey(contextPayload);
    const contextEpoch = options.contextEpoch ?? crmAssistantContextEpoch;
    if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
    if (response.thread && !crmAssistantThreadMatchesContext(response.thread, contextPayload)) {
      throw new Error("Samtalen tilhører en annen CRM-kontekst og ble ikke åpnet.");
    }
    if (Array.isArray(response.threads)) crmAssistantThreads = response.threads;
    if (response.thread) {
      crmAssistantThread = response.thread;
      upsertCrmAssistantThread(response.thread);
    }
    if (Array.isArray(response.messages)) {
      crmAssistantMessages = mergeCrmAssistantMessages(response.messages);
    } else {
      const incoming = [];
      if (response.message && typeof response.message === "object") incoming.push(response.message);
      if (typeof response.message === "string" && !response.assistantMessage) incoming.push({ role: "assistant", content: response.message });
      if (response.assistantMessage) incoming.push(response.assistantMessage);
      if (incoming.length) crmAssistantMessages = mergeCrmAssistantMessages(crmAssistantMessages, incoming);
    }
    if (Array.isArray(response.memories)) crmAssistantMemories = response.memories;
    if (response.workflow && typeof response.workflow === "object") {
      crmAssistantWorkflow = response.workflow;
    } else {
      const workflowMessage = [response.assistantMessage, ...(Array.isArray(response.messages) ? response.messages.slice().reverse() : [])]
        .find((message) => message?.role === "assistant" && message?.structured_json?.workflow);
      if (workflowMessage?.structured_json?.workflow) {
        crmAssistantWorkflow = workflowMessage.structured_json.workflow;
      } else if (options.clearSuggestions) {
        crmAssistantWorkflow = null;
      }
    }
    renderCrmAssistantContext();
    renderCrmAssistantMemories();
    renderCrmAssistantThreads();
    renderCrmAssistantMessages();
    if (Array.isArray(response.suggestions)) {
      await storeCrmAssistantSuggestions(
        response.suggestions,
        response,
        stateGeneration,
        options.replacementAction || null,
        { payload: contextPayload, key: contextKey, epoch: contextEpoch },
        { persistMissing: options.persistSuggestions === true },
      );
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
    } else if (options.clearSuggestions) {
      crmAssistantSuggestions = [];
      renderCrmAssistantSuggestions();
    }
  }

  function renderCrmAssistantPanel() {
    ensureCrmAssistantContextState();
    renderCrmAssistantContext();
    renderCrmAssistantMemories();
    renderCrmAssistantThreads();
    renderCrmAssistantMessages({ keepScroll: true });
    renderCrmAssistantSuggestions();
    renderCrmAssistantQueueShortcut();
    el.crmAssistantThreadDrawer?.classList.toggle("hidden", !crmAssistantThreadDrawerOpen);
    el.crmAssistantThreadsButton?.setAttribute("aria-expanded", crmAssistantThreadDrawerOpen ? "true" : "false");
  }

  function closeCrmAssistantPanel(options = {}) {
    crmAssistantOpen = false;
    crmAssistantThreadDrawerOpen = false;
    el.crmAssistantPanel?.classList.remove("open");
    el.crmAssistantPanel?.setAttribute("aria-hidden", "true");
    if (el.crmAssistantPanel) el.crmAssistantPanel.inert = true;
    el.crmAssistantButton?.setAttribute("aria-expanded", "false");
    el.mobileCrmAssistantButton?.setAttribute("aria-expanded", "false");
    document.body.classList.remove("crm-assistant-open");
    el.crmAssistantThreadDrawer?.classList.add("hidden");
    if (options.restoreFocus !== false && crmAssistantReturnFocus?.focus) crmAssistantReturnFocus.focus();
    crmAssistantReturnFocus = null;
  }

  async function loadCrmAssistantThread(threadId) {
    if (!threadId || !store.getCrmAssistantThread) return;
    ensureCrmAssistantContextState();
    const activeContext = currentCrmAssistantContext().payload;
    const contextKey = crmAssistantContextKey(activeContext);
    const contextEpoch = crmAssistantContextEpoch;
    const stateGeneration = sensitiveWorkflowGeneration;
    const candidate = crmAssistantThreads.find((row) => crmAssistantThreadId(row) === threadId);
    if (!candidate || !crmAssistantThreadMatchesContext(candidate, activeContext)) {
      setCrmAssistantError("Samtalen tilhører en annen kunde eller sak og kan ikke åpnes her.");
      renderCrmAssistantPanel();
      return;
    }
    setCrmAssistantError();
    crmAssistantThread = candidate;
    crmAssistantMessages = [];
    crmAssistantSuggestions = [];
    crmAssistantWorkflow = null;
    crmAssistantMemories = [];
    setCrmAssistantBusy(true, "Laster samtale…");
    const retry = () => loadCrmAssistantThread(threadId);
    try {
      const response = await store.getCrmAssistantThread(threadId, activeContext);
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
      await applyCrmAssistantResponse(response, {
        clearSuggestions: true,
        stateGeneration,
        contextPayload: activeContext,
        contextKey,
        contextEpoch,
      });
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
      const thread = response.thread || candidate;
      if (!crmAssistantThreadMatchesContext(thread, activeContext)) {
        throw new Error("Samtalen tilhører en annen kunde eller sak og ble ikke åpnet.");
      }
      if (thread) crmAssistantThread = thread;
      crmAssistantThreadDrawerOpen = false;
    } catch (error) {
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
      setCrmAssistantError(error.message || "Klarte ikke laste samtalen.", retry);
    } finally {
      if (crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) {
        setCrmAssistantBusy(false);
        renderCrmAssistantPanel();
      }
    }
  }

  async function loadCrmAssistantThreads() {
    if (!store.listCrmAssistantThreads) {
      setCrmAssistantError("CRM-assistenten er ikke koblet til ennå.");
      return;
    }
    ensureCrmAssistantContextState();
    const activeContext = currentCrmAssistantContext().payload;
    const contextKey = crmAssistantContextKey(activeContext);
    const contextEpoch = crmAssistantContextEpoch;
    const stateGeneration = sensitiveWorkflowGeneration;
    setCrmAssistantError();
    setCrmAssistantBusy(true, "Laster samtaler…");
    const retry = () => loadCrmAssistantThreads();
    try {
      const response = await store.listCrmAssistantThreads(activeContext);
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
      crmAssistantInitialized = true;
      if (Array.isArray(response.threads)) crmAssistantThreads = response.threads;
      if (response.thread || response.messages) {
        if (!response.thread || !crmAssistantThreadMatchesContext(response.thread, activeContext)) {
          throw new Error("Serveren returnerte en samtale fra feil CRM-kontekst.");
        }
        await applyCrmAssistantResponse(response, {
          stateGeneration,
          contextPayload: activeContext,
          contextKey,
          contextEpoch,
        });
      } else {
        const currentId = crmAssistantThreadId();
        const contextThreads = crmAssistantThreads.filter((row) => crmAssistantThreadMatchesContext(row, activeContext));
        const preferred = contextThreads.find((row) => crmAssistantThreadId(row) === currentId) || contextThreads[0];
        if (preferred) {
          setCrmAssistantBusy(false);
          await loadCrmAssistantThread(crmAssistantThreadId(preferred));
          return;
        }
        crmAssistantThread = null;
        crmAssistantMessages = [];
        crmAssistantSuggestions = [];
        crmAssistantWorkflow = null;
        crmAssistantMemories = [];
      }
    } catch (error) {
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
      setCrmAssistantError(error.message || "Klarte ikke laste samtaler.", retry);
    } finally {
      if (crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) {
        setCrmAssistantBusy(false);
        renderCrmAssistantPanel();
      }
    }
  }

  async function createCrmAssistantThread() {
    if (!store.createCrmAssistantThread) throw new Error("Ny samtale er ikke tilgjengelig ennå.");
    ensureCrmAssistantContextState();
    const activeContext = currentCrmAssistantContext().payload;
    const contextKey = crmAssistantContextKey(activeContext);
    const contextEpoch = crmAssistantContextEpoch;
    const stateGeneration = sensitiveWorkflowGeneration;
    setCrmAssistantError();
    setCrmAssistantBusy(true, "Starter ny samtale…");
    const retry = () => createCrmAssistantThread();
    try {
      const response = await store.createCrmAssistantThread(activeContext);
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return null;
      if (!response.thread || !crmAssistantThreadMatchesContext(response.thread, activeContext)) {
        throw new Error("Serveren opprettet samtalen i feil CRM-kontekst.");
      }
      crmAssistantThread = response.thread || null;
      crmAssistantMessages = Array.isArray(response.messages) ? response.messages : [];
      crmAssistantSuggestions = [];
      crmAssistantWorkflow = null;
      crmAssistantMemories = Array.isArray(response.memories) ? response.memories : [];
      if (crmAssistantThread) upsertCrmAssistantThread(crmAssistantThread);
      crmAssistantThreadDrawerOpen = false;
      await applyCrmAssistantResponse(response, {
        clearSuggestions: true,
        stateGeneration,
        contextPayload: activeContext,
        contextKey,
        contextEpoch,
      });
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return null;
      crmAssistantInitialized = true;
      setTimeout(() => el.crmAssistantInput?.focus(), 0);
      return crmAssistantThread;
    } catch (error) {
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return null;
      setCrmAssistantError(error.message || "Klarte ikke starte ny samtale.", retry);
      return null;
    } finally {
      if (crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) {
        setCrmAssistantBusy(false);
        renderCrmAssistantPanel();
      }
    }
  }

  async function openCrmAssistantPanel() {
    if (!isAdmin()) return;
    closeFloatingMenus();
    crmAssistantReturnFocus = document.activeElement;
    crmAssistantOpen = true;
    const contextChanged = ensureCrmAssistantContextState();
    el.crmAssistantPanel?.classList.add("open");
    el.crmAssistantPanel?.setAttribute("aria-hidden", "false");
    if (el.crmAssistantPanel) el.crmAssistantPanel.inert = false;
    el.crmAssistantButton?.setAttribute("aria-expanded", "true");
    el.mobileCrmAssistantButton?.setAttribute("aria-expanded", "true");
    document.body.classList.add("crm-assistant-open");
    renderCrmAssistantPanel();
    setTimeout(() => el.crmAssistantInput?.focus(), 0);
    if (contextChanged || !crmAssistantInitialized) await loadCrmAssistantThreads();
  }

  function createCrmAssistantClientMessageId() {
    if (globalThis.crypto?.randomUUID) return globalThis.crypto.randomUUID();
    const bytes = new Uint8Array(16);
    if (globalThis.crypto?.getRandomValues) {
      globalThis.crypto.getRandomValues(bytes);
    } else {
      for (let index = 0; index < bytes.length; index += 1) bytes[index] = Math.floor(Math.random() * 256);
    }
    bytes[6] = (bytes[6] & 0x0f) | 0x40;
    bytes[8] = (bytes[8] & 0x3f) | 0x80;
    const hex = Array.from(bytes, (value) => value.toString(16).padStart(2, "0")).join("");
    return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20)}`;
  }

  async function sendCrmAssistantMessage(textOverride = "", clientMessageId = "", replacementAction = null) {
    const message = String(textOverride || el.crmAssistantInput?.value || "").trim();
    if (!message || crmAssistantLoading) return;
    if (!store.sendCrmAssistantMessage || !store.createCrmAssistantThread) {
      setCrmAssistantError("CRM-assistenten er ikke koblet til ennå.");
      return;
    }
    ensureCrmAssistantContextState();
    const activeContext = currentCrmAssistantContext().payload;
    const contextKey = crmAssistantContextKey(activeContext);
    const contextEpoch = crmAssistantContextEpoch;
    const stateGeneration = sensitiveWorkflowGeneration;
    const replacementRequest = replacementAction || crmAssistantReplacementAction;
    crmAssistantReplacementAction = null;
    setCrmAssistantError();
    if (el.crmAssistantInput) el.crmAssistantInput.value = "";
    crmAssistantPendingUserMessage = {
      id: `pending-${Date.now()}`,
      role: "user",
      content: message,
      created_at: new Date().toISOString(),
    };
    crmAssistantSuggestions = [];
    crmAssistantWorkflow = null;
    renderCrmAssistantSuggestions();
    setCrmAssistantBusy(true, "Forbereder svar…");
    const stableClientMessageId = clientMessageId || createCrmAssistantClientMessageId();
    const retry = () => sendCrmAssistantMessage(message, stableClientMessageId, replacementRequest);
    try {
      let threadId = crmAssistantThreadId();
      if (threadId && !crmAssistantThreadMatchesContext(crmAssistantThread, activeContext)) {
        crmAssistantThread = null;
        threadId = "";
      }
      if (!threadId) {
        const created = await store.createCrmAssistantThread(activeContext);
        if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
        if (!created.thread || !crmAssistantThreadMatchesContext(created.thread, activeContext)) {
          throw new Error("Serveren opprettet samtalen i feil CRM-kontekst.");
        }
        if (created.thread) {
          crmAssistantThread = created.thread;
          upsertCrmAssistantThread(created.thread);
        }
        threadId = crmAssistantThreadId();
        if (!threadId) throw new Error("Klarte ikke opprette samtalen.");
      }
      const response = await store.sendCrmAssistantMessage(
        threadId,
        message,
        activeContext,
        stableClientMessageId,
        replacementRequest?.actionId || "",
      );
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
      const optimistic = { ...crmAssistantPendingUserMessage, id: `local-${Date.now()}` };
      crmAssistantPendingUserMessage = null;
      if (!response.message || typeof response.message !== "object") {
        crmAssistantMessages = mergeCrmAssistantMessages(crmAssistantMessages, optimistic);
      }
      await applyCrmAssistantResponse(response, {
        stateGeneration,
        replacementAction: replacementRequest,
        contextPayload: activeContext,
        contextKey,
        contextEpoch,
        persistSuggestions: true,
      });
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
      crmAssistantInitialized = true;
    } catch (error) {
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
      crmAssistantPendingUserMessage = null;
      if (replacementRequest?.actionId) crmAssistantReplacementAction = replacementRequest;
      if (el.crmAssistantInput && !el.crmAssistantInput.value) el.crmAssistantInput.value = message;
      setCrmAssistantError(error.message || "Klarte ikke sende meldingen.", retry);
    } finally {
      if (crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) {
        setCrmAssistantBusy(false);
        renderCrmAssistantPanel();
      }
    }
  }

  async function archiveCrmAssistantThread(threadId) {
    if (!threadId || !store.archiveCrmAssistantThread) return;
    ensureCrmAssistantContextState();
    const activeContext = currentCrmAssistantContext().payload;
    const contextKey = crmAssistantContextKey(activeContext);
    const contextEpoch = crmAssistantContextEpoch;
    const stateGeneration = sensitiveWorkflowGeneration;
    const thread = crmAssistantThreads.find((row) => crmAssistantThreadId(row) === threadId);
    if (!thread || !crmAssistantThreadMatchesContext(thread, activeContext)) {
      setCrmAssistantError("Samtalen tilhører en annen kunde eller sak og kan ikke arkiveres her.");
      renderCrmAssistantPanel();
      return;
    }
    const confirmed = await askForConfirmation({
      title: "Arkiver samtale",
      message: `Arkiver «${crmAssistantThreadTitle(thread)}»? Samtalen fjernes fra listen, men kundedata endres ikke.`,
      confirmLabel: "Arkiver",
    });
    if (!confirmed || !crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
    setCrmAssistantError();
    setCrmAssistantBusy(true, "Arkiverer samtale…");
    try {
      await store.archiveCrmAssistantThread(threadId, activeContext);
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
      crmAssistantThreads = crmAssistantThreads.filter((row) => crmAssistantThreadId(row) !== threadId);
      if (crmAssistantThreadId() === threadId) {
        crmAssistantThread = null;
        crmAssistantMessages = [];
        crmAssistantSuggestions = [];
        crmAssistantWorkflow = null;
        crmAssistantMemories = [];
        const next = crmAssistantThreads.find((row) => crmAssistantThreadMatchesContext(row, activeContext));
        if (next) {
          setCrmAssistantBusy(false);
          await loadCrmAssistantThread(crmAssistantThreadId(next));
          return;
        }
      }
    } catch (error) {
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
      setCrmAssistantError(error.message || "Klarte ikke arkivere samtalen.");
    } finally {
      if (crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) {
        setCrmAssistantBusy(false);
        renderCrmAssistantPanel();
      }
    }
  }

  async function sendCrmAssistantFeedback(messageId, value, button) {
    ensureCrmAssistantContextState();
    const activeContext = currentCrmAssistantContext().payload;
    const contextKey = crmAssistantContextKey(activeContext);
    const contextEpoch = crmAssistantContextEpoch;
    const stateGeneration = sensitiveWorkflowGeneration;
    const threadId = crmAssistantThreadId();
    if (!threadId || !messageId || !store.sendCrmAssistantFeedback || !crmAssistantThreadMatchesContext(crmAssistantThread, activeContext)) return;
    let details = { reasonCode: "accepted", note: "" };
    if (value === "not_helpful") {
      details = await askForAssistantLearningFeedback({
        title: "Hva bør assistenten forbedre?",
        message: "Velg den viktigste grunnen. Dette brukes som et mønster, ikke som nye kundedata.",
        reasons: [
          { value: "incorrect_fact", label: "Feil fakta" },
          { value: "missing_information", label: "Mangler viktig informasjon" },
          { value: "wrong_tone", label: "Feil tone eller formulering" },
          { value: "too_long", label: "For langt svar" },
          { value: "wrong_action", label: "Foreslo feil handling" },
          { value: "unsafe", label: "Utrygt forslag" },
          { value: "other", label: "Annet" },
        ],
      });
      if (!details) return;
    }
    if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
    button.disabled = true;
    try {
      await store.sendCrmAssistantFeedback(threadId, {
        messageId,
        value,
        reasonCode: details.reasonCode,
        note: details.note,
        clientEventId: createCrmAssistantClientMessageId(),
      }, activeContext);
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
      crmAssistantFeedback.set(messageId, value);
      renderCrmAssistantMessages({ keepScroll: true });
      if (el.crmAssistantStatus) el.crmAssistantStatus.textContent = "Takk for tilbakemeldingen.";
    } catch (error) {
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
      setCrmAssistantError(error.message || "Klarte ikke lagre tilbakemeldingen.");
    } finally {
      if (crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) button.disabled = false;
    }
  }

  async function saveCrmAssistantMemory(messageId, button) {
    ensureCrmAssistantContextState();
    const activeContext = currentCrmAssistantContext().payload;
    const contextKey = crmAssistantContextKey(activeContext);
    const contextEpoch = crmAssistantContextEpoch;
    const threadId = crmAssistantThreadId();
    const message = crmAssistantMessages.find((row, index) => crmAssistantMessageId(row, index) === messageId);
    const rule = crmAssistantMemorySuggestion(message);
    if (!threadId || !message || !rule || !store.saveCrmAssistantMemory || !crmAssistantThreadMatchesContext(crmAssistantThread, activeContext)) return;
    const stateGeneration = sensitiveWorkflowGeneration;
    button.disabled = true;
    try {
      const response = await store.saveCrmAssistantMemory(threadId, {
        messageId,
        rule,
      }, activeContext);
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
      crmAssistantSavedMemories.add(messageId);
      if (Array.isArray(response.memories)) crmAssistantMemories = response.memories;
      renderCrmAssistantMemories();
      renderCrmAssistantMessages({ keepScroll: true });
      if (el.crmAssistantStatus) el.crmAssistantStatus.textContent = "Husket for senere samtaler.";
    } catch (error) {
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
      setCrmAssistantError(error.message || "Klarte ikke lagre minnet.");
    } finally {
      if (crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) button.disabled = false;
    }
  }

  async function disableCrmAssistantMemory(memoryId, button) {
    ensureCrmAssistantContextState();
    const activeContext = currentCrmAssistantContext().payload;
    const contextKey = crmAssistantContextKey(activeContext);
    const contextEpoch = crmAssistantContextEpoch;
    const stateGeneration = sensitiveWorkflowGeneration;
    const threadId = crmAssistantThreadId();
    if (!threadId || !memoryId || !store.disableCrmAssistantMemory || !crmAssistantThreadMatchesContext(crmAssistantThread, activeContext)) return;
    const confirmed = await askForConfirmation({
      title: "Deaktiver regel eller kundeminne",
      message: "Deaktivere denne oppføringen? Den beholdes i historikken, men brukes ikke i nye svar.",
      confirmLabel: "Deaktiver",
    });
    if (!confirmed || !crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
    button.disabled = true;
    try {
      const response = await store.disableCrmAssistantMemory(threadId, memoryId, activeContext);
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
      crmAssistantMemories = Array.isArray(response.memories)
        ? response.memories
        : crmAssistantMemories.filter((memory) => String(memory?.id || "") !== String(memoryId));
      renderCrmAssistantMemories();
      if (el.crmAssistantStatus) el.crmAssistantStatus.textContent = "Regelen er deaktivert og beholdt i historikken.";
    } catch (error) {
      if (!crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch)) return;
      setCrmAssistantError(error.message || "Klarte ikke deaktivere regelen.");
    } finally {
      if (crmAssistantRequestIsCurrent(stateGeneration, contextKey, contextEpoch) && button.isConnected) button.disabled = false;
    }
  }

  function openCrmAssistantQueue(actionId = "") {
    const normalizedActionId = String(actionId || "").trim();
    if (normalizedActionId) assistantQueueExpanded = true;
    if (isMobileLayout()) selectedLeadId = "";
    setLeadInboxTab("new");
    setView("leads");
    closeCrmAssistantPanel({ restoreFocus: false });
    setTimeout(() => {
      const cards = Array.from(el.assistantActionQueue?.querySelectorAll("[data-assistant-action-card]") || []);
      const target = normalizedActionId
        ? cards.find((card) => card.dataset.assistantActionCard === normalizedActionId)
        : null;
      (target || el.assistantActionQueue)?.scrollIntoView({ behavior: "smooth", block: "start" });
      if (target) {
        target.classList.add("assistant-action-focus");
        window.setTimeout(() => target.classList.remove("assistant-action-focus"), 1800);
      }
    }, 0);
  }

  function openCrmAssistantServiceRoute(areaLabel = "", customerIds = crmAssistantWorkflow?.customerIds) {
    const area = String(areaLabel || crmAssistantWorkflow?.areaLabel || "").trim();
    if (!area || !el.routeArea) return;
    const allControlledIds = Array.isArray(customerIds)
      ? customerIds.map((id) => String(id || "").trim()).filter(Boolean)
      : [];
    const controlledIds = allControlledIds.slice(0, 10);
    el.routeArea.value = area;
    if (el.routeStatus) el.routeStatus.value = "due";
    if (el.routeReplyFilter) el.routeReplyFilter.value = "all";
    routeAssistantCustomerIds = controlledIds.length ? new Set(controlledIds) : null;
    routeSelectedCustomerIds = new Set(controlledIds);
    routeSelectedInstallationIds = new Map();
    routeSelectedLocationIds = new Map();
    routeCustomerConfirmations = new Map();
    routeVerifiedPlan = null;
    setView("routeplanner");
    renderRoutePlanner();
    if (isMobileLayout()) closeCrmAssistantPanel({ restoreFocus: false });
    setSyncStatus(
      controlledIds.length
        ? `Serviceruten viser det kontrollerte utvalget på ${controlledIds.length} kunder i ${area}${allControlledIds.length > controlledIds.length ? `. ${allControlledIds.length - controlledIds.length} må tas i en ny runde` : ""}. Kundene er ikke booket.`
        : `Serviceruten viser aktuelle kunder i ${area}. Kundene er ikke bekreftet eller booket.`,
      "ok",
    );
  }

  function openCustomerCard(customerId) {
    const customer = findCustomer(customerId);
    if (!customer) return;
    selectedCustomerId = customerKey(customer);
    currentCustomerFilter = "all";
    currentSearch = "";
    if (el.statusFilter) el.statusFilter.value = "all";
    if (el.customerSearch) el.customerSearch.value = "";
    setView("customers");
  }

  function showBookingInPlanning(bookingId) {
    const row = bookingRows().find((item) => item.id === bookingId);
    if (!row) {
      setSyncStatus("Fant ikke bookingen i plan.", "error");
      return;
    }
    const date = new Date(`${row.booking.date}T00:00:00`);
    if (!Number.isNaN(date.getTime())) {
      weekStart = startOfWeek(date);
      planningMonthCursor = date;
    }
    planningMode = "week";
    planningResourceFilter = "all";
    setView("planning");
    focusPlanningBookingCard(bookingId);
    setSyncStatus(`${cleanDisplayName(row.customer)} ligger i planen ${formatDate(row.booking.date)}. Bruk Flytt eller dra jobben til ny dato.`, "ok");
  }

  function focusPlanningBookingCard(bookingId) {
    const id = String(bookingId || "").trim();
    if (!id || !el.planningBoard) return;
    window.requestAnimationFrame(() => {
      const matches = Array.from(el.planningBoard.querySelectorAll("[data-booking-id]"))
        .filter((element) => String(element.dataset.bookingId || "") === id);
      if (!matches.length) return;
      const target = matches.find((element) => element.classList.contains("timeline-event")) || matches[0];
      const details = target.closest("details");
      if (details) details.open = true;
      matches.forEach((element) => element.classList.add("planning-booking-focus"));
      target.scrollIntoView({ behavior: "smooth", block: "center", inline: "center" });
      window.setTimeout(() => {
        matches.forEach((element) => element.classList.remove("planning-booking-focus"));
      }, 5000);
    });
  }

  function focusInboxComposer() {
    setLeadInboxTab("new");
    setView("leads");
    setTimeout(() => {
      document.querySelector(".ai-registration-panel")?.setAttribute("open", "");
      el.aiRegistrationPasteZone?.scrollIntoView({ behavior: "smooth", block: "start" });
      el.aiRegistrationInput?.focus();
    }, 0);
  }

  function handleNewAction(action) {
    closeFloatingMenus();
    if (action === "customer") {
      openCustomerDialog("");
      return;
    }
    if (action === "lead" || action === "paste") {
      focusInboxComposer();
      return;
    }
    if (action === "booking") {
      openBookingDialog("");
      return;
    }
    if (action === "service") {
      openBookingDialog("", "", { type: "service" });
      return;
    }
    if (action === "install") {
      openBookingDialog("", "", { type: "installasjon" });
      return;
    }
    if (action === "reminder") {
      openReminderDialog("");
      return;
    }
    if (action === "unscheduled-job") {
      pendingCustomerAction = "job";
      selectedCustomerId = "";
      currentCustomerFilter = "all";
      currentSearch = "";
      if (el.statusFilter) el.statusFilter.value = "all";
      if (el.customerSearch) el.customerSearch.value = "";
      setView("customers");
      setSyncStatus("Velg kunden som jobben gjelder. Jobbskjemaet åpnes med en gang.", "ok");
      setTimeout(() => el.customerSearch?.focus(), 0);
      return;
    }
  }

  function openBookingFromButton(button) {
    if (!button) return;
    const customer = findCustomer(button.dataset.bookCustomer);
    const installation = customer && button.dataset.bookInstallation
      ? installationsForCustomer(customer).find((item) => String(item.id || "") === String(button.dataset.bookInstallation))
      : null;
    openBookingDialog(button.dataset.bookCustomer, "", {
      type: button.dataset.bookType || "",
      installationId: installation?.id || "",
      note: installation ? installationBookingNote(installation, customer) : "",
    });
  }

  function legacyInstallationPrefill(customer) {
    if (!customer) return {};
    const product = customerProductDisplayParts(customer);
    const serviceDates = [
      customer.last_service_date,
      ...(String(customer.service_dates || "").match(/\d{4}-\d{2}-\d{2}/g) || []),
    ].filter(Boolean).sort();
    const lastService = serviceDates.at(-1) || "";
    const intervalText = `${customer.service_interval || ""} ${customer.tags || ""}`;
    const serviceIntervalMonths = /årlig|arlig|1\s*år|1\s*ar/i.test(intervalText) ? 12 : 24;
    const fallbackLocation = fallbackCustomerLocation(customer) || {};
    const hasLocations = customerLocationsForCustomer(customer).length > 0;
    const notes = [
      "Opprettet fra serviceinfo på kundekortet. Kontroller modell, datoer og adresse før lagring.",
      customer.service_interval ? `Serviceintervall fra import: ${customer.service_interval}` : "",
      customer.service_dates ? `Tidligere servicedatoer: ${customer.service_dates}` : "",
    ].filter(Boolean);
    return {
      label: "Hovedanlegg",
      brand: product.brand,
      model: product.model,
      installed_at: customer.first_install_date || "",
      last_service_at: lastService,
      next_service_due: customer.next_service_due || addMonthsIsoDate(lastService, serviceIntervalMonths),
      service_interval_months: serviceIntervalMonths,
      notes: notes.join("\n"),
      forceNewLocation: !hasLocations,
      location_name: fallbackLocation.location_name || "Kundeadresse",
      address: fallbackLocation.address || "",
      postal_code: fallbackLocation.postal_code || "",
      city: fallbackLocation.city || "",
    };
  }

  function openInstallationFromButton(button) {
    if (!button) return;
    const customerId = button.dataset.newInstallationCustomer || "";
    const customer = findCustomer(customerId);
    const prefill = button.dataset.installationPrefill === "legacy"
      ? legacyInstallationPrefill(customer)
      : {};
    openInstallationDialog(customerId, "", Object.keys(prefill).length ? { prefill } : {});
  }

  function handleStartAction(action) {
    if (action === "inbox" || action === "followup") {
      setLeadInboxTab(action === "followup" ? "followup" : "new");
      setView("leads");
      return;
    }
    if (action === "assistant") {
      openCrmAssistantQueue();
      return;
    }
    if (action === "today") {
      weekStart = startOfWeek(new Date());
      planningMonthCursor = new Date();
      setView("planning");
      return;
    }
    if (action === "service") {
      selectedCustomerId = "";
      currentCustomerFilter = "due";
      if (el.statusFilter) el.statusFilter.value = "due";
      setView("customers");
      return;
    }
    if (action === "billing") {
      setView("dashboard");
      if (el.dashboardQueueDetails) el.dashboardQueueDetails.open = true;
      setTimeout(() => el.billingQueue?.closest(".panel")?.scrollIntoView({ behavior: "smooth", block: "start" }), 0);
      return;
    }
    if (action === "reminders") {
      setView("dashboard");
      if (el.dashboardQueueDetails) el.dashboardQueueDetails.open = true;
      setTimeout(() => el.reminderQueue?.closest(".panel")?.scrollIntoView({ behavior: "smooth", block: "start" }), 0);
      return;
    }
    if (action === "move") {
      setView("dashboard");
      if (el.dashboardQueueDetails) el.dashboardQueueDetails.open = true;
      setTimeout(() => el.moveQueue?.closest(".panel")?.scrollIntoView({ behavior: "smooth", block: "start" }), 0);
      return;
    }
    if (action === "quality") {
      const firstQuality = dataQualityRows()[0]?.id || "missing";
      selectedCustomerId = "";
      currentCustomerFilter = firstQuality;
      currentSearch = "";
      if (el.statusFilter) el.statusFilter.value = firstQuality;
      if (el.customerSearch) el.customerSearch.value = "";
      setView("customers");
    }
  }

  function showPasswordResetMessage(message, tone = "error") {
    if (!el.passwordResetMessage) return;
    el.passwordResetMessage.textContent = message || "";
    el.passwordResetMessage.className = `dialog-message ${tone || ""}`.trim();
    el.passwordResetMessage.classList.toggle("hidden", !message);
  }

  function openPasswordResetDialog() {
    if (!el.passwordResetDialog) return;
    passwordRecoveryActive = true;
    el.passwordResetNew.value = "";
    el.passwordResetConfirm.value = "";
    showPasswordResetMessage("", "error");
    if (!el.passwordResetDialog.open) el.passwordResetDialog.showModal();
    setTimeout(() => el.passwordResetNew?.focus(), 0);
  }

  async function requestPasswordReset() {
    if (!store.isConfigured || !store.resetPassword) {
      el.loginMessage.textContent = "Passordreset er ikke tilgjengelig akkurat nå.";
      return;
    }
    const email = el.loginEmail.value.trim();
    if (!email) {
      el.loginMessage.textContent = "Skriv inn e-postadressen først.";
      el.loginEmail.focus();
      return;
    }
    const redirectTo = appPublicUrl("/");
    const previousText = el.forgotPasswordButton.textContent;
    el.forgotPasswordButton.disabled = true;
    el.forgotPasswordButton.textContent = "Sender...";
    try {
      await store.resetPassword(email, redirectTo);
      el.loginMessage.textContent = "Hvis e-posten finnes i CRM, kommer det en lenke for nytt passord.";
    } catch (error) {
      el.loginMessage.textContent = error.message || "Klarte ikke sende passordlenke.";
    } finally {
      el.forgotPasswordButton.disabled = false;
      el.forgotPasswordButton.textContent = previousText;
    }
  }

  async function savePasswordReset() {
    if (!store.updatePassword) throw new Error("Passordendring er ikke tilgjengelig akkurat nå.");
    const password = el.passwordResetNew.value;
    const confirm = el.passwordResetConfirm.value;
    if (password.length < 10) throw new Error("Passordet må ha minst 10 tegn.");
    if (password !== confirm) throw new Error("Passordene er ikke like.");
    await store.updatePassword(password);
    passwordRecoveryActive = false;
    el.passwordResetDialog.close();
    if (window.history?.replaceState) window.history.replaceState(null, "", `${window.location.origin}${window.location.pathname}`);
    await refreshData("Passord oppdatert.");
  }

  function rememberLoginPreference() {
    return localStorage.getItem(storage.rememberLogin) !== "false";
  }

  function clearLoginPassword() {
    if (el.loginPassword) el.loginPassword.value = "";
  }

  function renderApp() {
    const missingProductionDatabase = !store.isConfigured && !demoEnabled;
    if (el.loginRemember) el.loginRemember.checked = rememberLoginPreference();
    el.loginIntro.textContent = store.isConfigured
      ? "Logg inn med e-post og passord."
      : demoEnabled
        ? "Lokal utviklingsdemo. Ikke bruk dette til ekte kundedata."
        : databaseUnavailableMessage;
    el.loginForm.classList.toggle("hidden", !store.isConfigured);
    const showDemoLogin = demoEnabled && !store.isConfigured;
    document.querySelector(".demo-label")?.classList.toggle("hidden", !showDemoLogin);
    document.querySelector(".demo-login-actions")?.classList.toggle("hidden", !showDemoLogin);
    document.querySelectorAll("[data-login]").forEach((button) => button.classList.toggle("hidden", !showDemoLogin));
    if (missingProductionDatabase && el.loginMessage) el.loginMessage.textContent = databaseUnavailableMessage;

    if (!currentUser) {
      closeCrmAssistantPanel({ restoreFocus: false });
      el.loginView.classList.remove("hidden");
      el.appView.classList.add("hidden");
      el.appView.classList.remove("technician-mode");
      installHelpText();
      return;
    }
    clearLoginPassword();
    el.loginView.classList.add("hidden");
    el.appView.classList.remove("hidden");
    el.currentUserName.textContent = currentUser.name;
    el.currentUserRole.textContent = currentUser.role;
    el.dataModePill.textContent = store.isConfigured ? "Tilkoblet" : "Lokal utviklingsdemo";
    el.dataModePill.classList.toggle("online", store.isConfigured);
    el.importSeedButton.classList.toggle("hidden", !(store.isConfigured && browserImportEnabled && isAdmin() && (rawData.customers || []).length));
    const technician = isTechnicianUser();
    el.appView.classList.toggle("technician-mode", technician);
    el.crmAssistantButton?.classList.toggle("hidden", technician);
    el.mobileCrmAssistantButton?.classList.toggle("hidden", technician);
    if (technician && crmAssistantOpen) closeCrmAssistantPanel({ restoreFocus: false });
    updateNavigationForRole();
    if (!viewAllowedForCurrentUser(currentView)) currentView = defaultViewForCurrentUser();
    el.newActionButton?.classList.toggle("hidden", technician);
    el.newCustomerButton?.classList.toggle("hidden", technician);
    el.newBookingButton?.classList.toggle("hidden", technician);
    setView(currentView || currentUser.view);
    installHelpText();
  }

  function renderCurrentView() {
    if (!currentUser) return;
    switch (currentView) {
      case "customers":
        renderCustomers();
        return;
      case "leads":
        renderLeads();
        return;
      case "orders":
        renderOrders();
        return;
      case "insulation":
        renderInsulation();
        return;
      case "planning":
        renderPlanning();
        return;
      case "routeplanner":
        renderRoutePlanner();
        return;
      case "technician":
        renderTechnician();
        return;
      case "settings":
        renderSettings();
        return;
      case "dashboard":
      default:
        renderDashboard();
    }
  }

  function renderAll(options = {}) {
    if (!options.forceAll) {
      renderCurrentView();
      return;
    }
    renderDashboard();
    renderCustomers();
    renderLeads();
    renderOrders();
    renderInsulation();
    renderPlanning();
    renderRoutePlanner();
    renderTechnician();
    renderSettings();
  }

  function renderDashboard() {
    const serviceRows = [];
    let redCount = 0;
    let yellowCount = 0;
    let greenCount = 0;
    for (const customer of customers) {
      if (!customer || customer.is_inactive) continue;
      const kind = statusKind(customer);
      if (kind === "red") redCount += 1;
      else if (kind === "yellow") yellowCount += 1;
      else if (kind === "green") greenCount += 1;
      serviceRows.push({ customer, kind });
    }
    const dashboardBookingRows = bookingRows();
    const upcomingBookings = dashboardBookingRows.filter((row) => row.booking.date >= isoDate(new Date())).length;
    const moveRows = moveQueueRows();
    const billingRows = billingQueueRows();
    const reminderRows = activeReminderRows();
    const leadEntries = allLeadEntries();
    const leadMetadata = leadEntryRenderMetadata(leadEntries);
    const newLeadCount = leadEntries.filter((entry) => leadEntryMatchesInboxTab(entry, "new", leadMetadata.get(leadEntryKey(entry)))).length;
    const offerFollowupCount = leadEntries.filter((entry) => leadEntryMatchesInboxTab(entry, "followup", leadMetadata.get(leadEntryKey(entry)))).length;
    const openWebsiteSubmissionCount = openWebsiteSubmissionRows().length;
    const openIntakeCount = openIntakeRows().length;
    const openAssistantCount = pendingAssistantActions().length;
    el.redMetric.textContent = redCount.toLocaleString("nb-NO");
    el.yellowMetric.textContent = yellowCount.toLocaleString("nb-NO");
    el.greenMetric.textContent = greenCount.toLocaleString("nb-NO");
    el.bookedMetric.textContent = dashboardBookingRows.length.toLocaleString("nb-NO");
    if (el.dashboardServiceCount) el.dashboardServiceCount.textContent = (redCount + yellowCount).toLocaleString("nb-NO");
    if (el.dashboardLeadCount) el.dashboardLeadCount.textContent = (newLeadCount + offerFollowupCount + openWebsiteSubmissionCount + openIntakeCount).toLocaleString("nb-NO");
    if (el.dashboardBookingCount) el.dashboardBookingCount.textContent = upcomingBookings.toLocaleString("nb-NO");
    if (el.dashboardMoveCount) el.dashboardMoveCount.textContent = moveRows.length.toLocaleString("nb-NO");
    if (el.dashboardBillingCount) el.dashboardBillingCount.textContent = billingRows.length.toLocaleString("nb-NO");
    if (el.dashboardReminderCount) el.dashboardReminderCount.textContent = reminderRows.length.toLocaleString("nb-NO");

    renderStartWorklist({
      redCount,
      yellowCount,
      newLeadCount,
      offerFollowupCount,
      openWebsiteSubmissionCount,
      openIntakeCount,
      openAssistantCount,
      moveCount: moveRows.length,
      billingCount: billingRows.length,
      reminderCount: reminderRows.length,
    });
    renderGoogleInsights();
    renderGlobalSearch();
    if (el.dashboardQueueDetails?.open) {
      renderNextJobs();
      renderMoveQueue(moveRows);
      renderReminderQueue();

      el.dueCustomers.innerHTML = "";
      const dueList = serviceRows
        .filter((row) => ["red", "yellow"].includes(row.kind))
        .map((row) => ({ ...row, due: nextServiceDueForCustomer(row.customer) || "9999-99-99" }))
        .sort((a, b) => String(a.due).localeCompare(String(b.due)));
      setDashboardSectionVisibility(el.dueCustomers, dueList.length > 0);
      for (const row of dueList.slice(0, 12)) {
        const customer = row.customer;
        const button = document.createElement("button");
        const installationLine = routeInstallationLine(customer);
        button.type = "button";
        button.dataset.customerId = customerKey(customer);
        button.innerHTML = `<span class="dot ${row.kind}"></span><strong>${customerStarHtml(customer)}${customerCashBadgeHtml(customer)}${escapeHtml(cleanDisplayName(customer))}</strong><span>${escapeHtml([installationLine, customer.location_tag || customer.visit_city || ""].filter(Boolean).join(" · "))}</span>`;
        el.dueCustomers.appendChild(button);
      }
      renderBillingQueue();
      renderDataQuality();
      syncDashboardQueueDetailsVisibility();
    }
    if (el.recentActivity?.closest("details")?.open) renderRecentActivity();
  }

  function googleDashboardSnapshot() {
    let value = crmSettings?.google_dashboard_metrics;
    if (typeof value === "string") {
      try {
        value = JSON.parse(value);
      } catch (_error) {
        return {};
      }
    }
    return value && typeof value === "object" && !Array.isArray(value) ? value : {};
  }

  function googleMetricNumber(value, fallback = 0) {
    const number = Number(value);
    return Number.isFinite(number) ? number : fallback;
  }

  function googleMetricDate(value) {
    const text = String(value || "").slice(0, 10);
    if (!/^\d{4}-\d{2}-\d{2}$/.test(text)) return null;
    const date = new Date(`${text}T00:00:00`);
    return Number.isNaN(date.getTime()) ? null : date;
  }

  function defaultGoogleMetricPeriods() {
    const today = new Date();
    const end = new Date(today.getFullYear(), today.getMonth(), today.getDate() - 1);
    const start = new Date(end);
    start.setDate(start.getDate() - 27);
    const previousEnd = new Date(start);
    previousEnd.setDate(previousEnd.getDate() - 1);
    const previousStart = new Date(previousEnd);
    previousStart.setDate(previousStart.getDate() - 27);
    return { start, end, previousStart, previousEnd };
  }

  function googleMetricPeriods(searchConsole = {}) {
    const fallback = defaultGoogleMetricPeriods();
    const period = searchConsole.period || {};
    const previousPeriod = searchConsole.previous_period || {};
    return {
      start: googleMetricDate(period.start_date) || fallback.start,
      end: googleMetricDate(period.end_date) || fallback.end,
      previousStart: googleMetricDate(previousPeriod.start_date) || fallback.previousStart,
      previousEnd: googleMetricDate(previousPeriod.end_date) || fallback.previousEnd,
    };
  }

  function websiteSubmissionCountsForGoogle(periods) {
    const counts = { current: 0, previous: 0 };
    const endOfDay = (date) => new Date(date.getFullYear(), date.getMonth(), date.getDate() + 1).getTime();
    const currentStart = periods.start.getTime();
    const currentEnd = endOfDay(periods.end);
    const previousStart = periods.previousStart.getTime();
    const previousEnd = endOfDay(periods.previousEnd);
    for (const row of websiteSubmissions || []) {
      const status = String(row?.processing_status || "new").toLowerCase();
      if (["spam", "invalid"].includes(status) || websiteSubmissionLooksLikeSpam(row)) continue;
      const payload = websiteSubmissionPayload(row);
      if (payload.test_mode === true || payload.testMode === true || row?.test_mode === true) continue;
      const received = Date.parse(row?.received_at || row?.created_at || "");
      if (!Number.isFinite(received)) continue;
      if (received >= currentStart && received < currentEnd) counts.current += 1;
      if (received >= previousStart && received < previousEnd) counts.previous += 1;
    }
    return counts;
  }

  function googleMetricChange(current, previous, options = {}) {
    const now = googleMetricNumber(current);
    const before = googleMetricNumber(previous);
    if (!before) return now ? { text: "Ny aktivitet", kind: "positive" } : { text: "Ingen endring", kind: "neutral" };
    const change = Math.round(((now - before) / before) * 100);
    const better = options.lowerIsBetter ? change < 0 : change > 0;
    const worse = options.lowerIsBetter ? change > 0 : change < 0;
    return {
      text: `${change > 0 ? "+" : ""}${change.toLocaleString("nb-NO")} % mot forrige periode`,
      kind: better ? "positive" : worse ? "negative" : "neutral",
    };
  }

  function googleMetricCard(label, value, note = "", change = null) {
    return `
      <div class="google-metric">
        <span>${escapeHtml(label)}</span>
        <strong>${escapeHtml(value)}</strong>
        ${change ? `<small class="${escapeHtml(change.kind)}">${escapeHtml(change.text)}</small>` : `<small>${escapeHtml(note)}</small>`}
      </div>
    `;
  }

  function formatGoogleMetric(value) {
    return Math.round(googleMetricNumber(value)).toLocaleString("nb-NO");
  }

  function googleTrendHtml(searchConsole = {}) {
    const rows = (Array.isArray(searchConsole.daily) ? searchConsole.daily : [])
      .filter((row) => row?.date)
      .slice(-14);
    if (!rows.length) return `<div class="empty-state compact">Daglig søketrend kommer etter første Google-synk.</div>`;
    const max = Math.max(1, ...rows.map((row) => googleMetricNumber(row.impressions)));
    const bars = rows.map((row) => {
      const impressions = googleMetricNumber(row.impressions);
      const height = Math.max(8, Math.round((impressions / max) * 100));
      const date = new Date(`${row.date}T12:00:00`);
      const label = Number.isNaN(date.getTime()) ? row.date : date.toLocaleDateString("nb-NO", { day: "2-digit", month: "2-digit" });
      return `<span style="--google-bar:${height}%" title="${escapeHtml(`${label}: ${formatGoogleMetric(impressions)} visninger, ${formatGoogleMetric(row.clicks)} klikk`)}"><i></i><small>${escapeHtml(label)}</small></span>`;
    }).join("");
    return `<div class="google-trend" aria-label="Google-visninger per dag">${bars}</div>`;
  }

  function googleTopQueriesHtml(searchConsole = {}) {
    const rows = (Array.isArray(searchConsole.top_queries) ? searchConsole.top_queries : []).slice(0, 6);
    if (!rows.length) return `<div class="empty-state compact">Søkeord kommer etter første Google-synk.</div>`;
    return `<ol class="google-query-list">${rows.map((row) => `
      <li>
        <span>${escapeHtml(row.query || "(ukjent søk)")}</span>
        <strong>${formatGoogleMetric(row.clicks)} klikk</strong>
        <small>${formatGoogleMetric(row.impressions)} visninger</small>
      </li>
    `).join("")}</ol>`;
  }

  function googleBusinessMetricsHtml(businessProfile = {}) {
    if (businessProfile.available !== true) {
      return `<span>Google-bedriftsprofilen er klargjort, men ytelses-API-et er ikke koblet til ennå.</span>`;
    }
    const metrics = businessProfile.metrics || {};
    return [
      `${formatGoogleMetric(metrics.profile_impressions)} profilvisninger`,
      `${formatGoogleMetric(metrics.website_clicks)} nettsideklikk`,
      `${formatGoogleMetric(metrics.call_clicks)} telefonklikk`,
      `${formatGoogleMetric(metrics.direction_requests)} veibeskrivelser`,
    ].map((text) => `<span>${escapeHtml(text)}</span>`).join("");
  }

  function renderGoogleInsights() {
    if (!el.googleInsightsContent || !el.googleInsightsPanel) return;
    el.googleInsightsPanel.classList.toggle("hidden", !isAdmin());
    if (!isAdmin()) return;
    const snapshot = googleDashboardSnapshot();
    const searchConsole = snapshot.search_console && typeof snapshot.search_console === "object" ? snapshot.search_console : {};
    const businessProfile = snapshot.business_profile && typeof snapshot.business_profile === "object" ? snapshot.business_profile : {};
    const current = searchConsole.current || {};
    const previous = searchConsole.previous || {};
    const periods = googleMetricPeriods(searchConsole);
    const websiteCounts = websiteSubmissionCountsForGoogle(periods);
    const hasSearchData = searchConsole.available === true && Number.isFinite(Number(current.impressions));
    const generated = new Date(snapshot.generated_at || "");
    const generatedLabel = Number.isNaN(generated.getTime())
      ? "Google-søk er ikke synkronisert ennå"
      : `Oppdatert ${generated.toLocaleString("nb-NO", { dateStyle: "short", timeStyle: "short" })}`;
    const stale = !Number.isNaN(generated.getTime()) && Date.now() - generated.getTime() > 48 * 60 * 60 * 1000;
    const periodLabel = `${periods.start.toLocaleDateString("nb-NO")}–${periods.end.toLocaleDateString("nb-NO")}`;
    const websiteChange = googleMetricChange(websiteCounts.current, websiteCounts.previous);
    const cards = [
      googleMetricCard("Nettsidehenvendelser", formatGoogleMetric(websiteCounts.current), "Fra CRM", websiteChange),
      googleMetricCard("Klikk fra Google", hasSearchData ? formatGoogleMetric(current.clicks) : "–", "Venter på Google-synk", hasSearchData ? googleMetricChange(current.clicks, previous.clicks) : null),
      googleMetricCard("Visninger i Google", hasSearchData ? formatGoogleMetric(current.impressions) : "–", "Venter på Google-synk", hasSearchData ? googleMetricChange(current.impressions, previous.impressions) : null),
      googleMetricCard("Klikkfrekvens", hasSearchData ? `${(googleMetricNumber(current.ctr) * 100).toLocaleString("nb-NO", { maximumFractionDigits: 1 })} %` : "–", "Klikk delt på visninger"),
      googleMetricCard("Snittposisjon", hasSearchData ? googleMetricNumber(current.position).toLocaleString("nb-NO", { maximumFractionDigits: 1 }) : "–", "Lavere er normalt bedre"),
    ].join("");

    el.googleInsightsContent.innerHTML = `
      <div class="google-metrics-grid">${cards}</div>
      <div class="google-insights-detail-grid">
        <div>
          <h3>Synlighet siste 14 dager</h3>
          ${googleTrendHtml(searchConsole)}
        </div>
        <div>
          <h3>Søk som gir trafikk</h3>
          ${googleTopQueriesHtml(searchConsole)}
        </div>
      </div>
      <div class="google-business-summary">
        <strong>Google-bedrift</strong>
        ${googleBusinessMetricsHtml(businessProfile)}
        <a href="${escapeHtml(googleBusinessProfileUrl)}" target="_blank" rel="noreferrer">Åpne profil</a>
      </div>
      <div class="google-insights-meta ${stale ? "stale" : ""}">
        <span>${escapeHtml(periodLabel)}</span>
        <span>${escapeHtml(generatedLabel)}${stale ? " · data er eldre enn 48 timer" : ""}</span>
        <a href="${escapeHtml(googleSearchConsoleUrl)}" target="_blank" rel="noreferrer">Se hele rapporten</a>
      </div>
    `;
  }

  function renderStartWorklist(counts = {}) {
    if (!el.startWorklist) return;
    const today = isoDate(new Date());
    const todayJobs = bookingRows().filter((row) => row.booking?.date === today && row.booking?.status !== "done");
    const items = [
      {
        action: "inbox",
        label: "Nye meldinger",
        count: (counts.newLeadCount || 0) + (counts.openWebsiteSubmissionCount || 0) + (counts.openIntakeCount || 0),
        help: "Nettside, e-postutkast og saker som må avklares.",
        tone: "new",
      },
      {
        action: "followup",
        label: "Tilbud / svar",
        count: counts.offerFollowupCount || 0,
        help: "Tilbud som må skrives, sendes eller følges opp.",
        tone: "followup",
      },
      {
        action: "assistant",
        label: "Assistentforslag",
        count: counts.openAssistantCount || 0,
        help: "Svar, plan eller fakturagrunnlag som må kontrolleres. Ingenting er sendt automatisk.",
        tone: "assistant",
      },
      {
        action: "today",
        label: "Dagens jobber",
        count: todayJobs.length,
        help: "Avtaler i kalenderen for i dag.",
        tone: "today",
      },
      {
        action: "reminders",
        label: "Påminnelser",
        count: counts.reminderCount || 0,
        help: "Raske huskelapper, telefonløfter og oppfølginger.",
        tone: "reminder",
      },
      {
        action: "billing",
        label: "Må faktureres",
        count: counts.billingCount || 0,
        help: "Utførte jobber som ikke er markert fakturert eller betalt.",
        tone: "billing",
      },
      {
        action: "service",
        label: "Serviceoppfølging",
        count: (counts.redCount || 0) + (counts.yellowCount || 0),
        help: "Kunder/anlegg som kan kontaktes. Ikke booket før kunden har sagt ja eller adkomst finnes.",
        tone: "service",
      },
      {
        action: "move",
        label: "Må flyttes",
        count: counts.moveCount || 0,
        help: "Avtaler som må planlegges på nytt.",
        tone: "move",
      },
    ];
    const visibleItems = items.filter((item) => Number(item.count || 0) > 0);
    if (!visibleItems.length) {
      el.startWorklist.innerHTML = `<div class="start-worklist-empty"><strong>Ingen åpne oppgaver akkurat nå</strong><span>Bruk søk eller + Ny for å starte en ny jobb.</span></div>`;
      return;
    }
    el.startWorklist.innerHTML = visibleItems.map((item) => `
      <button class="${escapeHtml(item.tone)}" data-start-action="${escapeHtml(item.action)}" type="button" title="${escapeHtml(item.help)}">
        <span>${escapeHtml(item.label)}</span>
        <strong${item.action === "assistant" ? " data-assistant-queue-count" : ""}>${Number(item.count || 0).toLocaleString("nb-NO")}</strong>
      </button>
    `).join("");
  }

  function globalSearchMatches(text, query) {
    const terms = normalizeMatch(query).split(" ").filter(Boolean);
    if (!terms.length) return false;
    const haystack = normalizeMatch(text);
    const digits = String(text || "").replace(/\D/g, "");
    return terms.every((term) => {
      const termDigits = term.replace(/\D/g, "");
      return haystack.includes(term) || (termDigits && digits.includes(termDigits));
    });
  }

  function invoiceSearchRows() {
    const rows = [];
    const seen = new Set();
    for (const [key, list] of invoicesByCustomer.entries()) {
      const customer = findCustomer(key) || customers.find((item) => item.lime_id === key || item.legacy_lime_id === key);
      if (!customer) continue;
      for (const invoice of list || []) {
        const stable = [
          invoice.id,
          invoice.invoice_number,
          invoice.file_name,
          invoice.file_url,
          invoice.date || invoice.invoice_date,
          customerKey(customer),
        ].filter(Boolean).join("|");
        if (seen.has(stable)) continue;
        seen.add(stable);
        rows.push({ invoice, customer });
      }
    }
    return rows;
  }

  const globalSearchKindRank = { Kunde: 0, Anlegg: 1, Lead: 2, Nettside: 3, Jobb: 4, Avtale: 5, Aktivitet: 6, Faktura: 7, Påminnelse: 8 };

  function finalizeGlobalSearchResults(results) {
    return results
      .sort((a, b) => (globalSearchKindRank[a.kind] ?? 9) - (globalSearchKindRank[b.kind] ?? 9) || String(a.title || "").localeCompare(String(b.title || ""), "nb"))
      .slice(0, 18);
  }

  function globalSearchRows(query = globalSearchQuery) {
    if (!String(query || "").trim()) return [];
    const results = [];
    for (const customer of customers || []) {
      if (customer?.is_inactive) continue;
      const text = customerHaystack(customer);
      if (!globalSearchMatches(text, query)) continue;
      const matchingContact = customerContactPeople(customer)
        .find((contact) => globalSearchMatches([contact.name, contact.phone, contact.email, contact.role].filter(Boolean).join(" "), query));
      const contactMeta = matchingContact
        ? `Kontakt: ${[matchingContact.name, matchingContact.phone, matchingContact.email].filter(Boolean).join(" · ")}`
        : "";
      results.push({
        id: `customer:${customerKey(customer)}`,
        kind: "Kunde",
        title: cleanDisplayName(customer),
        meta: [contactMeta, customer.phone, customer.email, addressFor(customer) || customer.location_tag, customer.tags].filter(Boolean).join(" · "),
        customerId: customerKey(customer),
        searchText: text,
      });
    }
    if (results.length >= 18) return finalizeGlobalSearchResults(results);
    for (const customer of customers || []) {
      if (customer?.is_inactive) continue;
      installationsForCustomer(customer).forEach((installation, index) => {
        const location = locationForInstallation(installation, customer);
        const text = [
          customerHaystack(customer),
          installation.label,
          installation.kind,
          installation.brand,
          installation.model,
          installation.serial_number,
          installation.notes,
          locationAddressText(location),
          installation.next_service_due,
          installation.installed_at,
        ].filter(Boolean).join(" ");
        if (!globalSearchMatches(text, query)) return;
        results.push({
          id: `installation:${customerKey(customer)}:${installation.id || index}`,
          kind: "Anlegg",
          title: installationDisplayName(installation),
          meta: [
            cleanDisplayName(customer),
            locationAddressText(location),
            installation.next_service_due ? `Neste service ${formatDate(installation.next_service_due)}` : "",
          ].filter(Boolean).join(" · "),
          customerId: customerKey(customer),
          installationId: installation.id || "",
          searchText: text,
        });
      });
    }
    if (results.length >= 18) return finalizeGlobalSearchResults(results);
    for (const entry of allLeadEntries()) {
      const customer = entry.customer;
      const text = [
        customerHaystack(customer),
        entry.lead?.source,
        entry.lead?.source_detail,
        entry.lead?.product_interest,
        leadStatusDisplayLabel(leadStatusForEntry(entry), entry),
        leadNoteForEntry(entry),
      ].filter(Boolean).join(" ");
      if (!globalSearchMatches(text, query)) continue;
      results.push({
        id: `lead:${leadEntryKey(entry)}`,
        kind: "Lead",
        title: cleanDisplayName(customer),
        meta: [leadStatusDisplayLabel(leadStatusForEntry(entry), entry), customer.phone, addressFor(customer) || customer.visit_city].filter(Boolean).join(" · "),
        leadKey: leadEntryKey(entry),
        searchText: text,
      });
    }
    if (results.length >= 18) return finalizeGlobalSearchResults(results);
    for (const row of openWebsiteSubmissionRows()) {
      const values = websiteSubmissionLeadValues(row);
      const text = [
        values.name,
        values.phone,
        values.email,
        values.address,
        values.city,
        values.product_interest,
        values.note,
        row?.public_reference,
        row?.idempotency_key,
        websiteSubmissionSourcePage(row),
      ].filter(Boolean).join(" ");
      if (!globalSearchMatches(text, query)) continue;
      results.push({
        id: `website:${row.id || row.public_reference || results.length}`,
        kind: "Nettside",
        title: values.name || row?.public_reference || "Nettsideinnsending",
        meta: [
          websiteSubmissionTypeLabel(row),
          values.phone,
          values.email,
          values.address || values.city,
          row?.public_reference,
        ].filter(Boolean).join(" · "),
        websiteSubmissionId: row.id,
        searchText: text,
      });
    }
    if (results.length >= 18) return finalizeGlobalSearchResults(results);
    for (const row of orderRows()) {
      const text = orderSearchText(row);
      if (!globalSearchMatches(text, query)) continue;
      results.push({
        id: `order:${row.id}`,
        kind: "Jobb",
        title: row.order.title || defaultOrderTitle(row.customer, row.order.type),
        meta: [cleanDisplayName(row.customer), orderStatusLabel(orderEffectiveStatus(row.order, row.job, row.linkedBookings)), billingStatusLabel(orderEffectiveBillingStatus(row.order, row.job, row.linkedBookings))].filter(Boolean).join(" · "),
        orderId: row.id,
        searchText: text,
      });
    }
    if (results.length >= 18) return finalizeGlobalSearchResults(results);
    for (const row of bookingRows()) {
      const text = [
        cleanDisplayName(row.customer),
        customerHaystack(row.customer),
        row.booking.type,
        row.booking.status,
        row.booking.note,
        row.booking.resource,
        row.booking.date,
        bookingJobLabel(row),
      ].filter(Boolean).join(" ");
      if (!globalSearchMatches(text, query)) continue;
      results.push({
        id: `booking:${row.id}`,
        kind: "Avtale",
        title: cleanDisplayName(row.customer),
        meta: [formatDate(row.booking.date), bookingTimeText(row.booking), row.booking.resource, bookingJobLabel(row)].filter(Boolean).join(" · "),
        bookingId: row.id,
        customerId: customerKey(row.customer),
        searchText: text,
      });
    }
    if (results.length >= 18) return finalizeGlobalSearchResults(results);
    const activityCustomerIndex = customerActivityIndex();
    let activityMatchCount = 0;
    [...(activities || [])]
      .sort((a, b) => activityTime(b.occurred_at || b.created_at) - activityTime(a.occurred_at || a.created_at))
      .forEach((activity, index) => {
        if (activityMatchCount >= 6) return;
        const activityType = String(activity?.activity_type || "").toLowerCase();
        if (["reminder", "reminder_done", "status_change", "lead_status"].includes(activityType)) return;
        const customer = customerForActivity(activity, activityCustomerIndex);
        if (!customer || customer?.is_inactive) return;
        const metadata = activity.metadata || {};
        const reference = metadata.email_reference || extractEmailReference(activity.summary, activity.body, metadata.subject);
        const text = [
          activity.summary,
          activity.body,
          metadata.subject,
          activityTypeLabel(activity.activity_type),
          reference,
          customerHaystack(customer),
        ].filter(Boolean).join(" ");
        if (!globalSearchMatches(text, query)) return;
        activityMatchCount += 1;
        results.push({
          id: `activity:${activity.id || reference || index}`,
          kind: "Aktivitet",
          title: activity.summary || metadata.subject || activityTypeLabel(activity.activity_type),
          meta: [
            activityTypeLabel(activity.activity_type),
            cleanDisplayName(customer),
            formatDate(activity.occurred_at || activity.created_at),
            reference ? `Ref ${reference}` : "",
          ].filter(Boolean).join(" · "),
          activityId: activity.id || "",
          customerId: customerKey(customer),
          searchText: text,
        });
      });
    for (const { invoice, customer } of invoiceSearchRows()) {
      const text = [
        invoice.invoice_number,
        invoice.file_name,
        invoice.description,
        invoice.amount,
        invoice.date || invoice.invoice_date,
        customerHaystack(customer),
      ].filter(Boolean).join(" ");
      if (!globalSearchMatches(text, query)) continue;
      results.push({
        id: `invoice:${customerKey(customer)}:${invoice.id || invoice.invoice_number || invoice.file_name || results.length}`,
        kind: "Faktura",
        title: invoice.invoice_number ? `Faktura ${invoice.invoice_number}` : invoice.file_name || "Faktura",
        meta: [cleanDisplayName(customer), formatDate(invoice.date || invoice.invoice_date), invoice.amount ? formatMoney(invoice.amount) : ""].filter(Boolean).join(" · "),
        customerId: customerKey(customer),
        searchText: text,
      });
    }
    activeReminderRows().forEach(({ activity, customer }, index) => {
      const dueLabel = reminderDueLabel(activity);
      const urgency = reminderUrgency(activity);
      const text = [
        activity.summary,
        activity.body,
        dueLabel,
        urgency.label,
        customer ? customerHaystack(customer) : "",
      ].filter(Boolean).join(" ");
      if (!globalSearchMatches(text, query)) return;
      const reminderTitle = shortEventNote(activity.body || activity.summary || "") || "Påminnelse";
      results.push({
        id: `reminder:${activity.id || index}`,
        kind: "Påminnelse",
        title: reminderTitle,
        meta: [urgency.label, dueLabel, customer ? cleanDisplayName(customer) : ""].filter(Boolean).join(" · "),
        reminderId: activity.id || "",
        customerId: customer ? customerKey(customer) : "",
        searchText: text,
      });
    });
    return finalizeGlobalSearchResults(results);
  }

  function globalSearchKindLabel(kind) {
    const labels = {
      Kunde: "Kundekort",
      Anlegg: "Anlegg",
      Lead: "Oppfølging",
      Nettside: "Nettsideinnsending",
      Jobb: "Jobb",
      Avtale: "Planlagt",
      Aktivitet: "Aktivitet",
      Faktura: "Faktura",
      Påminnelse: "Påminnelse",
    };
    return labels[kind] || kind || "Treff";
  }

  function globalSearchGroupLabel(kind) {
    const labels = {
      Kunde: "Kunder",
      Anlegg: "Varmepumper og anlegg",
      Lead: "Oppfølginger",
      Nettside: "Nye nettskjema",
      Jobb: "Jobber",
      Avtale: "Planlagte jobber",
      Aktivitet: "E-post, notater og aktivitet",
      Faktura: "Fakturaer",
      Påminnelse: "Påminnelser",
    };
    return labels[kind] || "Andre treff";
  }

  function globalSearchRowsHtml(rows) {
    let currentGroup = "";
    return rows.map((row) => {
      globalSearchResultCache.set(row.id, row);
      const group = globalSearchGroupLabel(row.kind);
      const heading = group !== currentGroup ? `<div class="global-search-group-title">${escapeHtml(group)}</div>` : "";
      currentGroup = group;
      return `
        ${heading}
        <button data-global-search-result="${escapeHtml(row.id)}" type="button" title="Åpne ${escapeHtml(globalSearchKindLabel(row.kind).toLowerCase())}">
          <span>${escapeHtml(globalSearchKindLabel(row.kind))}</span>
          <strong>${escapeHtml(row.title || "Uten navn")}</strong>
          <small>${escapeHtml(row.meta || "Ingen ekstra info")}</small>
        </button>
      `;
    }).join("");
  }

  function renderGlobalSearch() {
    if (!el.globalSearchResults) return;
    const query = globalSearchQuery || el.globalSearchInput?.value?.trim() || "";
    const searchFocused = document.activeElement === el.globalSearchInput
      || Boolean(document.activeElement && el.globalSearchResults?.contains(document.activeElement));
    globalSearchResultCache.clear();
    if (!query) {
      el.globalSearchResults.innerHTML = "";
      el.globalSearchResults.classList.add("hidden");
      return;
    }
    el.globalSearchResults.classList.toggle("hidden", !searchFocused);
    if (normalizeMatch(query).length < 2) {
      el.globalSearchResults.innerHTML = `<div class="empty-state compact">Skriv minst to tegn.</div>`;
      return;
    }
    const rows = globalSearchRows(query);
    if (!rows.length) {
      el.globalSearchResults.innerHTML = `<div class="empty-state compact">Ingen treff på "${escapeHtml(query)}".</div>`;
      return;
    }
    el.globalSearchResults.innerHTML = `
      <div class="global-search-count">${rows.length.toLocaleString("nb-NO")} treff</div>
      ${globalSearchRowsHtml(rows)}
    `;
  }

  function scheduleGlobalSearchRender() {
    window.clearTimeout(globalSearchRenderTimer);
    globalSearchRenderTimer = 0;
    const query = globalSearchQuery || el.globalSearchInput?.value?.trim() || "";
    if (normalizeMatch(query).length < 2) {
      renderGlobalSearch();
      return;
    }
    if (document.activeElement === el.globalSearchInput && el.globalSearchResults) {
      el.globalSearchResults.classList.remove("hidden");
      el.globalSearchResults.innerHTML = `<div class="empty-state compact">Søker...</div>`;
    }
    globalSearchRenderTimer = window.setTimeout(() => {
      globalSearchRenderTimer = 0;
      renderGlobalSearch();
    }, 120);
  }

  function hideGlobalSearchResults() {
    el.globalSearchResults?.classList.add("hidden");
  }

  function clearGlobalSearch() {
    window.clearTimeout(globalSearchRenderTimer);
    globalSearchRenderTimer = 0;
    window.clearTimeout(globalSearchSuppressTimer);
    globalSearchSuppressTimer = 0;
    globalSearchPointerStart = null;
    globalSearchSuppressClick = false;
    globalSearchQuery = "";
    if (el.globalSearchInput) el.globalSearchInput.value = "";
    if (el.globalSearchResults) el.globalSearchResults.innerHTML = "";
    hideGlobalSearchResults();
  }

  function openFirstGlobalSearchResult() {
    const query = globalSearchQuery || el.globalSearchInput?.value?.trim() || "";
    if (normalizeMatch(query).length < 2) return false;
    const rows = globalSearchRows(query);
    rows.forEach((row) => globalSearchResultCache.set(row.id, row));
    const first = rows[0];
    if (!first) return false;
    openGlobalSearchResult(first.id);
    hideGlobalSearchResults();
    el.globalSearchInput?.blur();
    return true;
  }

  function scrollSelectedWebsiteSubmissionIntoView() {
    if (!selectedWebsiteSubmissionId || !el.websiteSubmissionInbox) return;
    const card = el.websiteSubmissionInbox.querySelector(`[data-website-submission-card="${CSS.escape(selectedWebsiteSubmissionId)}"]`);
    if (!card) return;
    card.scrollIntoView({ block: "center", behavior: "smooth" });
    card.focus({ preventScroll: true });
  }

  function openReminderOnDashboard(reminderId = "") {
    setView("dashboard");
    setTimeout(() => {
      const card = reminderId
        ? el.reminderQueue?.querySelector(`[data-open-reminder="${CSS.escape(reminderId)}"]`)
        : null;
      const target = card || el.reminderQueue?.closest(".panel");
      target?.scrollIntoView({ behavior: "smooth", block: "center" });
      card?.focus?.({ preventScroll: true });
    }, 0);
  }

  function revealCustomerActivity(activityId = "") {
    if (!activityId) return;
    setTimeout(() => {
      const selector = `[data-activity-id="${CSS.escape(activityId)}"]`;
      const target = el.customerDetail?.querySelector(selector)
        || el.customerQuickDialog?.querySelector(selector)
        || el.leadDetail?.querySelector(selector);
      if (!target) return;
      let parent = target.parentElement;
      while (parent) {
        if (parent.tagName === "DETAILS") parent.open = true;
        parent = parent.parentElement;
      }
      const panel = target.closest("[data-activity-timeline-panel]");
      if (panel) {
        panel.dataset.expanded = "true";
        filterActivityTimeline(panel);
      }
      target.hidden = false;
      target.scrollIntoView({ behavior: "smooth", block: "center" });
      target.focus?.({ preventScroll: true });
    }, 0);
  }

  function handleGlobalSearchKeydown(event) {
    if (event.key === "Escape") {
      if (globalSearchQuery || el.globalSearchInput?.value || !el.globalSearchResults?.classList.contains("hidden")) {
        event.preventDefault();
        clearGlobalSearch();
      }
      return;
    }
    if (event.key === "ArrowDown") {
      const first = el.globalSearchResults?.querySelector("[data-global-search-result]");
      if (first) {
        event.preventDefault();
        first.focus();
      }
      return;
    }
    if (event.key === "Enter") {
      if (openFirstGlobalSearchResult()) event.preventDefault();
    }
  }

  function handleGlobalSearchResultsKeydown(event) {
    const buttons = Array.from(el.globalSearchResults?.querySelectorAll("[data-global-search-result]") || []);
    if (!buttons.length) return;
    const index = buttons.indexOf(document.activeElement);
    if (event.key === "ArrowDown" || event.key === "ArrowUp") {
      event.preventDefault();
      const delta = event.key === "ArrowDown" ? 1 : -1;
      buttons[(index + delta + buttons.length) % buttons.length]?.focus();
      return;
    }
    if (event.key === "Escape") {
      event.preventDefault();
      el.globalSearchInput?.focus();
    }
  }

  function handleGlobalKeyboardShortcut(event) {
    if (event.defaultPrevented || document.querySelector("dialog[open]")) return;
    if (!(event.ctrlKey || event.metaKey) || String(event.key || "").toLowerCase() !== "k") return;
    event.preventDefault();
    el.globalSearchInput?.focus();
    el.globalSearchInput?.select();
    globalSearchQuery = el.globalSearchInput?.value?.trim() || "";
    renderGlobalSearch();
  }

  function openGlobalSearchResult(id) {
    let row = globalSearchResultCache.get(id);
    if (!row) {
      const query = globalSearchQuery || el.globalSearchInput?.value?.trim() || "";
      const rows = globalSearchRows(query);
      rows.forEach((candidate) => globalSearchResultCache.set(candidate.id, candidate));
      row = globalSearchResultCache.get(id) || rows.find((candidate) => candidate.id === id);
    }
    if (!row) {
      setSyncStatus("Fant ikke søketreffet. Skriv inn søket på nytt.", "error");
      return;
    }
    if (row.kind === "Kunde" || row.kind === "Anlegg" || row.kind === "Faktura") {
      openCustomerCard(row.customerId);
      requestAnimationFrame(() => scrollPanelIntoMobileView(el.customerDetail));
      setSyncStatus(`Åpnet kundekort for ${row.title || "valgt kunde"}.`, "ok");
      return;
    }
    if (row.kind === "Lead") {
      selectedLeadId = row.leadKey;
      currentLeadFilter = "all";
      currentLeadSearch = "";
      if (el.leadStatusFilter) el.leadStatusFilter.value = "all";
      if (el.leadSearch) el.leadSearch.value = "";
      setView("leads");
      setSyncStatus(`Åpnet oppfølging for ${row.title || "valgt kunde"}.`, "ok");
      return;
    }
    if (row.kind === "Nettside") {
      currentLeadFilter = "inbox_tab";
      currentLeadSearch = "";
      setLeadInboxTab("website");
      selectedWebsiteSubmissionId = row.websiteSubmissionId || "";
      if (el.leadStatusFilter) el.leadStatusFilter.value = "inbox_tab";
      if (el.leadSearch) el.leadSearch.value = "";
      setView("leads");
      requestAnimationFrame(scrollSelectedWebsiteSubmissionIntoView);
      if (selectedWebsiteSubmissionId) setSyncStatus(`Åpnet nettsideinnsending for ${row.title || "valgt treff"}.`, "ok");
      return;
    }
    if (row.kind === "Jobb") {
      openOrderById(row.orderId);
      return;
    }
    if (row.kind === "Avtale") {
      const linked = linkedOrderForBooking(row.bookingId);
      if (linked?.id) {
        openOrderById(linked.id);
        return;
      }
      showBookingInPlanning(row.bookingId);
      return;
    }
    if (row.kind === "Aktivitet") {
      openCustomerCard(row.customerId);
      revealCustomerActivity(row.activityId);
      setSyncStatus(`Åpnet kundehistorikk for ${row.title || "valgt aktivitet"}.`, "ok");
      return;
    }
    if (row.kind === "Påminnelse") {
      if (row.customerId) {
        openCustomerQuickPanel(row.customerId, "");
        setSyncStatus(`Åpnet kundekort fra påminnelse: ${row.title}.`, "ok");
        return;
      }
      openReminderOnDashboard(row.reminderId);
    }
  }

  function activateGlobalSearchResult(target) {
    const button = target?.closest?.("[data-global-search-result]");
    if (!button) return false;
    openGlobalSearchResult(button.dataset.globalSearchResult);
    clearGlobalSearch();
    return true;
  }

  function beginGlobalSearchPointer(event) {
    if (!event.target?.closest?.("[data-global-search-result]")) {
      globalSearchPointerStart = null;
      return;
    }
    window.clearTimeout(globalSearchSuppressTimer);
    globalSearchSuppressTimer = 0;
    globalSearchPointerStart = { x: event.clientX, y: event.clientY, id: event.pointerId };
    globalSearchSuppressClick = false;
  }

  function trackGlobalSearchPointer(event) {
    if (!globalSearchPointerStart || globalSearchPointerStart.id !== event.pointerId) return;
    const distance = Math.hypot(event.clientX - globalSearchPointerStart.x, event.clientY - globalSearchPointerStart.y);
    if (distance > 10) globalSearchSuppressClick = true;
  }

  function finishGlobalSearchPointer() {
    globalSearchPointerStart = null;
    window.clearTimeout(globalSearchSuppressTimer);
    globalSearchSuppressTimer = window.setTimeout(() => {
      globalSearchSuppressTimer = 0;
      globalSearchSuppressClick = false;
    }, 450);
  }

  function setDashboardSectionVisibility(contentElement, visible) {
    contentElement?.closest(".dashboard-grid > .panel")?.classList.toggle("hidden", !visible);
  }

  function syncDashboardQueueDetailsVisibility() {
    if (!el.dashboardQueueDetails) return;
    const visiblePanels = el.dashboardQueueDetails.querySelectorAll(".dashboard-grid > .panel:not(.hidden)").length;
    el.dashboardQueueDetails.classList.toggle("hidden", visiblePanels === 0);
    if (!visiblePanels) el.dashboardQueueDetails.open = false;
  }

  function renderBillingQueue() {
    if (!el.billingQueue) return;
    el.billingQueue.innerHTML = "";
    const rows = billingQueueRows().slice(0, 12);
    setDashboardSectionVisibility(el.billingQueue, rows.length > 0);
    if (!rows.length) {
      el.billingQueue.innerHTML = `<div class="empty-state">Ingen jobber venter på fakturering.</div>`;
      return;
    }
    for (const row of rows) {
      const card = document.createElement("article");
      card.className = "billing-queue-card";
      const label = bookingNeedsCashPayment(row)
        ? "Betaling ikke registrert"
        : bookingNeedsInvoiceFinalAction(row)
          ? "Utkast i eAccounting"
          : bookingNeedsInvoice(row)
            ? "Må faktureres"
            : "Dato passert";
      const kind = bookingNeedsPaymentAction(row) ? "yellow" : "red";
      const canPrepare = !bookingNeedsCashPayment(row) && (bookingNeedsInvoice(row) || bookingNeedsInvoiceFinalAction(row));
      card.innerHTML = `
        <button class="billing-queue-main" data-billing-customer="${escapeHtml(customerKey(row.customer))}" data-billing-booking="${escapeHtml(row.id)}" type="button">
          <span class="dot ${kind}"></span>
          <strong>${escapeHtml(cleanDisplayName(row.customer))}</strong>
          <span>${escapeHtml(label)} · ${formatDate(row.booking.date)} · ${escapeHtml(bookingJobLabel(row))}</span>
        </button>
        ${canPrepare ? `<button class="secondary" data-prepare-invoice-action="${escapeHtml(row.id)}" type="button" title="Lager et kontrollert fakturagrunnlag. Det opprettes ikke faktura i eAccounting ennå.">Forbered utkast</button>` : ""}
      `;
      el.billingQueue.appendChild(card);
    }
  }

  function profileRoleLabel(role) {
    return role === "admin" ? "Admin" : "Tekniker";
  }

  function renderOfferTemplateSettings() {
    if (!el.offerTemplateSettings) return;
    if (!isAdmin()) {
      el.offerTemplateSettings.innerHTML = "";
      return;
    }
    const settings = offerSettings();
    const canSave = Boolean(store.isConfigured && store.saveCrmSetting);
    const disabled = canSave ? "" : "disabled";
    el.offerTemplateSettings.innerHTML = `
      <section class="settings-section">
        <div class="section-head compact">
          <div>
            <h3>Tilbudsmaler og priser</h3>
            <p>Rediger tekstene som brukes i Innboks/tilbud. Prisgrunnlaget brukes i flere maler.</p>
          </div>
          <div class="mini-action-row">
            <button class="secondary" data-reset-offer-settings type="button">Standardtekst</button>
            <button data-save-offer-settings type="button" ${disabled}>Lagre</button>
          </div>
        </div>
        ${canSave ? "" : `<p class="form-hint">Lagring av maler krever Supabase og crm_settings-tabellen.</p>`}
        <label class="check-row"><input data-offer-settings-auto-email type="checkbox" ${settings.autoEmailEnabled ? "checked" : ""} ${disabled} /> Aktiver direkte sending fra CRM</label>
        <p class="form-hint">Direkte sending er testet med Google Workspace. Slå den bare av ved e-postfeil eller vedlikehold.</p>
        <div class="offer-template-editor-list">
          ${Object.entries(leadTemplates).map(([id, template]) => {
            const override = settings.templateOverrides?.[id] || {};
            const subject = String(override.subject || defaultLeadTemplateSubject(id));
            const body = String(override.body || defaultLeadTemplateBodyForSettings(id));
            const changed = String(override.subject || "").trim() || String(override.body || "").trim();
            return `
              <details class="offer-template-editor" data-offer-settings-template="${escapeHtml(id)}">
                <summary>
                  <strong>${escapeHtml(template.title)}</strong>
                  <span>${escapeHtml(changed ? "Tilpasset" : "Standard")}</span>
                </summary>
                <label>Emne
                  <input data-offer-settings-template-subject="${escapeHtml(id)}" value="${escapeHtml(subject)}" ${disabled} />
                </label>
                <label>Tekst
                  <textarea data-offer-settings-template-body="${escapeHtml(id)}" rows="10" ${disabled}>${escapeHtml(body)}</textarea>
                </label>
                <div class="mini-action-row">
                  <button class="secondary" data-reset-one-offer-template="${escapeHtml(id)}" type="button" ${disabled}>Tilbakestill denne</button>
                </div>
              </details>
            `;
          }).join("")}
        </div>
        <label>Prisgrunnlag / standard montering og tillegg
          <textarea data-offer-settings-prices rows="16" ${disabled}>${escapeHtml(settings.priceTermsText)}</textarea>
        </label>
        <p class="form-hint">Plassholdere: {fornavn}, {navn}, {adresse}, {prisgrunnlag}. Aktiv prisliste kan hukes av i tilbudsboksen og legges inn som PDF-lenke i e-postteksten.</p>
      </section>
    `;
  }

  function storedProductCatalogItems() {
    const value = crmSettings.product_catalog;
    if (Array.isArray(value)) return value;
    return Array.isArray(value?.items) ? value.items : [];
  }

  function productCatalogUnitForEaccounting(unit) {
    if (unit === "time") return "tim";
    if (unit === "g") return "gr";
    if (unit === "sett") return "stk";
    return unit || "stk";
  }

  function normalizeProductCatalogItem(value = {}, fallback = {}) {
    const item = { ...fallback, ...(value && typeof value === "object" ? value : {}) };
    const id = String(item.id || "").trim().slice(0, 80);
    let label = String(item.label || "").trim().slice(0, 160);
    if (id === "toshiba_signature_25" && /^(?:toshiba\s+)?signature\s+25$/i.test(label)) label = "Signatur 25";
    if (id === "toshiba_signature_35" && /^(?:toshiba\s+)?signature\s+35$/i.test(label)) label = "Signatur 35";
    if (!id || !label || !/^[a-z0-9][a-z0-9_-]*$/i.test(id)) return null;
    const rawPrice = typeof item.price === "number" ? item.price : parseJobPriceAmount(item.price);
    const price = Number.isFinite(rawPrice) && rawPrice >= 0 ? Math.round(rawPrice * 100) / 100 : 0;
    const rawQty = Number(String(item.defaultQty || 1).replace(",", "."));
    const defaultQty = Number.isFinite(rawQty) && rawQty > 0 ? rawQty : 1;
    const requiredStandardInstallation = id === "standard_installation";
    const kind = requiredStandardInstallation ? "addition" : item.kind === "heatpump" ? "heatpump" : "addition";
    const unit = String(item.unit || "stk").trim().slice(0, 16) || "stk";
    const eaccountingType = requiredStandardInstallation
      ? "services"
      : (kind === "heatpump" || item.eaccountingType !== "services" ? "goods" : "services");
    return {
      ...item,
      id,
      articleNo: String(item.articleNo || "").trim().slice(0, 24),
      articleName: String(item.articleName || "").trim().slice(0, 200),
      brand: String(item.brand || "").trim().slice(0, 80),
      label,
      aliases: Array.isArray(item.aliases)
        ? item.aliases.map((alias) => String(alias || "").trim()).filter(Boolean).join(" ").slice(0, 500)
        : String(item.aliases || "").trim().slice(0, 500),
      unit,
      price,
      defaultQty,
      kind,
      active: requiredStandardInstallation || item.active !== false,
      eaccountingType,
      eaccountingUnit: String(item.eaccountingUnit || productCatalogUnitForEaccounting(unit)).trim().slice(0, 16),
      eaccountingGroup: String(item.eaccountingGroup || "CRM").trim().slice(0, 40) || "CRM",
    };
  }

  function syncProductCatalogFromSettings() {
    const defaults = [...defaultHeatPumpOfferItems, ...defaultJobPriceItems];
    const savedItems = storedProductCatalogItems();
    const savedById = new Map(savedItems
      .filter((item) => item && typeof item === "object" && item.id)
      .map((item) => [String(item.id), item]));
    const merged = defaults
      .map((item) => normalizeProductCatalogItem(savedById.get(item.id), { ...item, active: true }))
      .filter(Boolean);
    for (const saved of savedItems) {
      if (!saved?.id || defaultProductCatalogIds.has(String(saved.id))) continue;
      const normalized = normalizeProductCatalogItem(saved);
      if (normalized) merged.push(normalized);
    }
    productCatalogItems = merged;
    heatPumpOfferItems = merged.filter((item) => item.active !== false && item.kind === "heatpump");
    jobPriceItems = merged.filter((item) => item.active !== false && item.kind !== "heatpump");
    offerLinePresets = [customOfferLineItem, ...heatPumpOfferItems, ...jobPriceItems];
  }

  function productCatalogCategory(item) {
    if (item?.kind === "heatpump") return "heatpump";
    return item?.eaccountingType === "services" ? "service" : "accessory";
  }

  function productCatalogCategoryLabel(itemOrCategory) {
    const category = typeof itemOrCategory === "string" ? itemOrCategory : productCatalogCategory(itemOrCategory);
    if (category === "heatpump") return "Varmepumpe";
    if (category === "service") return "Tjeneste";
    return "Tilbehør / vare";
  }

  function productCatalogCategoryOptions(selected = "heatpump") {
    return [
      ["heatpump", "Varmepumpe"],
      ["accessory", "Tilbehør / vare"],
      ["service", "Tjeneste"],
    ].map(([value, label]) => `<option value="${value}" ${value === selected ? "selected" : ""}>${label}</option>`).join("");
  }

  function productCatalogUnitOptions(selected = "stk") {
    const units = [
      ["stk", "Stykk"],
      ["sett", "Sett"],
      ["m", "Meter"],
      ["time", "Time"],
      ["km", "Kilometer"],
      ["g", "Gram"],
    ];
    if (selected && !units.some(([value]) => value === selected)) units.push([selected, selected]);
    return units.map(([value, label]) => `<option value="${escapeHtml(value)}" ${value === selected ? "selected" : ""}>${escapeHtml(label)}</option>`).join("");
  }

  function productCatalogFieldsHtml(item = {}, options = {}) {
    const category = options.category || productCatalogCategory(item);
    const categoryLocked = Boolean(options.categoryLocked);
    return `
      <div class="product-catalog-form-grid">
        <label>Kategori
          <select data-product-field="category" ${categoryLocked ? "disabled" : ""}>${productCatalogCategoryOptions(category)}</select>
        </label>
        <label>Merke (varmepumpe)
          <input data-product-field="brand" value="${escapeHtml(item.brand || "")}" placeholder="F.eks. Panasonic" />
        </label>
        <label class="product-name-field">Produktnavn
          <input data-product-field="label" value="${escapeHtml(item.label || "")}" placeholder="F.eks. HZ25 Flagship Hvit 7.5kw" required />
        </label>
        <label>Pris inkl. mva
          <input data-product-field="price" type="number" min="0" step="0.01" inputmode="decimal" value="${escapeHtml(String(item.price ?? ""))}" placeholder="0" required />
        </label>
        <label>Enhet
          <select data-product-field="unit">${productCatalogUnitOptions(item.unit || "stk")}</select>
        </label>
        <label>Varenummer
          <input data-product-field="articleNo" value="${escapeHtml(item.articleNo || "")}" placeholder="Lages automatisk hvis tomt" />
        </label>
        <label class="product-alias-field">Søkeord
          <input data-product-field="aliases" value="${escapeHtml(item.aliases || "")}" placeholder="Andre navn eller modellkoder, skilt med mellomrom" />
        </label>
      </div>
    `;
  }

  function productCatalogSortedRows() {
    const categoryOrder = { heatpump: 0, accessory: 1, service: 2 };
    return [...productCatalogItems].sort((a, b) => (
      (a.active === false) - (b.active === false)
      || (categoryOrder[productCatalogCategory(a)] ?? 9) - (categoryOrder[productCatalogCategory(b)] ?? 9)
      || String(a.brand || "").localeCompare(String(b.brand || ""), "nb-NO")
      || String(a.label || "").localeCompare(String(b.label || ""), "nb-NO")
    ));
  }

  function productCatalogRowHtml(item) {
    const inactive = item.active === false;
    const required = item.id === "standard_installation";
    const sourceLabel = defaultProductCatalogIds.has(item.id) ? "Standardvare" : "Egen vare";
    const displayName = offerLineDisplayLabel(item);
    const facts = [
      productCatalogCategoryLabel(item),
      item.articleNo ? `nr. ${item.articleNo}` : "uten varenummer",
      sourceLabel,
      inactive ? "skjult" : "aktiv",
    ].join(" · ");
    return `
      <details class="product-catalog-row ${inactive ? "inactive" : ""}" data-product-catalog-row="${escapeHtml(item.id)}">
        <summary>
          <span><strong>${escapeHtml(displayName)}</strong><small>${escapeHtml(facts)}</small></span>
          <em>${escapeHtml(formatJobPriceAmount(item.price))} / ${escapeHtml(item.unit)}</em>
        </summary>
        <form data-product-catalog-edit-form="${escapeHtml(item.id)}">
          ${productCatalogFieldsHtml(item, { categoryLocked: required })}
          ${required ? `<p class="form-hint">Standard montering brukes automatisk sammen med varmepumper og kan derfor ikke skjules.</p>` : ""}
          <div class="mini-action-row product-catalog-actions">
            <button type="submit">Lagre endring</button>
            ${required ? "" : `<button class="secondary" data-product-toggle-active="${escapeHtml(item.id)}" type="button">${inactive ? "Aktiver" : "Skjul"}</button>`}
            ${defaultProductCatalogIds.has(item.id) ? `<button class="secondary" data-reset-product-catalog-item="${escapeHtml(item.id)}" type="button">Tilbakestill</button>` : ""}
          </div>
        </form>
      </details>
    `;
  }

  function productCatalogMatchesFilter(item, query = "", category = "all") {
    if (category === "inactive") return item.active === false;
    if (category !== "all" && productCatalogCategory(item) !== category) return false;
    const search = normalizeMatch(query);
    if (!search) return true;
    const haystack = offerLineSearchText(item);
    return search.split(/\s+/).filter(Boolean).every((token) => haystack.includes(token));
  }

  function renderProductCatalogList() {
    const container = el.eaccountingCatalogSettings;
    const list = container?.querySelector("[data-product-catalog-list]");
    if (!list) return;
    const query = container.querySelector("[data-product-catalog-search]")?.value || "";
    const category = container.querySelector("[data-product-catalog-filter]")?.value || "all";
    const rows = productCatalogSortedRows().filter((item) => productCatalogMatchesFilter(item, query, category));
    list.innerHTML = rows.length
      ? rows.map(productCatalogRowHtml).join("")
      : `<div class="empty-state">Ingen produkter matcher søket.</div>`;
    const count = container.querySelector("[data-product-catalog-result-count]");
    if (count) count.textContent = `${rows.length.toLocaleString("nb-NO")} produkt${rows.length === 1 ? "" : "er"}`;
  }

  function nextProductArticleNo(category) {
    const prefix = category === "heatpump" ? "91" : category === "service" ? "94" : "93";
    const numbers = productCatalogItems
      .map((item) => String(item.articleNo || ""))
      .filter((number) => new RegExp(`^${prefix}\\d{2}$`).test(number))
      .map(Number);
    const next = Math.max(Number(`${prefix}00`), ...numbers) + 1;
    return String(next);
  }

  function newProductCatalogId(category, brand, label) {
    const slug = normalizeMatch([brand, label].filter(Boolean).join(" "))
      .replace(/[^a-z0-9]+/g, "_")
      .replace(/^_+|_+$/g, "")
      .slice(0, 45) || "produkt";
    return `custom_${category}_${slug}_${Date.now().toString(36)}`.slice(0, 80);
  }

  function productCatalogItemFromForm(form, existing = null) {
    if (!form) throw new Error("Fant ikke produktskjemaet.");
    const field = (name) => form.querySelector(`[data-product-field="${name}"]`);
    const category = field("category")?.value || productCatalogCategory(existing || {});
    const enteredBrand = String(field("brand")?.value || "").trim();
    const brand = category === "heatpump" ? enteredBrand : "";
    const label = String(field("label")?.value || "").trim();
    const priceText = String(field("price")?.value || "").trim();
    const price = Number(priceText.replace(",", "."));
    const unit = String(field("unit")?.value || "stk").trim() || "stk";
    const articleNo = String(field("articleNo")?.value || "").trim() || nextProductArticleNo(category);
    const aliases = String(field("aliases")?.value || "").trim();
    if (!label) throw new Error("Produktnavn må fylles inn.");
    if (!Number.isFinite(price) || price < 0) throw new Error("Pris må være 0 eller høyere.");
    if (!/^[A-Za-z0-9._-]{2,24}$/.test(articleNo)) throw new Error("Varenummer kan bare inneholde bokstaver, tall, punktum, bindestrek og understrek.");
    const duplicateArticle = productCatalogItems.find((item) => item.id !== existing?.id && normalizeMatch(item.articleNo) === normalizeMatch(articleNo));
    if (duplicateArticle) throw new Error(`Varenummer ${articleNo} brukes allerede av ${offerLineDisplayLabel(duplicateArticle)}.`);
    const proposedName = category === "heatpump" ? [brand, label].filter(Boolean).join(" ") : label;
    const duplicateName = productCatalogItems.find((item) => item.id !== existing?.id && normalizeMatch(offerLineDisplayLabel(item)) === normalizeMatch(proposedName));
    if (duplicateName) throw new Error("Et produkt med samme merke og navn finnes allerede.");
    const kind = category === "heatpump" ? "heatpump" : "addition";
    const eaccountingType = category === "service" ? "services" : "goods";
    return normalizeProductCatalogItem({
      ...(existing || {}),
      id: existing?.id || newProductCatalogId(category, brand, label),
      articleNo,
      articleName: existing && normalizeMatch([existing.brand, existing.label].filter(Boolean).join(" ")) === normalizeMatch([brand, label].filter(Boolean).join(" "))
        ? existing.articleName || ""
        : "",
      brand,
      label,
      aliases,
      unit,
      price,
      defaultQty: existing?.defaultQty || 1,
      kind,
      active: existing?.active !== false,
      eaccountingType,
      eaccountingUnit: productCatalogUnitForEaccounting(unit),
      eaccountingGroup: "CRM",
    });
  }

  function productCatalogStoredItem(item) {
    return {
      id: item.id,
      articleNo: item.articleNo || "",
      articleName: item.articleName || "",
      brand: item.brand || "",
      label: item.label,
      aliases: item.aliases || "",
      unit: item.unit || "stk",
      price: Number(item.price || 0),
      defaultQty: Number(item.defaultQty || 1),
      kind: item.kind === "heatpump" ? "heatpump" : "addition",
      active: item.active !== false,
      eaccountingType: item.eaccountingType === "services" ? "services" : "goods",
      eaccountingUnit: item.eaccountingUnit || productCatalogUnitForEaccounting(item.unit),
      eaccountingGroup: item.eaccountingGroup || "CRM",
    };
  }

  async function persistProductCatalog(items, message) {
    if (!isAdmin()) throw new Error("Bare admin kan endre produktkartoteket.");
    if (!store.saveCrmSetting && !canUseLocalDemo()) throw new Error("Produktkartoteket krever Supabase.");
    const payload = { version: 1, items: items.map(productCatalogStoredItem) };
    await saveCrmSettingValue("product_catalog", payload);
    syncProductCatalogFromSettings();
    renderSettings();
    setSyncStatus(message || "Produktkartoteket er oppdatert.", "ok");
  }

  async function createProductCatalogItem(form) {
    const item = productCatalogItemFromForm(form);
    await persistProductCatalog([...productCatalogItems, item], `${offerLineDisplayLabel(item)} er lagt til og kan velges i tilbud og jobber.`);
  }

  async function updateProductCatalogItem(form, id) {
    const existing = productCatalogItems.find((item) => item.id === id);
    if (!existing) throw new Error("Fant ikke produktet som skulle endres.");
    const item = productCatalogItemFromForm(form, existing);
    const next = productCatalogItems.map((row) => row.id === id ? item : row);
    await persistProductCatalog(next, `${offerLineDisplayLabel(item)} er oppdatert.`);
  }

  async function toggleProductCatalogItem(id) {
    const item = productCatalogItems.find((row) => row.id === id);
    if (!item) throw new Error("Fant ikke produktet.");
    if (item.id === "standard_installation") throw new Error("Standard montering kan ikke skjules.");
    if (item.active !== false) {
      const ok = await askForConfirmation({
        title: "Skjul produkt",
        message: `${offerLineDisplayLabel(item)} forsvinner fra nye tilbud og jobber. Tidligere prislinjer beholdes.`,
        confirmLabel: "Skjul",
        tone: "danger",
      });
      if (!ok) return;
    }
    const active = item.active === false;
    const next = productCatalogItems.map((row) => row.id === id ? { ...row, active } : row);
    await persistProductCatalog(next, active ? `${offerLineDisplayLabel(item)} er aktivert.` : `${offerLineDisplayLabel(item)} er skjult fra nye valg.`);
  }

  async function resetProductCatalogItem(id) {
    const fallback = [...defaultHeatPumpOfferItems, ...defaultJobPriceItems].find((item) => item.id === id);
    if (!fallback) throw new Error("Dette er ikke en standardvare.");
    const reset = normalizeProductCatalogItem({ ...fallback, active: true });
    const next = productCatalogItems.map((item) => item.id === id ? reset : item);
    await persistProductCatalog(next, `${offerLineDisplayLabel(reset)} er tilbakestilt til standardverdiene.`);
  }

  function renderEaccountingCatalogSettings() {
    if (!el.eaccountingCatalogSettings) return;
    if (!isAdmin()) {
      el.eaccountingCatalogSettings.innerHTML = "";
      return;
    }
    const rows = eaccountingProductRows();
    const heatPumpCount = heatPumpOfferItems.length;
    const serviceCount = rows.filter((row) => row.type === "Tjeneste").length;
    const goodsCount = rows.filter((row) => row.type === "Vare").length;
    const inactiveCount = productCatalogItems.filter((item) => item.active === false).length;
    const canSave = Boolean(store.saveCrmSetting || canUseLocalDemo());
    const disabled = canSave ? "" : "disabled";
    el.eaccountingCatalogSettings.innerHTML = `
      <section class="settings-section">
        <div class="section-head compact">
          <div>
            <h3>Produktkartotek</h3>
            <p>Produktene brukes i tilbud, jobber, fullføring og fakturagrunnlag.</p>
          </div>
          <div class="mini-action-row">
            <button class="secondary" data-download-eaccounting-products type="button">Last ned CSV</button>
          </div>
        </div>
        <div class="legacy-tag-summary">
          <article>
            <strong>${rows.length.toLocaleString("nb-NO")}</strong>
            <span>Aktive produkter</span>
          </article>
          <article>
            <strong>${heatPumpCount.toLocaleString("nb-NO")}</strong>
            <span>Varmepumper</span>
          </article>
          <article>
            <strong>${serviceCount.toLocaleString("nb-NO")} / ${goodsCount.toLocaleString("nb-NO")}</strong>
            <span>Tjenester / varer</span>
          </article>
          <article>
            <strong>${inactiveCount.toLocaleString("nb-NO")}</strong>
            <span>Skjulte produkter</span>
          </article>
        </div>
        ${canSave ? "" : `<p class="form-hint">Lagring krever Supabase og admin-tilgang.</p>`}
        <details class="product-catalog-create">
          <summary>+ Legg til produkt</summary>
          <form data-product-catalog-create-form>
            ${productCatalogFieldsHtml({ unit: "stk", price: "" }, { category: "heatpump" })}
            <div class="mini-action-row product-catalog-actions">
              <button type="submit" ${disabled}>Legg til produkt</button>
            </div>
          </form>
        </details>
        <div class="product-catalog-toolbar">
          <input data-product-catalog-search type="search" placeholder="Søk navn, merke, modell eller varenummer" aria-label="Søk i produktkartotek" />
          <select data-product-catalog-filter aria-label="Filtrer produktkartotek">
            <option value="all">Alle produkter</option>
            <option value="heatpump">Varmepumper</option>
            <option value="accessory">Tilbehør / varer</option>
            <option value="service">Tjenester</option>
            <option value="inactive">Skjulte</option>
          </select>
          <span data-product-catalog-result-count>${productCatalogItems.length.toLocaleString("nb-NO")} produkter</span>
        </div>
        <div class="product-catalog-list" data-product-catalog-list>
          ${productCatalogSortedRows().map(productCatalogRowHtml).join("")}
        </div>
        <p class="form-hint">Skjul produkter som ikke lenger skal velges. Tidligere tilbud og jobber beholder prislinjene sine. CSV-en inneholder bare aktive produkter.</p>
      </section>
    `;
  }

  function uniqueSnapshotRowsFromMap(map) {
    const rows = [];
    const seen = new Set();
    for (const list of map?.values?.() || []) {
      for (const item of list || []) {
        const key = item?.id || item?.legacy_key || item?.invoice_number || item?.event_id || JSON.stringify(item);
        if (seen.has(key)) continue;
        seen.add(key);
        rows.push(item);
      }
    }
    return rows;
  }

  function renderPrivateDataExportSettings() {
    if (!el.privateDataExportSettings) return;
    if (!isAdmin()) {
      el.privateDataExportSettings.innerHTML = "";
      return;
    }
    const installationCount = uniqueSnapshotRowsFromMap(installationsByCustomer).length;
    const locationCount = uniqueSnapshotRowsFromMap(customerLocationsByCustomer).length;
    const openLeadCount = activeInboxSnapshotCount();
    const bookingCount = bookingRows().length;
    const orderCount = orderRows().length;
    el.privateDataExportSettings.innerHTML = `
      <section class="settings-section">
        <div class="section-head compact">
          <div>
            <h3>Privat dataeksport</h3>
            <p>Last ned nåværende CRM-data for kontroll mot Lime Go, eAccounting og e-posthistorikk.</p>
          </div>
          <div class="mini-action-row">
            <button class="secondary" data-download-private-data-snapshot type="button">Last ned JSON</button>
          </div>
        </div>
        <div class="legacy-tag-summary">
          <article>
            <strong>${customers.length.toLocaleString("nb-NO")}</strong>
            <span>Kunder</span>
          </article>
          <article>
            <strong>${installationCount.toLocaleString("nb-NO")}</strong>
            <span>Anlegg</span>
          </article>
          <article>
            <strong>${openLeadCount.toLocaleString("nb-NO")}</strong>
            <span>Aktive saker</span>
          </article>
          <article>
            <strong>${bookingCount.toLocaleString("nb-NO")} / ${orderCount.toLocaleString("nb-NO")}</strong>
            <span>Bookinger / jobber</span>
          </article>
          <article>
            <strong>${locationCount.toLocaleString("nb-NO")} / ${crmAttachments.length.toLocaleString("nb-NO")}</strong>
            <span>Adresser / vedlegg</span>
          </article>
        </div>
        <p class="form-hint">Filen er privat og kan inneholde kundedata. Den brukes lokalt til datavask før eventuelle kontrollerte databaseendringer.</p>
      </section>
    `;
  }

  function activeInboxSnapshotCount() {
    return openWebsiteSubmissionRows().length
      + openIntakeRows().length
      + allLeadEntries().filter((entry) => !leadEntryLooksLikeSpam(entry) && !["won", "lost"].includes(leadStatusForEntry(entry))).length;
  }

  function renderSettings() {
    if (!el.settingsAccessSummary || !el.profileList) return;
    const admin = isAdmin();
    const activeProfiles = (profiles || []).filter((profile) => profile.active !== false);
    const adminCount = activeProfiles.filter((profile) => profile.role === "admin").length;
    const technicianCount = activeProfiles.filter((profile) => profile.role === "technician").length;
    el.settingsAccessSummary.innerHTML = `
      <article>
        <strong>${adminCount.toLocaleString("nb-NO")}</strong>
        <span>Aktive admin</span>
      </article>
      <article>
        <strong>${technicianCount.toLocaleString("nb-NO")}</strong>
        <span>Aktive teknikere</span>
      </article>
      <article>
        <strong>${store.isConfigured ? "Supabase" : "Demo"}</strong>
        <span>${store.isConfigured ? "Innlogging og roller styres mot databasen" : "Lokal demo viser bare testbrukere"}</span>
      </article>
    `;
    renderOfferTemplateSettings();
    renderEaccountingCatalogSettings();
    renderPrivateDataExportSettings();
    renderTagSettings();
    if (!admin) {
      el.profileList.innerHTML = `<div class="empty-state">Bare admin kan endre brukerroller.</div>`;
      return;
    }
    const rows = [...(profiles || [])].sort((a, b) => (
      (a.active === false) - (b.active === false)
      || String(a.display_name || a.full_name || "").localeCompare(String(b.display_name || b.full_name || ""), "nb")
    ));
    if (!rows.length) {
      el.profileList.innerHTML = `<div class="empty-state">Ingen CRM-profiler funnet.</div>`;
      return;
    }
    el.profileList.innerHTML = rows.map((profile) => {
      const id = String(profile.id || "");
      const name = profile.full_name || profile.display_name || "Uten navn";
      const self = (currentUser?.id && String(currentUser.id) === id) || (currentUser?.key && String(currentUser.key) === id);
      const canEdit = ((store.isConfigured && store.saveProfile) || canUseLocalDemo()) && !self;
      const disabled = canEdit ? "" : "disabled";
      const active = profile.active !== false;
      const prefs = profilePreferences(profile);
      const resourceStatus = active ? "Synlig i planlegging og booking" : "Skjult til brukeren aktiveres";
      return `
        <article class="${active ? "" : "inactive"}" data-profile-row="${escapeHtml(id)}">
          <div>
            <strong>${escapeHtml(name)}${self ? ` <span class="profile-self">Deg</span>` : ""}</strong>
            <span>${escapeHtml(profileRoleLabel(profile.role))}${active ? "" : " · Inaktiv"} · ${escapeHtml(resourceStatus)}</span>
          </div>
          <label>Navn<input data-profile-name="${escapeHtml(id)}" value="${escapeHtml(name)}" ${disabled} /></label>
          <label>Telefon<input data-profile-phone="${escapeHtml(id)}" value="${escapeHtml(profile.phone || "")}" ${disabled} /></label>
          <label>Rolle
            <select data-profile-role="${escapeHtml(id)}" ${disabled}>
              <option value="technician" ${profile.role === "technician" ? "selected" : ""}>Tekniker</option>
              <option value="admin" ${profile.role === "admin" ? "selected" : ""}>Admin</option>
            </select>
          </label>
          <label>Språk
            <select data-profile-language="${escapeHtml(id)}" ${disabled}>
              ${profileLanguageOptionsHtml(prefs.language)}
            </select>
          </label>
          <label class="check-row profile-active"><input data-profile-active="${escapeHtml(id)}" type="checkbox" ${active ? "checked" : ""} ${disabled} /> Aktiv</label>
          <label class="check-row profile-active"><input data-profile-extra-help="${escapeHtml(id)}" type="checkbox" ${prefs.extraHelp ? "checked" : ""} ${disabled} /> Ekstra forklaring for tekniker</label>
          <button data-save-profile="${escapeHtml(id)}" type="button" ${canEdit ? "" : "disabled"}>${self ? "Egen profil" : "Lagre"}</button>
        </article>
      `;
    }).join("");
  }

  function tagUsageRows(filter) {
    const usage = new Map();
    for (const customer of customers || []) {
      if (!customer || customer.is_inactive) continue;
      const seenForCustomer = new Set();
      for (const tag of splitTags(customer.tags)) {
        if (filter && !filter(tag)) continue;
        const label = canonicalTagLabel(tag);
        const key = tagIdentity(label);
        if (!key || seenForCustomer.has(key)) continue;
        seenForCustomer.add(key);
        const row = usage.get(key) || { tag: label, count: 0, kind: legacyTagKind(label), variants: new Set() };
        row.count += 1;
        row.variants.add(tag);
        usage.set(key, row);
      }
    }
    return [...usage.values()]
      .map((row) => ({ ...row, variants: [...row.variants].map(canonicalTagLabel).filter((tag, index, list) => list.indexOf(tag) === index) }))
      .sort((a, b) => b.count - a.count || a.tag.localeCompare(b.tag, "nb-NO"));
  }

  function customerTagUsageRows() {
    return tagUsageRows((tag) => !isLegacyImportTag(tag));
  }

  function hiddenCustomerTagUsageRows() {
    return tagUsageRows((tag) => isLegacyImportTag(tag));
  }

  function customersWithTag(tag) {
    const wanted = tagIdentity(tag);
    return (customers || []).filter((customer) => splitTags(customer.tags).some((item) => tagIdentity(item) === wanted));
  }

  async function saveProfileFromSettings(profileId) {
    if (!isAdmin()) throw new Error("Bare admin kan endre brukerroller.");
    if (!store.saveProfile && !canUseLocalDemo()) throw new Error("Brukerroller krever Supabase.");
    if ((currentUser?.id && String(currentUser.id) === String(profileId)) || (currentUser?.key && String(currentUser.key) === String(profileId))) {
      throw new Error("Egen rolle/aktiv-status må endres av en annen admin.");
    }
    const row = el.profileList?.querySelector(`[data-profile-row="${CSS.escape(profileId)}"]`);
    if (!row) throw new Error("Fant ikke profilen som skulle lagres.");
    const name = row.querySelector(`[data-profile-name="${CSS.escape(profileId)}"]`)?.value?.trim() || "";
    const phone = row.querySelector(`[data-profile-phone="${CSS.escape(profileId)}"]`)?.value?.trim() || "";
    const role = row.querySelector(`[data-profile-role="${CSS.escape(profileId)}"]`)?.value === "admin" ? "admin" : "technician";
    const active = Boolean(row.querySelector(`[data-profile-active="${CSS.escape(profileId)}"]`)?.checked);
    const language = row.querySelector(`[data-profile-language="${CSS.escape(profileId)}"]`)?.value || "nb";
    const extraHelp = Boolean(row.querySelector(`[data-profile-extra-help="${CSS.escape(profileId)}"]`)?.checked);
    if (!name) throw new Error("Navn kan ikke være tomt.");
    const patch = {
      display_name: name,
      full_name: name,
      phone,
      role,
      active,
    };
    const existing = profiles.find((profile) => String(profile.id) === String(profileId)) || {};
    const saved = store.isConfigured && store.saveProfile
      ? await store.saveProfile(profileId, patch)
      : { ...existing, id: profileId, ...patch };
    await saveProfilePreferences(profileId, { language, extraHelp });
    const index = profiles.findIndex((profile) => String(profile.id) === String(saved.id));
    if (index >= 0) profiles[index] = saved;
    else profiles.push(saved);
    updateResourceSelects();
    renderSettings();
    setSyncStatus("Brukerprofil oppdatert.", "ok");
  }

  async function saveOfferSettingsFromSettings() {
    if (!isAdmin()) throw new Error("Bare admin kan endre tilbudsmaler.");
    if (!store.saveCrmSetting) throw new Error("Lagring av tilbudsmaler krever Supabase.");
    const container = el.offerTemplateSettings;
    const templateOverrides = {};
    container?.querySelectorAll("[data-offer-settings-template]").forEach((row) => {
      const id = row.dataset.offerSettingsTemplate || "";
      if (!leadTemplates[id]) return;
      const subject = row.querySelector(`[data-offer-settings-template-subject="${CSS.escape(id)}"]`)?.value?.trim() || "";
      const body = row.querySelector(`[data-offer-settings-template-body="${CSS.escape(id)}"]`)?.value || "";
      const defaultSubject = defaultLeadTemplateSubject(id);
      const defaultBody = defaultLeadTemplateBodyForSettings(id);
      const changedSubject = subject && subject !== defaultSubject;
      const changedBody = body.trim() && body !== defaultBody;
      if (changedSubject || changedBody) {
        templateOverrides[id] = {
          subject: changedSubject ? subject : defaultSubject,
          body: changedBody ? body : defaultBody,
        };
      }
    });
    const generalOverride = templateOverrides.general_price_offer || {};
    const next = {
      generalOfferSubject: generalOverride.subject || "Pristilbud på varmepumpe og tilleggsarbeid",
      generalOfferBody: generalOverride.body || defaultGeneralOfferBody(),
      priceTermsText: normalizeOfferPriceTermsText(container?.querySelector("[data-offer-settings-prices]")?.value || defaultOfferPriceTermsText()),
      autoEmailEnabled: Boolean(container?.querySelector("[data-offer-settings-auto-email]")?.checked),
      templateOverrides,
    };
    const saved = await store.saveCrmSetting("offer_settings", next);
    crmSettings.offer_settings = saved?.value || next;
    renderSettings();
    renderLeadDetail();
    setSyncStatus("Tilbudsmaler og prisgrunnlag lagret.", "ok");
  }

  function resetOfferSettingsForm() {
    const container = el.offerTemplateSettings;
    const prices = container?.querySelector("[data-offer-settings-prices]");
    const autoEmail = container?.querySelector("[data-offer-settings-auto-email]");
    if (autoEmail) autoEmail.checked = false;
    container?.querySelectorAll("[data-offer-settings-template]").forEach((row) => {
      const id = row.dataset.offerSettingsTemplate || "";
      resetOneOfferTemplateForm(id);
    });
    if (prices) prices.value = defaultOfferPriceTermsText();
    setSyncStatus("Standard tilbudstekst er fylt inn. Trykk Lagre for å bruke den videre.", "ok");
  }

  function resetOneOfferTemplateForm(templateId) {
    const container = el.offerTemplateSettings;
    if (!container || !leadTemplates[templateId]) return;
    const row = container.querySelector(`[data-offer-settings-template="${CSS.escape(templateId)}"]`);
    const subject = container.querySelector(`[data-offer-settings-template-subject="${CSS.escape(templateId)}"]`);
    const body = container.querySelector(`[data-offer-settings-template-body="${CSS.escape(templateId)}"]`);
    if (subject) subject.value = defaultLeadTemplateSubject(templateId);
    if (body) body.value = defaultLeadTemplateBodyForSettings(templateId);
    const stateLabel = row?.querySelector("summary span");
    if (stateLabel) stateLabel.textContent = "Standard";
  }

