      ...direct,
      symptom_slug: firstFilled(direct.symptom_slug, row?.symptom_slug, nested.symptom_slug, formSupport.symptom_slug, payload.symptom_slug, form.symptom_slug, fieldAliasValue(sources, ["symptom_slug", "symptom", "problem", "problem_type"])),
      severity: firstFilled(direct.severity, row?.severity, nested.severity, formSupport.severity, payload.severity, form.severity, fieldAliasValue(sources, ["severity", "alvorlighet", "haster"])),
      preferred_contact_method: firstFilled(direct.preferred_contact_method, row?.preferred_contact_method, nested.preferred_contact_method, formSupport.preferred_contact_method, payload.preferred_contact_method, payload.requested_booking_type, form.preferred_contact_method, form.requested_booking_type, fieldAliasValue(sources, ["preferred_contact_method", "contact_method", "kontaktmate", "kontaktmåte", "kontaktform", "requested_booking_type", "booking_type", "bookingønske", "bookingonske"])),
      message: firstFilled(direct.message, row?.message, nested.message, formSupport.message, payload.message, payload.melding, form.message, form.melding, form.description, form.comment, form.kommentar, fieldAliasValue(sources, ["message", "melding", "beskjed", "note", "notes", "comment", "kommentar", "description", "beskrivelse", "your-message", "your_message"])),
      billable: direct.billable ?? row?.billable ?? nested.billable ?? formSupport.billable ?? payload.billable ?? form.billable,
