  async function openSmsWithCopiedNumber(button) {
    const phone = button.dataset.openSmsPhone || "";
    if (!phone) return;
    const oldText = button.textContent;
    const targetUrl = smsUrl(phone);
    let openedWindow = null;
    if (!targetUrl.startsWith("sms:")) {
      openedWindow = window.open("about:blank", "_blank", "noopener,noreferrer");
    }
    const copied = await copyTextToClipboard(phone, { manualFallback: true, mobileAssist: true });
    button.textContent = copied ? "SMS klar" : "Kopier manuelt";
    setSyncStatus(
      copied
        ? `Telefonnummer kopiert: ${phone}. Lim inn i SMS/Google Messages hvis mottakerfeltet ikke fylles automatisk.`
        : `${manualCopyStatus("Telefonnummeret")} Lim inn nummeret i SMS/Google Messages.`,
      copied ? "ok" : "",
    );
    if (openedWindow) {
      openedWindow.location.href = targetUrl;
    } else if (targetUrl.startsWith("sms:")) {
      window.location.href = targetUrl;
    } else {
      window.open(targetUrl, "_blank", "noopener,noreferrer");
    }
    setTimeout(() => {
      button.textContent = oldText;
    }, 1600);
  }

  function downloadTextFile(filename, text, type = "text/plain;charset=utf-8") {
    const url = URL.createObjectURL(new Blob([text], { type }));
    const link = document.createElement("a");
    link.href = url;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    link.remove();
    URL.revokeObjectURL(url);
  }

