  function snapshotBlockedKey(key) {
    return /password|passord|secret|access[_-]?token|refresh[_-]?token|id[_-]?token|api[_-]?key|authorization/i.test(String(key || ""));
  }

  function snapshotSafeValue(value, depth = 0) {
    if (value == null) return value;
    if (depth > 8) return String(value);
    if (value instanceof Date) return value.toISOString();
    if (typeof File !== "undefined" && value instanceof File) {
      return { name: value.name, type: value.type, size: value.size, lastModified: value.lastModified };
    }
    if (typeof Blob !== "undefined" && value instanceof Blob) {
      return { type: value.type, size: value.size };
    }
    if (Array.isArray(value)) return value.map((item) => snapshotSafeValue(item, depth + 1));
    if (typeof value === "object") {
      const output = {};
      for (const [key, item] of Object.entries(value)) {
        if (snapshotBlockedKey(key) || typeof item === "function") continue;
        output[key] = snapshotSafeValue(item, depth + 1);
      }
      return output;
    }
    return value;
  }

  function snapshotObjectRows(objectRows) {
    return Object.entries(objectRows || {}).map(([id, row]) => snapshotSafeValue({
      id: row?.id || id,
      ...row,
    }));
  }

  function snapshotActivityRows() {
    const rows = [];
    const seen = new Set();
    [...(activityArchiveRows || []), ...(activities || [])].forEach((activity) => {
      const id = String(activity?.id || "");
      const fallback = [
        activity?.activity_type,
        activity?.customer_id,
        activity?.occurred_at || activity?.created_at,
        activity?.summary,
        activity?.body,
      ].join("|");
      const key = id || fallback;
      if (seen.has(key)) return;
      seen.add(key);
      rows.push(activity);
    });
    return snapshotSafeValue(rows);
  }

  function buildPrivateDataSnapshot() {
    const customerLocations = uniqueSnapshotRowsFromMap(customerLocationsByCustomer);
    const accessNotes = uniqueSnapshotRowsFromMap(accessNotesByCustomer);
    const installations = uniqueSnapshotRowsFromMap(installationsByCustomer);
    const invoices = uniqueSnapshotRowsFromMap(invoicesByCustomer);
    const serviceEvents = uniqueSnapshotRowsFromMap(serviceEventsByCustomer);
    const bookingRowsSnapshot = snapshotObjectRows(bookings);
    const orderRowsSnapshot = snapshotObjectRows(orders);
    const activityRowsSnapshot = snapshotActivityRows();
    const activeInboxCount = activeInboxSnapshotCount();
    return {
      schema: "numedal-crm-private-snapshot/v1",
      exported_at: new Date().toISOString(),
      app_version: "20260719-13",
      source: store.isConfigured ? "supabase" : "local-demo",
      counts: {
        customers: customers.length,
        customerLocations: customerLocations.length,
        accessNotes: accessNotes.length,
        installations: installations.length,
        invoices: invoices.length,
        serviceEvents: serviceEvents.length,
        bookings: bookingRowsSnapshot.length,
        orders: orderRowsSnapshot.length,
        jobs: jobs.length,
        appointments: appointments.length,
        leads: leads.length,
        activities: activityRowsSnapshot.length,
        hiddenActivities: activityRowsSnapshot.filter(activityIsHiddenFromCrm).length,
        websiteSubmissions: websiteSubmissions.length,
        intakeItems: intakeItems.length,
        activeInboxItems: activeInboxCount,
        crmAttachments: crmAttachments.length,
      },
      customers: snapshotSafeValue(customers),
      customerLocations: snapshotSafeValue(customerLocations),
      accessNotes: snapshotSafeValue(accessNotes),
      installations: snapshotSafeValue(installations),
      invoices: snapshotSafeValue(invoices),
      serviceEvents: snapshotSafeValue(serviceEvents),
      bookings: bookingRowsSnapshot,
      orders: orderRowsSnapshot,
      jobs: snapshotSafeValue(jobs),
      appointments: snapshotSafeValue(appointments),
      leads: snapshotSafeValue(leads),
      activities: activityRowsSnapshot,
      websiteSubmissions: snapshotSafeValue(websiteSubmissions),
      intakeItems: snapshotSafeValue(intakeItems),
      crmAttachments: snapshotSafeValue(crmAttachments),
      profiles: snapshotSafeValue((profiles || []).map((profile) => ({
        id: profile.id,
        display_name: profile.display_name,
        full_name: profile.full_name,
        role: profile.role,
        active: profile.active !== false,
        phone: profile.phone,
      }))),
    };
  }

  function downloadPrivateDataSnapshot() {
    const snapshot = buildPrivateDataSnapshot();
    const text = JSON.stringify(snapshot, null, 2);
    downloadTextFile(`numedal-crm-private-snapshot-${isoDate(new Date())}.json`, text, "application/json;charset=utf-8");
    setSyncStatus(`Privat CRM-snapshot lastet ned (${snapshot.counts.customers.toLocaleString("nb-NO")} kunder, ${snapshot.counts.installations.toLocaleString("nb-NO")} anlegg).`, "ok");
  }

