  el.routeSelectedCustomers?.addEventListener("change", (event) => {
    const confirmationSelect = event.target.closest("[data-route-confirmation-source]");
    if (confirmationSelect) {
      const customerId = confirmationSelect.dataset.routeConfirmationSource;
      if (confirmationSelect.value) {
        routeCustomerConfirmations.set(customerId, { source: confirmationSelect.value, confirmedAt: new Date().toISOString() });
      } else {
        routeCustomerConfirmations.delete(customerId);
      }
      routePlanInputChanged();
      return;
    }
    const installationSelect = event.target.closest("[data-route-select-installation]");
    if (installationSelect) {
      const customerId = installationSelect.dataset.routeSelectInstallation;
      if (installationSelect.value) routeSelectedInstallationIds.set(customerId, installationSelect.value);
      else routeSelectedInstallationIds.delete(customerId);
      const customer = findCustomer(customerId);
      const chosen = installationsForCustomer(customer).find((installation) => installation.id === installationSelect.value);
      const linkedLocationId = chosen?.location_id || chosen?.locationId || "";
      if (linkedLocationId) routeSelectedLocationIds.set(customerId, linkedLocationId);
      else routeSelectedLocationIds.delete(customerId);
      routePlanInputChanged();
      return;
    }
    const locationSelect = event.target.closest("[data-route-select-location]");
    if (!locationSelect) return;
    const customerId = locationSelect.dataset.routeSelectLocation;
    if (locationSelect.value) routeSelectedLocationIds.set(customerId, locationSelect.value);
    else routeSelectedLocationIds.delete(customerId);
    routePlanInputChanged();
  });
